// iOS emergency visibility mode for cases where Safari renders portal panels blank.
if (document && document.documentElement) {
  try {
    if (/(?:\?|&)iosfix=1(?:&|$)/.test(window.location.search || "")) {
      document.documentElement.classList.add("ios-visibility-fallback");
    }
  } catch (err) {
    // Keep default behavior if URL parsing fails.
  }
}

// Service Worker scope guard: on non-PWA pages, unregister any SW registered at
// root scope so stale SW caches cannot serve outdated assets to portal pages.
(function() {
  try {
    var p = window.location.pathname || "";
    var isAppPage = (p === "/app/" || p === "/app" || p === "/app.html" || p.indexOf("/app/") === 0);
    if (!isAppPage && "serviceWorker" in navigator) {
      navigator.serviceWorker.getRegistrations().then(function(regs) {
        regs.forEach(function(reg) {
          // Unregister any SW whose scope covers portal pages (i.e. not limited to /app/).
          var scope = reg.scope || "";
          if (!scope.match(/\/app\/?$/)) {
            reg.unregister();
          }
        });
      }).catch(function() {});
    }
  } catch (e) {}
})();

// --- Profil löschen Logik für Profilseiten ---
document.addEventListener('DOMContentLoaded', function() {
  const deleteBtn = document.getElementById('deleteProfileBtn');
  if (deleteBtn) {
    deleteBtn.addEventListener('click', function() {
      if (!confirm('Willst du dein Profil wirklich unwiderruflich löschen?')) return;
      const studentAuth = getStoredStudentAuth();
      const student = studentAuth ? findStudentByAuth(studentAuth) : null;
      if (student && deleteStudentAccountById(student.id)) {
        window.location.href = (window.AzubiMatchRoutes && window.AzubiMatchRoutes.index) ? window.AzubiMatchRoutes.index : 'index.html';
        return;
      }
      if (studentAuth && studentAuth.id && deleteStudentRegistrationByUserId(studentAuth.id)) {
        window.location.href = (window.AzubiMatchRoutes && window.AzubiMatchRoutes.index) ? window.AzubiMatchRoutes.index : 'index.html';
        return;
      }
      clearStoredStudentAuth();

      const firmAuth = getStoredFirmAuth();
      const offer = firmAuth ? findFirmOfferByAuth(firmAuth) : null;
      if (offer && deleteFirmAccountById(offer.id)) {
        window.location.href = (window.AzubiMatchRoutes && window.AzubiMatchRoutes.index) ? window.AzubiMatchRoutes.index : 'index.html';
        return;
      }
      if (firmAuth && firmAuth.id && deleteFirmRegistrationByUserId(firmAuth.id)) {
        window.location.href = (window.AzubiMatchRoutes && window.AzubiMatchRoutes.index) ? window.AzubiMatchRoutes.index : 'index.html';
        return;
      }
      clearStoredFirmAuth();
      window.location.href = (window.AzubiMatchRoutes && window.AzubiMatchRoutes.index) ? window.AzubiMatchRoutes.index : 'index.html';
    });
  }
});
