// Admin: Lösche Bewerber mit Status 'Nur registriert' oder 'Ausstehend' nach 10 Sekunden, wenn Profil unvollständig
function purgeIncompleteStudentsAfterDelay() {
  setTimeout(function() {
    let students = loadStudents();
    const before = students.length;
    students = students.filter(s => {
      // Status prüfen
      const status = (s.status || '').toLowerCase();
      // Prüfe, ob Profil vollständig (z.B. Pflichtfelder wie name, beruf, stadt, plz, grundschuleVon, grundschuleBis, weiterfuehrendeSchulform, weiterfuehrendeVon, weiterfuehrendeBis, wahlfach, noten)
      const isComplete = isStudentProfileComplete(s);
      // Nur löschen, wenn Status "nur registriert" oder "ausstehend" und Profil unvollständig
      if ((status === 'nur registriert' || status === 'ausstehend') && !isComplete) {
        return false;
      }
      return true;
    });
    if (students.length !== before) {
      saveStudents(students);
      if (typeof renderStudentsList === 'function') renderStudentsList();
    }
  }, 10000);
}
document.addEventListener('DOMContentLoaded', purgeIncompleteStudentsAfterDelay);

function isStudentProfileComplete(s) {
  if (!s) return false;
  return !!(s.name && s.beruf && s.stadt && s.plz && s.grundschuleVon && s.grundschuleBis && s.weiterfuehrendeSchulform && s.weiterfuehrendeVon && s.weiterfuehrendeBis && s.wahlfach && s.noteMathe && s.noteDeutsch && s.noteEnglisch && s.noteWahlfach);
}

// Helper: Send notification to student or firm (localStorage-based demo)
function sendContactNotification({ toType, toId, toEmail, toName, subject, message, relatedRequestId, studentProfilCode }) {
  // For demo: store in azubimatch_contact_notifications
  const key = 'azubimatch_contact_notifications';
  const list = readJson(key, []);
  let finalToId = toId;
  // Wenn es sich um einen Bewerber handelt, immer den Profil-Code als ID verwenden
  if (toType === 'student' && studentProfilCode) {
    finalToId = studentProfilCode;
  }
  list.push({
    id: uniqueId('notif'),
    toType, // 'student' or 'firm'
    toId: finalToId,
    toEmail,
    toName,
    subject,
    message,
    relatedRequestId,
    createdAt: new Date().toISOString()
  });
  writeJson(key, list);
}

