// Verschiebt Bewerber und Firmen mit identischem Beruf in einen separaten Ordner 'Match'
function verschiebeMatchesInMatchOrdner() {
  const students = loadStudents();
  const firms = loadOffers();
  const requests = loadFullProfileRequests();
  const matches = [];
  const unmatchedStudents = [];
  const unmatchedFirms = [];

  // Finde Matches: Bewerber-Beruf <-> Ausbildungsberuf der Firma
  students.forEach(s => {
    const beruf = (s.beruf || '').trim();
    if (!beruf) return;
    const passendeFirmen = firms.filter(function(firm) {
      const matchMeta = getMatchMeta(s, firm, { allOffers: firms });
      return matchMeta.isVisibleMatch && !isStudentFirmMatchSuppressed(s, firm, matchMeta.matchedProfession, requests);
    });
    if (passendeFirmen.length > 0) {
      passendeFirmen.forEach(firm => {
        const matchMeta = getMatchMeta(s, firm, { allOffers: firms });
        const matchedProfession = matchMeta.matchedProfession || beruf;
        matches.push({
          beruf: matchedProfession,
          student: s,
          firm: firm,
          matchedProfession: matchedProfession,
          isInclusionMatch: matchMeta.isInclusionMatch,
          isAlternativeMatch: matchMeta.isAlternativeMatch,
          isActivatedAlternativeProfession: matchMeta.isActivatedAlternativeProfession,
          alternativeFamilyLabel: matchMeta.alternativeFamilyLabel,
          matchLabel: matchMeta.matchLabel,
          distanceKm: matchMeta.distanceKm,
          distanceLabel: matchMeta.distanceLabel
        });
        // Benachrichtige beide Teilnehmer bei Match
        if (isFirmAccountReleased(firm)) {
          const firmTarget = resolveFirmNotificationTarget(firm);
          if (firmTarget.email) {
            sendContactNotification({
              toType: 'firm',
              toId: firm.id,
              toEmail: firmTarget.email,
              toName: firmTarget.name,
              subject: matchMeta.isInclusionMatch ? 'Neuer Inklusions-Match' : 'Neuer Match mit einem Profil',
              message: `Sie haben ein neues ${matchMeta.isInclusionMatch ? 'Inklusions-Match' : 'Match'} mit dem Profil "${s.name || '-'}" für den Beruf "${matchedProfession}".`,
              relatedRequestId: null
            });
          }
        }
        if (s.verified) {
          const studentTarget = resolveStudentNotificationTarget(s);
          if (studentTarget.email) {
            sendContactNotification({
              toType: 'student',
              toId: s.id,
              toEmail: studentTarget.email,
              toName: studentTarget.name,
              subject: matchMeta.isInclusionMatch ? 'Neues Inklusions-Match' : 'Neues Firmen-Match',
              message: `Du hast ein neues ${matchMeta.isInclusionMatch ? 'Inklusions-Match' : 'Match'} mit der Firma "${firm.firma || '-'}" für den Beruf "${matchedProfession}".`,
              relatedRequestId: null,
              studentProfilCode: s.profilCode || null
            });
          }
        }
      });
    } else {
      unmatchedStudents.push(s);
    }
  });

  // Firmen ohne passenden Bewerber-Beruf
  firms.forEach(f => {
    const hatMatch = students.some(function(student) {
      const matchMeta = getMatchMeta(student, f, { allOffers: firms });
      return matchMeta.isVisibleMatch && !isStudentFirmMatchSuppressed(student, f, matchMeta.matchedProfession, requests);
    });
    if (!hatMatch) {
      unmatchedFirms.push(f);
    }
  });

  // Speichere Matches und Nicht-Matches in localStorage
  writeJson('azubimatch_matches', matches);
  writeJson('azubimatch_unmatched_students', unmatchedStudents);
  writeJson('azubimatch_unmatched_firms', unmatchedFirms);
}
// Zeigt die vollstaendige Matching-Uebersicht im Admin-Tab an.
// Gruppiert Bewerber und Firmen nach Beruf und zeigt sie gemeinsam an.
function renderMatchingByProfession() {
  const students = loadStudents();
  const firms = (typeof loadOffers === 'function' ? loadOffers() : []);
  const requests = loadFullProfileRequests();
  const groupedMatches = {};
  firms.forEach(function(firm) {
    students.forEach(function(student) {
      const matchMeta = getMatchMeta(student, firm, { allOffers: firms });
      if (!matchMeta.isVisibleMatch) return;
      if (isStudentFirmMatchSuppressed(student, firm, matchMeta.matchedProfession, requests)) return;
      const fitScore = getMatchFitScore(matchMeta);

      if (!groupedMatches[matchMeta.matchedProfession]) {
        groupedMatches[matchMeta.matchedProfession] = [];
      }

      groupedMatches[matchMeta.matchedProfession].push({
        firm: firm,
        student: student,
        matchedProfession: matchMeta.matchedProfession,
        isInclusionMatch: matchMeta.isInclusionMatch,
        isAlternativeMatch: matchMeta.isAlternativeMatch,
        isActivatedAlternativeProfession: matchMeta.isActivatedAlternativeProfession,
        alternativeFamilyLabel: matchMeta.alternativeFamilyLabel,
        matchLabel: matchMeta.matchLabel,
        fitScore: fitScore,
        distanceKm: matchMeta.distanceKm,
        debug: matchMeta.isAlternativeMatch && matchMeta.alternativeFamilyLabel
          ? 'Berufsfeld ' + matchMeta.alternativeFamilyLabel
          : ''
      });
    });
  });

  const professionGroups = Object.keys(groupedMatches).sort().map(function(beruf) {
    return { beruf: beruf, pairs: groupedMatches[beruf] };
  });

  const container = document.getElementById("matchingByProfession");
  if (!container) return;
  if (!professionGroups.length) {
    container.innerHTML = '<p style="color:#64748b;text-align:center;">Noch keine passenden Profile oder Firmen vorhanden.</p>';
    return;
  }
  container.innerHTML = professionGroups.map(group => {
    const matchPairs = group.pairs.slice().sort(function(left, right) {
      if (right.fitScore !== left.fitScore) {
        return right.fitScore - left.fitScore;
      }
      const distanceCompare = compareDistanceAsc(left.distanceKm, right.distanceKm);
      if (distanceCompare !== 0) {
        return distanceCompare;
      }
      return String(left.firm.firma || '').localeCompare(String(right.firm.firma || ''), 'de');
    });
    const matchCount = matchPairs.length;
    const inclusionMatchCount = matchPairs.filter(pair => pair.isInclusionMatch).length;
    const alternativeMatchCount = matchPairs.filter(pair => pair.isAlternativeMatch).length;
    const activatedMatchCount = matchPairs.filter(pair => pair.isActivatedAlternativeProfession).length;
    return `
      <div class="beruf-box-collapsible">
        <div class="beruf-box-title">
          ${group.beruf}
          <span class="beruf-box-count">${matchCount} Match${matchCount === 1 ? '' : 'es'}</span>
          ${activatedMatchCount > 0 ? `<span class="matching-match-kind matching-match-kind--activated">${activatedMatchCount} aktivierter Alternativberuf${activatedMatchCount === 1 ? '' : 'e'}</span>` : ''}
          ${alternativeMatchCount > 0 ? `<span class="matching-match-kind matching-match-kind--alternative">${alternativeMatchCount} Berufsfeld-Match${alternativeMatchCount === 1 ? '' : 'es'}</span>` : ''}
          ${inclusionMatchCount > 0 ? `<span class="matching-match-kind matching-match-kind--inclusion">${inclusionMatchCount} Inklusions-Match${inclusionMatchCount === 1 ? '' : 'es'}</span>` : ''}
        </div>
        <div class="beruf-box-content">
          <ul class="matching-pair-list">
            ${matchPairs.length > 0 ? matchPairs.map(pair => {
              const scoreMeta = getMatchScoreMeta(pair);
              return `
              <li class="matching-pair-item">
                <span class="matching-pill matching-pill--firm">Firma</span>
                <span class="matching-pair-name">${pair.firm.firma || '-'}</span>
                <span class="matching-pair-role">${Array.isArray(pair.firm.berufe) ? pair.firm.berufe.join(', ') : (pair.firm.beruf || '-')}</span>
                <span class="matching-pair-separator">&#8596;</span>
                <span class="matching-pill matching-pill--student">Profil</span>
                <span class="matching-pair-name">${pair.student.name || '-'}</span>
                <span class="matching-pair-role">${pair.student.beruf || '-'}</span>
                <span class="matching-match-kind ${scoreMeta.adminChipClass}">${scoreMeta.shortLabel}</span>
                ${pair.isActivatedAlternativeProfession ? `<span class="matching-match-kind matching-match-kind--activated">Aktiviert für Matchanfragen</span>` : ''}
                ${pair.isAlternativeMatch ? `<span class="matching-match-kind matching-match-kind--alternative">Berufsfeld-Match${pair.alternativeFamilyLabel ? ` · ${pair.alternativeFamilyLabel}` : ''}</span>` : ''}
                ${pair.isInclusionMatch ? `<span class="matching-match-kind matching-match-kind--inclusion">${pair.matchLabel}</span>` : ''}
                <span class="matching-pair-debug">${pair.debug ? '[Debug: ' + pair.debug + ']' : ''}</span>
              </li>
            `;
            }).join('') : '<li class="matching-empty-item">Keine Matches</li>'}
          </ul>
        </div>
      </div>
    `;
  }).join('');
}

function initAdminMatchingOverview() {
  const container = document.getElementById("matchingByProfession");
  if (!container) return;

  const status = document.getElementById("matchingAdminStatus");
  const auth = typeof getAdminAuth === "function" ? getAdminAuth() : null;
  const hasAdminSession = !!(auth && auth.role === "admin");

  if (status) {
    status.textContent = hasAdminSession ? "Admin-Sitzung aktiv" : "Bitte zuerst im Admin einloggen";
  }

  if (!hasAdminSession) {
    container.innerHTML = "";
    return;
  }

  renderMatchingByProfession();
}
// Benachrichtigt Firmen, wenn ein Bewerber in derselben Berufsgruppe ist
function benachrichtigeFirmenBeiMatching(student) {
  if (!student || !student.beruf) return;
  const beruf = (student.beruf || "").trim();
  const firms = (typeof loadOffers === 'function' ? loadOffers() : []).filter(f => f.verified);
  const passendeFirmen = firms.filter(f => {
    if (Array.isArray(f.berufe) && f.berufe.length > 0) {
      return f.berufe.map(b => b.trim()).includes(beruf);
    } else if (f.beruf) {
      return f.beruf.trim() === beruf;
    }
    return false;
  });
  passendeFirmen.forEach(firm => {
    const target = resolveFirmNotificationTarget(firm);
    console.log("Benachrichtigung an Firma:", target);
    if (target.email) {
      sendNotificationEmail({
        email: target.email,
        name: target.name,
        title: "Neues passendes Profil im Berufsfeld",
        message: `Es gibt ein neues Profil fuer den Beruf "${beruf}". Name: ${student.name || "-"}`,
        type: "match_firm"
      }).catch(e => {
        console.error("Benachrichtigung an Firma fehlgeschlagen:", e);
      });
    }
  });
}

// Admin: Profil aktivieren, ohne Dokumente global freizugeben
async function approveProfileRelease(btn) {
  const studentId = btn.getAttribute("data-student-id");
  if (!studentId) return;

  try {
    if (await verifyStudentById(studentId, { allowMissingDocuments: true })) {
      const activeFilterBtn = document.querySelector("#studentsTab .admin-filter-btn.admin-filter-active");
      const activeFilter = activeFilterBtn ? activeFilterBtn.getAttribute("data-filter") : "verified";
      renderStudentsList(activeFilter || "verified");
      updateAdminStats();
    }
  } catch (err) {
    if (err && (err.code === "NAME_CHECK_FAILED" || err.code === "GRADE_MISMATCH" || err.code === "GRADE_CHECK_FAILED")) {
      alert(err.message || "Profil konnte nicht aktiviert werden.");
      return;
    }
    alert("Profil wurde aktiviert, aber Benachrichtigung konnte nicht vollständig versendet werden: " + err.message);
    renderStudentsList("verified");
    updateAdminStats();
  }
}
