// Sprachen dynamisch verwalten (Schnellprofil)
document.addEventListener('DOMContentLoaded', function() {
  const sprachenInput = document.getElementById("sprachenInput");
  const addSpracheBtn = document.getElementById("addSpracheBtn");
  const sprachenList = document.getElementById("sprachenList");
  if (addSpracheBtn && sprachenInput && sprachenList) {
    addSpracheBtn.addEventListener("click", function() {
      const sprache = sprachenInput.value.trim();
      if (!sprache) return;
      const exists = Array.from(sprachenList.querySelectorAll("li .sprache-label")).some(function(el) {
        return el.textContent.trim().toLowerCase() === sprache.toLowerCase();
      });
      if (exists) {
        sprachenInput.value = "";
        return;
      }
      const li = document.createElement("li");
      li.style.display = "flex";
      li.style.alignItems = "center";
      li.style.gap = "0.3em";
      li.innerHTML = `<span class="sprache-label">${sprache}</span> <button type="button" class="btn ghost small remove-sprache-btn" title="Entfernen">✖</button>`;
      sprachenList.appendChild(li);
      sprachenInput.value = "";
      sprachenInput.focus();
    });
    sprachenList.addEventListener("click", function(e) {
      if (e.target && e.target.classList.contains("remove-sprache-btn")) {
        const li = e.target.closest("li");
        if (li) li.remove();
      }
    });
  }
});
