// 1. Die Filter-Logik in der laden() Funktion anpassen
function laden() {
  const anzeige = document.getElementById("anzeige");
  if (!anzeige) return;
  const aktuelleFirma = JSON.parse(sessionStorage.getItem("aktuelleFirma"));
  
  if (!aktuelleFirma) return;

  var liste = JSON.parse(localStorage.getItem("schuelerListe")) || [];

  // Filter: Nur Schüler zeigen, die diese Firma NICHT gesperrt haben
  const gefilterte = liste.filter(function(s) {
    // Falls der Schüler die Firma nach einer Absage gesperrt hat -> weg damit
    if (s.gesperrteAbsender && s.gesperrteAbsender.includes(aktuelleFirma.name)) {
      return false;
    }
    
    // Nur Schüler der passenden Branche zeigen
    if (s.branche !== aktuelleFirma.branche) return false;
    
    // Nur aktive Schüler
    return s.status === "aktiv";
  });

  // Anzeige generieren...
  // (Hier folgt dein bisheriger Code für anzeige.innerHTML)
}

// 2. Die Absage-Logik in antworteFreischaltung sicherstellen
function antworteFreischaltung(schuelerEmail, anfrageIndex, antwort) {
            // Ablehnung auch in azubimatch_fullprofile_requests eintragen
            let requests = JSON.parse(localStorage.getItem('azubimatch_fullprofile_requests') || '[]');
            const ablehnBeruf = anfrage.beruf || schueler.beruf;
            // Prüfe, ob schon ein Eintrag existiert
            let found = false;
            for (let req of requests) {
              if (
                (req.studentId === (schueler.profilCode || schueler.id || schueler.email)) &&
                (req.firmId === anfrage.firmaId || req.firmName === anfrage.firmaName) &&
                (req.beruf === ablehnBeruf || !req.beruf || !ablehnBeruf)
              ) {
                req.status = 'abgelehnt';
                found = true;
              }
            }
            if (!found) {
              // Falls kein Eintrag existiert, neuen anlegen
              requests.push({
                studentId: schueler.profilCode || schueler.id || schueler.email,
                firmId: anfrage.firmaId || '',
                firmName: anfrage.firmaName || '',
                beruf: ablehnBeruf,
                status: 'abgelehnt',
                createdAt: new Date().toISOString()
              });
            }
            localStorage.setItem('azubimatch_fullprofile_requests', JSON.stringify(requests));
        // Entferne sofort alle Matches für diesen Bewerber, diese Firma und diesen Beruf
        let matches = JSON.parse(localStorage.getItem('azubimatch_matches') || '[]');
        matches = matches.filter(m => {
          // Entferne das Match, wenn es diesen Bewerber, diese Firma und diesen Beruf betrifft
          if (!m.student || !m.firm) return true;
          const isSameStudent = (m.student.email && m.student.email === schuelerEmail) || (m.student.name && m.student.name === schueler.name);
          const isSameFirm = (anfrage.firmaName && m.firm.firma === anfrage.firmaName);
          const isSameBeruf = (m.student.beruf && (anfrage.beruf ? m.student.beruf === anfrage.beruf : m.student.beruf === schueler.beruf));
          return !(isSameStudent && isSameFirm && isSameBeruf);
        });
        localStorage.setItem('azubimatch_matches', JSON.stringify(matches));
  var liste = JSON.parse(localStorage.getItem("schuelerListe")) || [];
  const schueler = liste.find(s => s.email === schuelerEmail);
  if (!schueler) return;
  // Auch im Haupt-Studentenarray suchen
  var students = JSON.parse(localStorage.getItem("azubimatch_students")) || [];
  const mainStudent = students.find(s => s.email === schuelerEmail);

  if (antwort === "nein") {
    const anfrage = schueler.freischaltungsAnfragen[anfrageIndex];
    // Firma auf die Sperrliste setzen
      if (!schueler.gesperrteAbsender) schueler.gesperrteAbsender = [];
      // Sperre als Objekt mit Firma und Beruf speichern
      const ablehnBeruf = anfrage.beruf || schueler.beruf;
      if (!schueler.gesperrteAbsender.some(e => e.firma === anfrage.firmaName && e.beruf === ablehnBeruf)) {
        schueler.gesperrteAbsender.push({ firma: anfrage.firmaName, beruf: ablehnBeruf });
      }
      // Auch im Haupt-Studentenarray: Firma als gesperrt speichern (für Matching)
      if (mainStudent) {
        if (!mainStudent.gesperrteAbsender) mainStudent.gesperrteAbsender = [];
        if (!mainStudent.gesperrteAbsender.some(e => e.firma === anfrage.firmaName && e.beruf === ablehnBeruf)) {
          mainStudent.gesperrteAbsender.push({ firma: anfrage.firmaName, beruf: ablehnBeruf });
        }
        localStorage.setItem("azubimatch_students", JSON.stringify(students));
      }
      // Anfrage als abgelehnt markieren
      anfrage.status = "abgelehnt";
      localStorage.setItem("schuelerListe", JSON.stringify(liste));
      localStorage.setItem("azubimatch_students", JSON.stringify(students));
      // Nach jeder Änderung Matches neu berechnen
      if (typeof verschiebeMatchesInMatchOrdner === 'function') {
        try { verschiebeMatchesInMatchOrdner(); } catch(e) { /* ignore */ }
      }
    // Matches neu berechnen, damit der Bewerber sofort entfernt wird
    if (typeof verschiebeMatchesInMatchOrdner === 'function') {
      try { verschiebeMatchesInMatchOrdner(); } catch(e) { /* ignore */ }
    }
    // Nachricht an die Firma über die Absage (verwende sendContactNotification für Konsistenz)
    if (anfrage.firmaId || anfrage.firmaEmail || anfrage.firmaName) {
      sendContactNotification({
        toType: 'firm',
        toId: anfrage.firmaId || '',
        toEmail: anfrage.firmaEmail || '',
        toName: anfrage.firmaName || '',
        subject: 'Anfrage abgelehnt',
        message: `${schueler.name} hat Ihre Anfrage abgelehnt. Das Schnellprofil wird nicht mehr angezeigt.`,
        relatedRequestId: null
      });
    }
    showToast("Anfrage abgelehnt. Das Profil wird für die Firma ausgeblendet.", "info");
    // Falls die Seite gerade offen ist (für Tests), UI neu laden
    if (window.location.href.includes("bewerber.html")) {
      loadOffeneAnfragen();
    }
    // Firmenprofil DOM aktualisieren, falls offen (ohne Reload)
    if (window.location.pathname.endsWith('firma_profil.html')) {
      if (typeof window.initFirmProfilePage === 'function') {
        setTimeout(function() { window.initFirmProfilePage(); }, 200);
      }
    }
    // Matching-Ansicht im Admin aktualisieren, falls vorhanden
    if (document.getElementById('matchingByProfession')) {
      if (typeof window.initAdminMatchingOverview === 'function') {
        setTimeout(function() { window.initAdminMatchingOverview(); }, 200);
      }
    }
  } else {
    // Logik für Zustimmung (Zustand wie bisher)
    // ...
  }
}
