function initScrollReveal() {
  if (!document.body) return;
  if (window.matchMedia && window.matchMedia("(prefers-reduced-motion: reduce)").matches) return;

  const revealGroups = getScrollRevealGroups();
  if (!revealGroups.length) return;

  const elements = [];
  revealGroups.forEach((selector) => {
    document.querySelectorAll(selector).forEach((element) => {
      if (elements.indexOf(element) === -1) {
        elements.push(element);
      }
    });
  });

  if (!elements.length) return;

  elements.forEach((element, index) => {
    element.classList.add("motion-reveal");
    element.style.setProperty("--reveal-delay", String((index % 4) * 70) + "ms");
  });

  const observer = new IntersectionObserver((entries, revealObserver) => {
    entries.forEach((entry) => {
      if (!entry.isIntersecting) return;
      entry.target.classList.add("is-visible");
      revealObserver.unobserve(entry.target);
    });
  }, {
    threshold: 0.01,
    rootMargin: "0px 0px -10% 0px"
  });

  elements.forEach((element) => {
    observer.observe(element);
  });
}

function initAccordionGroups() {
  const accordionItems = Array.from(document.querySelectorAll("details[data-accordion-group]"));
  if (!accordionItems.length) return;

  accordionItems.forEach((item) => {
    item.addEventListener("toggle", () => {
      if (!item.open) return;

      const groupName = item.getAttribute("data-accordion-group");
      if (!groupName) return;

      accordionItems.forEach((otherItem) => {
        if (otherItem === item) return;
        if (otherItem.getAttribute("data-accordion-group") !== groupName) return;
        otherItem.open = false;
      });
    });
  });
}

function navigateWithTransition(url, statusText) {
  if (statusEl && statusText) {
    statusEl.textContent = statusText;
  }
  document.body.classList.add("page-leave");
  window.setTimeout(() => {
    window.location.href = buildRuntimeUrl(url);
  }, 220);
}

function enableNormalBackLinks() {
  const backLinks = document.querySelectorAll("a.back-home");
  backLinks.forEach((link) => {
    link.addEventListener("click", () => {
      document.body.classList.remove("page-leave");
    });
  });
}

