// ---------------------------------------------------------------------------
// PostgreSQL-Sync: Nutzer bei Registrierung und Login parallel in Railway-DB
// schreiben. Schlägt der API-Call fehl, läuft die App normal weiter.
// ---------------------------------------------------------------------------
function getPostgresApiBase() {
  return String((window.AzubiMatchRuntime && window.AzubiMatchRuntime.apiEndpoint) || "").replace(/\/$/, "").trim();
}

async function tryPostgresSync(email, password, role) {
  const base = getPostgresApiBase();
  if (!base) return;
  const body = JSON.stringify({ email: String(email).toLowerCase().trim(), password: String(password), role: String(role) });
  const headers = { "Content-Type": "application/json" };
  try {
    // Erst Registrierung versuchen
    const regRes = await fetch(base + "/api/auth/register", { method: "POST", headers, body });
    if (regRes.ok) {
      const data = await regRes.json();
      if (data && data.token) localStorage.setItem("azubimatch_api_jwt", data.token);
      return;
    }
    // 409 = bereits registriert → Login
    if (regRes.status === 409) {
      const loginRes = await fetch(base + "/api/auth/login", { method: "POST", headers, body });
      if (loginRes.ok) {
        const data = await loginRes.json();
        if (data && data.token) localStorage.setItem("azubimatch_api_jwt", data.token);
      }
    }
  } catch (_) {
    // Netzwerkfehler ignorieren – App läuft weiter
  }
}
// ---------------------------------------------------------------------------

function readJson(key, fallback) {
  try {
    const raw = localStorage.getItem(key);
    return raw ? JSON.parse(raw) : fallback;
  } catch (e) {
    return fallback;
  }
}

function writeJson(key, value) {
  localStorage.setItem(key, JSON.stringify(value));
}

function readSessionJson(key, fallback) {
  try {
    const raw = sessionStorage.getItem(key);
    return raw ? JSON.parse(raw) : fallback;
  } catch (e) {
    return fallback;
  }
}

function writeSessionJson(key, value) {
  try {
    sessionStorage.setItem(key, JSON.stringify(value));
  } catch (e) {
    // Ignore quota/session restrictions in unsupported runtimes.
  }
}

function removeSessionValue(key) {
  try {
    sessionStorage.removeItem(key);
  } catch (e) {
    // Ignore session storage failures.
  }
}

function readAuthStorageRecord(key) {
  const privacyApi = window.AzubiMatchPrivacy;
  if (privacyApi && typeof privacyApi.readAuthSession === "function") {
    return privacyApi.readAuthSession(key);
  }
  return readJson(key, null);
}

function writeAuthStorageRecord(key, value) {
  const privacyApi = window.AzubiMatchPrivacy;
  if (privacyApi && typeof privacyApi.writeAuthSession === "function") {
    privacyApi.writeAuthSession(key, value);
    return;
  }
  writeJson(key, value);
}

function clearAuthStorageRecord(key) {
  const privacyApi = window.AzubiMatchPrivacy;
  if (privacyApi && typeof privacyApi.clearAuthSession === "function") {
    privacyApi.clearAuthSession(key);
    return;
  }
  localStorage.removeItem(key);
}

function secretHashingAvailable() {
  return !!(window.crypto && window.crypto.subtle && window.crypto.getRandomValues && window.TextEncoder);
}

function bytesToBase64(bytes) {
  let binary = "";
  const chunkSize = 0x8000;
  for (let index = 0; index < bytes.length; index += chunkSize) {
    const chunk = bytes.subarray(index, index + chunkSize);
    binary += String.fromCharCode.apply(null, Array.from(chunk));
  }
  return btoa(binary);
}

function base64ToBytes(value) {
  const binary = atob(String(value || ""));
  const bytes = new Uint8Array(binary.length);
  for (let index = 0; index < binary.length; index++) {
    bytes[index] = binary.charCodeAt(index);
  }
  return bytes;
}

function legacySecretHash(value) {
  const bytes = new TextEncoder().encode(String(value || ""));
  return bytesToBase64(bytes);
}

function createRandomSaltBase64(length) {
  const bytes = new Uint8Array(length);
  window.crypto.getRandomValues(bytes);
  return bytesToBase64(bytes);
}

async function deriveSecretHash(secret, saltBase64, iterations) {
  const encoder = new TextEncoder();
  const keyMaterial = await window.crypto.subtle.importKey(
    "raw",
    encoder.encode(String(secret || "")),
    "PBKDF2",
    false,
    ["deriveBits"]
  );
  const derivedBits = await window.crypto.subtle.deriveBits({
    name: "PBKDF2",
    hash: "SHA-256",
    salt: base64ToBytes(saltBase64),
    iterations: iterations
  }, keyMaterial, 256);
  return bytesToBase64(new Uint8Array(derivedBits));
}

function isStoredSecretRecord(value) {
  return !!value
    && typeof value === "object"
    && value.version === 2
    && value.algorithm === "pbkdf2-sha256"
    && value.salt
    && value.hash;
}

async function createStoredSecret(secret, options) {
  const opts = options || {};
  if (!secretHashingAvailable()) {
    return legacySecretHash(secret);
  }
  const iterations = typeof opts.iterations === "number"
    ? opts.iterations
    : (opts.type === "otp" ? OTP_HASH_ITERATIONS : SECRET_HASH_ITERATIONS);
  const salt = createRandomSaltBase64(16);
  const hash = await deriveSecretHash(secret, salt, iterations);
  return {
    version: 2,
    algorithm: "pbkdf2-sha256",
    salt: salt,
    iterations: iterations,
    hash: hash,
    createdAt: new Date().toISOString()
  };
}

async function verifyStoredSecret(secret, storedValue) {
  if (isStoredSecretRecord(storedValue)) {
    if (!secretHashingAvailable()) {
      throw new Error("Sicherer Passwortabgleich ist in diesem Browserkontext nicht verfügbar.");
    }
    const derived = await deriveSecretHash(secret, storedValue.salt, storedValue.iterations || SECRET_HASH_ITERATIONS);
    return {
      valid: storedValue.hash === derived,
      needsUpgrade: false
    };
  }

  if (typeof storedValue === "string" && storedValue) {
    const valid = storedValue === legacySecretHash(secret);
    return {
      valid: valid,
      needsUpgrade: valid && secretHashingAvailable()
    };
  }

  return {
    valid: false,
    needsUpgrade: false
  };
}

function buildTimedSession(auth, ttlMs, timeField) {
  if (!auth || typeof auth !== "object") return null;
  const session = Object.assign({}, auth);
  const fieldName = timeField || (session.loggedInAt ? "loggedInAt" : "loginTime");
  const rawStart = session[fieldName] ? new Date(session[fieldName]).getTime() : Date.now();
  const startTime = Number.isFinite(rawStart) && rawStart > 0 ? rawStart : Date.now();
  session[fieldName] = new Date(startTime).toISOString();
  if (!session.sessionExpiresAt) {
    session.sessionExpiresAt = new Date(startTime + ttlMs).toISOString();
  }
  return session;
}

function isTimedSessionExpired(auth) {
  if (!auth || !auth.sessionExpiresAt) return false;
  const expiresAt = new Date(auth.sessionExpiresAt).getTime();
  return !Number.isFinite(expiresAt) || Date.now() > expiresAt;
}

function getAdminCredentialStore() {
  return readJson(ADMIN_CREDENTIALS_KEY, null);
}

function adminCredentialsConfigured() {
  const credentials = getAdminCredentialStore();
  return !!(credentials && credentials.passwordHash);
}

async function saveAdminCredentials(password) {
  const current = getAdminCredentialStore() || {};
  const next = {
    createdAt: current.createdAt || new Date().toISOString(),
    updatedAt: new Date().toISOString(),
    passwordHash: await createStoredSecret(password, { type: "password" })
  };
  writeJson(ADMIN_CREDENTIALS_KEY, next);
  return next;
}

async function verifyAdminCredentials(password) {
  const credentials = getAdminCredentialStore();
  if (!credentials || !credentials.passwordHash) {
    return { valid: false, needsSetup: true };
  }

  const verification = await verifyStoredSecret(password, credentials.passwordHash);
  if (verification.valid && verification.needsUpgrade) {
    credentials.passwordHash = await createStoredSecret(password, { type: "password" });
    credentials.updatedAt = new Date().toISOString();
    writeJson(ADMIN_CREDENTIALS_KEY, credentials);
  }

  return {
    valid: verification.valid,
    needsSetup: false
  };
}

function setAdminResetNotice(message) {
  const text = String(message || "").trim();
  if (!text) {
    sessionStorage.removeItem(ADMIN_RESET_NOTICE_KEY);
    return;
  }
  sessionStorage.setItem(ADMIN_RESET_NOTICE_KEY, text);
}

function consumeAdminResetNotice() {
  const text = sessionStorage.getItem(ADMIN_RESET_NOTICE_KEY) || "";
  if (text) {
    sessionStorage.removeItem(ADMIN_RESET_NOTICE_KEY);
  }
  return text;
}

function clearAdminCredentials() {
  localStorage.removeItem(ADMIN_CREDENTIALS_KEY);
  clearAdminAuth();
}

function isSameOriginRuntimeUrl(value) {
  const raw = String(value || "").trim();
  if (!raw) return false;
  try {
    return new URL(raw, window.location.href).origin === window.location.origin;
  } catch (e) {
    return false;
  }
}

function canUseSameOriginRuntimeEndpoint(value) {
  const raw = String(value || "").trim();
  if (!raw) return false;
  try {
    const currentUrl = new URL(window.location.href);
    const targetUrl = new URL(raw, currentUrl.href);
    const isHttpRuntime = currentUrl.protocol === "http:" || currentUrl.protocol === "https:";
    const isHttpEndpoint = targetUrl.protocol === "http:" || targetUrl.protocol === "https:";
    return isHttpRuntime && isHttpEndpoint && targetUrl.origin === currentUrl.origin;
  } catch (e) {
    return false;
  }
}

function canUseRuntimeMailRelayEndpoint(value) {
  return canUseSameOriginRuntimeEndpoint(value);
}

function canUseRuntimeStateEndpoint(value) {
  return canUseSameOriginRuntimeEndpoint(value);
}

