const SERVER_BACKED_STORAGE_REQUESTED_WITH = "AzubiMatchStateSync";

const nativeStorageMethods = {
  getItem: null,
  setItem: null
};

const serverBackedStorageHydrationState = Object.create(null);
const serverBackedStoragePendingSyncs = Object.create(null);

let serverBackedStoragePatched = false;

function getRuntimeStateEndpoint() {
  return String((window.AzubiMatchRuntime && window.AzubiMatchRuntime.stateEndpoint) || "").trim();
}

function isServerBackedStorageKey(key) {
  return Object.prototype.hasOwnProperty.call(SERVER_BACKED_STORAGE_SCHEMA, String(key || "").trim());
}

function getServerBackedStorageDefaultValue(key) {
  return SERVER_BACKED_STORAGE_SCHEMA[String(key || "").trim()] === "object" ? {} : [];
}

function normalizeServerBackedStorageValue(key, value) {
  const schema = SERVER_BACKED_STORAGE_SCHEMA[String(key || "").trim()];
  if (schema === "object") {
    return value && typeof value === "object" && !Array.isArray(value) ? value : {};
  }
  if (schema === "array") {
    return Array.isArray(value) ? value : [];
  }
  return value;
}

function parseServerBackedStoragePayload(rawValue) {
  if (typeof rawValue !== "string") {
    return { ok: true, value: rawValue };
  }

  try {
    return { ok: true, value: JSON.parse(rawValue) };
  } catch (error) {
    return { ok: false, value: null };
  }
}

function ensureNativeStorageMethods() {
  if (nativeStorageMethods.getItem && nativeStorageMethods.setItem) {
    return true;
  }
  if (typeof Storage === "undefined") return false;
  nativeStorageMethods.getItem = Storage.prototype.getItem;
  nativeStorageMethods.setItem = Storage.prototype.setItem;
  return typeof nativeStorageMethods.getItem === "function" && typeof nativeStorageMethods.setItem === "function";
}

function setNativeLocalStorageJson(key, value) {
  if (!ensureNativeStorageMethods()) return;
  nativeStorageMethods.setItem.call(window.localStorage, String(key || ""), JSON.stringify(value));
}

function getNativeLocalStorageRaw(key) {
  if (!ensureNativeStorageMethods()) return null;
  return nativeStorageMethods.getItem.call(window.localStorage, String(key || ""));
}

function hasMeaningfulServerBackedStorageValue(value) {
  if (Array.isArray(value)) {
    return value.length > 0;
  }
  if (value && typeof value === "object") {
    return Object.keys(value).length > 0;
  }
  return value != null && value !== "";
}

function hydrateServerBackedStorageKey(key) {
  const normalizedKey = String(key || "").trim();
  if (!normalizedKey || !isServerBackedStorageKey(normalizedKey)) return;
  if (!ensureNativeStorageMethods()) return;
  if (serverBackedStorageHydrationState[normalizedKey]) return;

  const endpoint = getRuntimeStateEndpoint();
  if (!canUseRuntimeStateEndpoint(endpoint)) return;

  serverBackedStorageHydrationState[normalizedKey] = "loading";

  try {
    const localRawBeforeHydration = getNativeLocalStorageRaw(normalizedKey);
    const localPayload = localRawBeforeHydration == null
      ? { exists: false, ok: true, value: getServerBackedStorageDefaultValue(normalizedKey) }
      : { exists: true, ...parseServerBackedStoragePayload(localRawBeforeHydration) };

    const request = new XMLHttpRequest();
    const separator = endpoint.indexOf("?") === -1 ? "?" : "&";
    request.open("GET", endpoint + separator + "key=" + encodeURIComponent(normalizedKey) + "&_=" + Date.now(), false);
    request.setRequestHeader("Accept", "application/json");
    request.setRequestHeader("X-Requested-With", SERVER_BACKED_STORAGE_REQUESTED_WITH);
    request.send(null);

    if (request.status >= 200 && request.status < 300) {
      const payload = JSON.parse(String(request.responseText || "{}"));
      const remoteExists = !!(payload && payload.exists);
      const remoteValue = payload && Object.prototype.hasOwnProperty.call(payload, "value")
        ? payload.value
        : getServerBackedStorageDefaultValue(normalizedKey);
      const normalizedRemoteValue = normalizeServerBackedStorageValue(normalizedKey, remoteValue);

      if (!remoteExists && localPayload.exists && localPayload.ok) {
        const normalizedLocalValue = normalizeServerBackedStorageValue(normalizedKey, localPayload.value);
        setNativeLocalStorageJson(normalizedKey, normalizedLocalValue);
        if (hasMeaningfulServerBackedStorageValue(normalizedLocalValue)) {
          queueServerBackedStorageSync(normalizedKey, JSON.stringify(normalizedLocalValue));
        }
      } else {
        setNativeLocalStorageJson(normalizedKey, normalizedRemoteValue);
      }
    }
  } catch (error) {
    console.warn("AzubiMatch server hydration failed for", normalizedKey, error);
  } finally {
    serverBackedStorageHydrationState[normalizedKey] = "done";
  }
}

function queueServerBackedStorageSync(key, rawValue) {
  const normalizedKey = String(key || "").trim();
  const endpoint = getRuntimeStateEndpoint();
  if (!normalizedKey || !isServerBackedStorageKey(normalizedKey) || !canUseRuntimeStateEndpoint(endpoint)) {
    return null;
  }

  const parsed = parseServerBackedStoragePayload(rawValue);
  if (!parsed.ok) {
    console.warn("AzubiMatch server sync skipped for", normalizedKey, "because the payload was not valid JSON.");
    return null;
  }

  const payload = JSON.stringify({
    key: normalizedKey,
    value: normalizeServerBackedStorageValue(normalizedKey, parsed.value)
  });

  const previous = serverBackedStoragePendingSyncs[normalizedKey] || Promise.resolve(true);
  const next = previous
    .catch(function() {
      return false;
    })
    .then(function() {
      return fetch(endpoint, {
        method: "POST",
        headers: {
          "Accept": "application/json",
          "Content-Type": "application/json",
          "X-Requested-With": SERVER_BACKED_STORAGE_REQUESTED_WITH
        },
        credentials: "same-origin",
        body: payload
      }).then(function(response) {
        if (response.ok) {
          return response.json().catch(function() {
            return { success: true };
          });
        }

        return response.text().then(function(text) {
          throw new Error(text || ("HTTP " + response.status));
        });
      }).then(function() {
        return true;
      });
    })
    .catch(function(error) {
      console.warn("AzubiMatch server sync failed for", normalizedKey, error);
      return false;
    });

  serverBackedStoragePendingSyncs[normalizedKey] = next;
  return next;
}

function waitForServerBackedStorageSync(key, timeoutMs) {
  const pending = serverBackedStoragePendingSyncs[String(key || "").trim()];
  if (!pending) return null;

  const timeout = Math.max(0, Number(timeoutMs) || 0);
  if (!timeout) return pending;

  return Promise.race([
    pending,
    new Promise(function(resolve) {
      window.setTimeout(function() {
        resolve(false);
      }, timeout);
    })
  ]);
}

function patchServerBackedLocalStorage() {
  if (serverBackedStoragePatched) return;
  if (typeof window === "undefined" || !window.localStorage) return;
  if (!ensureNativeStorageMethods()) return;

  Storage.prototype.getItem = function(key) {
    const normalizedKey = String(key || "");
    if (this === window.localStorage && isServerBackedStorageKey(normalizedKey)) {
      hydrateServerBackedStorageKey(normalizedKey);
    }
    return nativeStorageMethods.getItem.call(this, normalizedKey);
  };

  Storage.prototype.setItem = function(key, value) {
    const normalizedKey = String(key || "");
    nativeStorageMethods.setItem.call(this, normalizedKey, String(value));
    if (this === window.localStorage && isServerBackedStorageKey(normalizedKey)) {
      queueServerBackedStorageSync(normalizedKey, String(value));
    }
  };

  serverBackedStoragePatched = true;
}

patchServerBackedLocalStorage();

function uniqueId(prefix) {
  return prefix + "_" + Date.now() + "_" + Math.random().toString(36).slice(2, 8);
}

function createProfileCode() {
  return "AZ-" + Math.random().toString(36).slice(2, 8).toUpperCase();
}

