function normalizeProfessionText(value) {
  return String(value || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9]+/g, " ")
    .trim()
    .replace(/\s+/g, " ");
}

function levenshteinDistance(a, b) {
  const left = String(a || "");
  const right = String(b || "");
  if (!left) return right.length;
  if (!right) return left.length;

  const row = new Array(right.length + 1);
  for (let j = 0; j <= right.length; j++) row[j] = j;

  for (let i = 1; i <= left.length; i++) {
    let prevDiagonal = row[0];
    row[0] = i;
    for (let j = 1; j <= right.length; j++) {
      const prevUp = row[j];
      const cost = left[i - 1] === right[j - 1] ? 0 : 1;
      row[j] = Math.min(
        row[j] + 1,
        row[j - 1] + 1,
        prevDiagonal + cost
      );
      prevDiagonal = prevUp;
    }
  }

  return row[right.length];
}

function getProfessionSuggestion(inputValue) {
  const raw = String(inputValue || "").trim();
  if (!raw) return null;

  const normalizedInput = normalizeProfessionText(raw);
  if (!normalizedInput) return null;

  let best = null;
  KNOWN_AUSBILDUNGSBERUFE.forEach((entry) => {
    const normalizedEntry = normalizeProfessionText(entry);
    if (!normalizedEntry) return;

    const distance = levenshteinDistance(normalizedInput, normalizedEntry);
    const maxLen = Math.max(normalizedInput.length, normalizedEntry.length, 1);
    const similarity = 1 - (distance / maxLen);

    if (!best || distance < best.distance || (distance === best.distance && similarity > best.similarity)) {
      best = { value: entry, distance: distance, similarity: similarity, normalized: normalizedEntry };
    }
  });

  if (!best) return null;

  if (best.normalized === normalizedInput) {
    return { value: best.value, exact: true, needsSuggestion: false };
  }

  const maxDistance = normalizedInput.length <= 8 ? 2 : 3;
  if (best.distance <= maxDistance || best.similarity >= 0.72) {
    return { value: best.value, exact: false, needsSuggestion: true };
  }

  return null;
}

function normalizeText(value) {
  return (value || "").toLowerCase().trim();
}

function normalizeAnswerValue(value) {
  return String(value || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .trim();
}

function normalizeFirmSalutationValue(value) {
  const normalized = normalizeText(value);
  if (normalized === "herr") return "Herr";
  if (normalized === "frau") return "Frau";
  if (normalized === "divers") return "Divers";
  return "";
}

function normalizeFirmInclusionValue(value) {
  const normalized = normalizeAnswerValue(value);
  if (normalized === "ja" || normalized === "yes" || normalized === "true" || normalized === "1") {
    return "Ja";
  }
  if (normalized === "nein" || normalized === "no" || normalized === "false" || normalized === "0") {
    return "Nein";
  }
  return "";
}

function studentNeedsInclusionSupport(student) {
  const value = normalizeAnswerValue(student && student.behinderung);
  return value === "ja" || value === "yes" || value === "true" || value === "1";
}

const DEFAULT_MATCH_RADIUS_VALUE = "de";

function normalizeGeoLookupValue(value) {
  return String(value || "")
    .toLowerCase()
    .replace(/ß/g, "ss")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9]+/g, " ")
    .trim()
    .replace(/\s+/g, " ");
}

