const LOCAL_CITY_GEO_LOOKUP = LOCAL_CITY_GEO_REFERENCE.reduce(function(map, entry) {
  entry.names.forEach(function(name) {
    const key = normalizeGeoLookupValue(name);
    if (key && !map[key]) {
      map[key] = { lat: entry.lat, lon: entry.lon };
    }
  });
  return map;
}, Object.create(null));

function normalizePostalCodeValue(value) {
  const normalized = String(value || "").trim();
  return /^[0-9]{5}$/.test(normalized) ? normalized : "";
}

function normalizeMatchRadiusValue(value) {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "5" || normalized === "10" || normalized === "25" || normalized === "50" || normalized === "100") {
    return normalized;
  }
  return DEFAULT_MATCH_RADIUS_VALUE;
}

function getMatchRadiusKm(value) {
  const normalized = normalizeMatchRadiusValue(value);
  if (normalized === DEFAULT_MATCH_RADIUS_VALUE) {
    return Number.POSITIVE_INFINITY;
  }
  const parsed = Number(normalized);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : Number.POSITIVE_INFINITY;
}

function formatMatchRadiusLabel(value) {
  const normalized = normalizeMatchRadiusValue(value);
  return normalized === DEFAULT_MATCH_RADIUS_VALUE ? "Deutschlandweit" : normalized + " km";
}

function getLocalGeoPoint(location) {
  if (!location) return null;

  const postalCode = normalizePostalCodeValue(location.plz || location.postalCode);
  if (postalCode && LOCAL_POSTAL_GEO_REFERENCE[postalCode]) {
    return {
      lat: LOCAL_POSTAL_GEO_REFERENCE[postalCode].lat,
      lon: LOCAL_POSTAL_GEO_REFERENCE[postalCode].lon,
      precision: "postal"
    };
  }

  const cityCandidates = [location.stadt, location.ort, location.city];
  for (let index = 0; index < cityCandidates.length; index++) {
    const normalizedCity = normalizeGeoLookupValue(cityCandidates[index]);
    if (normalizedCity && LOCAL_CITY_GEO_LOOKUP[normalizedCity]) {
      return {
        lat: LOCAL_CITY_GEO_LOOKUP[normalizedCity].lat,
        lon: LOCAL_CITY_GEO_LOOKUP[normalizedCity].lon,
        precision: "city"
      };
    }
  }

  return null;
}

function calculateHaversineDistanceKm(leftPoint, rightPoint) {
  if (!leftPoint || !rightPoint) {
    return null;
  }

  const earthRadiusKm = 6371;
  const latDistance = (rightPoint.lat - leftPoint.lat) * Math.PI / 180;
  const lonDistance = (rightPoint.lon - leftPoint.lon) * Math.PI / 180;
  const leftLatRad = leftPoint.lat * Math.PI / 180;
  const rightLatRad = rightPoint.lat * Math.PI / 180;
  const a = Math.sin(latDistance / 2) * Math.sin(latDistance / 2)
    + Math.cos(leftLatRad) * Math.cos(rightLatRad) * Math.sin(lonDistance / 2) * Math.sin(lonDistance / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return earthRadiusKm * c;
}

function roundKnownDistanceKm(distanceKm, allowZero) {
  if (!Number.isFinite(distanceKm)) {
    return null;
  }

  const rounded = Math.round(distanceKm);
  if (allowZero) {
    return Math.max(0, rounded);
  }
  return Math.max(1, rounded);
}

function estimatePostalDistanceKmFallback(leftLocation, rightLocation) {
  const leftPlz = normalizePostalCodeValue(leftLocation && (leftLocation.plz || leftLocation.postalCode));
  const rightPlz = normalizePostalCodeValue(rightLocation && (rightLocation.plz || rightLocation.postalCode));
  if (!leftPlz || !rightPlz) {
    return null;
  }
  if (leftPlz === rightPlz) {
    return 0;
  }

  const leftCity = normalizeText(leftLocation && (leftLocation.stadt || leftLocation.ort || leftLocation.city));
  const rightCity = normalizeText(rightLocation && (rightLocation.stadt || rightLocation.ort || rightLocation.city));
  if (leftCity && rightCity && leftCity === rightCity) {
    return 8;
  }
  if (leftPlz.slice(0, 4) === rightPlz.slice(0, 4)) {
    return 12;
  }
  if (leftPlz.slice(0, 3) === rightPlz.slice(0, 3)) {
    return 24;
  }
  if (leftPlz.slice(0, 2) === rightPlz.slice(0, 2)) {
    return 75;
  }

  const leftRegion = Number(leftPlz.slice(0, 2));
  const rightRegion = Number(rightPlz.slice(0, 2));
  if (leftPlz.charAt(0) === rightPlz.charAt(0) && Number.isFinite(leftRegion) && Number.isFinite(rightRegion) && Math.abs(leftRegion - rightRegion) <= 1) {
    return 95;
  }
  if (leftPlz.charAt(0) === rightPlz.charAt(0)) {
    return 160;
  }
  return 320;
}

function getDistanceEstimateMeta(leftLocation, rightLocation) {
  const leftPlz = normalizePostalCodeValue(leftLocation && (leftLocation.plz || leftLocation.postalCode));
  const rightPlz = normalizePostalCodeValue(rightLocation && (rightLocation.plz || rightLocation.postalCode));
  if (leftPlz && rightPlz && leftPlz === rightPlz) {
    return {
      distanceKm: 0,
      isKnown: true,
      label: "gleiche PLZ",
      source: "postal"
    };
  }

  const leftGeoPoint = getLocalGeoPoint(leftLocation);
  const rightGeoPoint = getLocalGeoPoint(rightLocation);
  const geoDistance = calculateHaversineDistanceKm(leftGeoPoint, rightGeoPoint);
  if (Number.isFinite(geoDistance)) {
    const roundedDistance = roundKnownDistanceKm(geoDistance, false);
    return {
      distanceKm: roundedDistance,
      isKnown: true,
      label: formatEstimatedDistanceLabel(roundedDistance),
      source: leftGeoPoint && rightGeoPoint && leftGeoPoint.precision === "postal" && rightGeoPoint.precision === "postal" ? "postal" : "city"
    };
  }

  const fallbackDistance = estimatePostalDistanceKmFallback(leftLocation, rightLocation);
  return {
    distanceKm: fallbackDistance,
    isKnown: Number.isFinite(fallbackDistance),
    label: formatEstimatedDistanceLabel(fallbackDistance),
    source: Number.isFinite(fallbackDistance) ? "heuristic" : "unknown"
  };
}

function estimatePostalDistanceKm(leftLocation, rightLocation) {
  return getDistanceEstimateMeta(leftLocation, rightLocation).distanceKm;
}

function formatEstimatedDistanceLabel(distanceKm) {
  if (!Number.isFinite(distanceKm)) {
    return "Distanz unbekannt";
  }
  if (distanceKm === 0) {
    return "gleiche PLZ";
  }
  return "ca. " + distanceKm + " km";
}

function compareDistanceAsc(leftDistance, rightDistance) {
  const leftValue = Number.isFinite(leftDistance) ? leftDistance : Number.POSITIVE_INFINITY;
  const rightValue = Number.isFinite(rightDistance) ? rightDistance : Number.POSITIVE_INFINITY;
  if (leftValue === rightValue) {
    return 0;
  }
  return leftValue < rightValue ? -1 : 1;
}

function getMatchDistanceMeta(student, offer) {
  const studentRadiusValue = normalizeMatchRadiusValue(student && student.matchUmkreis);
  const offerRadiusValue = normalizeMatchRadiusValue(offer && offer.matchUmkreis);
  const studentRadiusKm = getMatchRadiusKm(studentRadiusValue);
  const offerRadiusKm = getMatchRadiusKm(offerRadiusValue);
  const distanceMeta = getDistanceEstimateMeta(student, offer);
  const distanceKm = distanceMeta.distanceKm;
  const withinStudentRadius = distanceKm === null ? !Number.isFinite(studentRadiusKm) : distanceKm <= studentRadiusKm;
  const withinOfferRadius = distanceKm === null ? !Number.isFinite(offerRadiusKm) : distanceKm <= offerRadiusKm;

  return {
    distanceKm: distanceKm,
    distanceLabel: distanceMeta.label,
    distanceSource: distanceMeta.source,
    isDistanceKnown: distanceMeta.isKnown,
    studentRadiusValue: studentRadiusValue,
    studentRadiusKm: studentRadiusKm,
    studentRadiusLabel: formatMatchRadiusLabel(studentRadiusValue),
    offerRadiusValue: offerRadiusValue,
    offerRadiusKm: offerRadiusKm,
    offerRadiusLabel: formatMatchRadiusLabel(offerRadiusValue),
    withinStudentRadius: withinStudentRadius,
    withinOfferRadius: withinOfferRadius,
    isWithinRadius: withinStudentRadius && withinOfferRadius
  };
}

function getDistanceScore(distanceKm) {
  if (!Number.isFinite(distanceKm)) {
    return 0;
  }
  if (distanceKm <= 10) return 4;
  if (distanceKm <= 25) return 3;
  if (distanceKm <= 50) return 2;
  if (distanceKm <= 100) return 1;
  return 0;
}

const MATCH_DISPLAY_SCORE_MAX = 17;
const INTERNSHIP_MATCH_DISPLAY_SCORE_MAX = MATCH_DISPLAY_SCORE_MAX + 4;

function getMatchFitScore(entryArg) {
  const entry = entryArg && typeof entryArg === "object" ? entryArg : {};
  if (!String(entry.matchedProfession || "").trim()) {
    return 0;
  }

  let score = 10;
  if (entry.isAlternativeMatch) {
    score = 6;
  } else if (entry.isActivatedAlternativeProfession) {
    score = 8;
  }

  score += getDistanceScore(entry.distanceKm);
  if (entry.isInclusionMatch) {
    score += 3;
  }
  return score;
}

function getMatchProfileCompletenessScore(studentArg) {
  const student = studentArg && typeof studentArg === "object" ? studentArg : {};
  let score = 0;
  if (student.lebenslauf) score += 1;
  if (student.anschreiben) score += 1;
  if (student.zeugnis) score += 1;
  return score;
}

function getMatchScoreTone(scoreArg, maxScoreArg) {
  const score = Number(scoreArg || 0);
  const maxScore = Number(maxScoreArg || 0);
  const ratio = maxScore > 0 ? score / maxScore : 0;
  if (ratio >= 0.8) return "strong";
  if (ratio >= 0.55) return "medium";
  return "light";
}

function getMatchScoreMeta(entryArg, options) {
  const entry = entryArg && typeof entryArg === "object" ? entryArg : {};
  const includeSchedule = !!(options && options.includeSchedule);
  const fitScore = Number.isFinite(entry.fitScore) ? Number(entry.fitScore) : getMatchFitScore(entry);
  const schedulePriority = includeSchedule ? Number(entry.schedulePriority || 0) : 0;
  const visibleScore = Math.max(0, fitScore + schedulePriority);
  const maxScore = includeSchedule ? INTERNSHIP_MATCH_DISPLAY_SCORE_MAX : MATCH_DISPLAY_SCORE_MAX;
  const tone = getMatchScoreTone(visibleScore, maxScore);
  const percentage = maxScore > 0 ? Math.round((visibleScore / maxScore) * 100) : 0;

  return {
    score: visibleScore,
    maxScore: maxScore,
    percentage: percentage,
    tone: tone,
    label: visibleScore + "/" + maxScore,
    shortLabel: "Match-Score " + visibleScore + "/" + maxScore,
    studentChipClass: "student-contact-chip--score-" + tone,
    firmChipClass: "firm-match-chip--score-" + tone,
    adminChipClass: "matching-match-kind--score-" + tone
  };
}

function getProfessionFamily(profession) {
  const normalized = normalizeProfessionText(profession);
  if (!normalized) return null;

  for (let index = 0; index < PROFESSION_FAMILY_DEFINITIONS.length; index++) {
    const family = PROFESSION_FAMILY_DEFINITIONS[index];
    const hasKeywordMatch = family.keywords.some(function(keyword) {
      return normalized.includes(normalizeProfessionText(keyword));
    });
    if (hasKeywordMatch) {
      return family;
    }
  }

  return null;
}

function hasExactProfessionMatchForStudent(student, offers, options) {
  if (window.AzubiMatchDiscovery && typeof window.AzubiMatchDiscovery.hasExactProfessionMatchForStudent === "function") {
    return window.AzubiMatchDiscovery.hasExactProfessionMatchForStudent(student, offers, options);
  }

  if (!isStudentApprenticeshipSearchActive(student)) {
    return false;
  }

  const config = options || {};
  const offerList = Array.isArray(offers) ? offers : loadOffers();
  return offerList.some(function(offer) {
    if (!isFirmApprenticeshipMatchingEnabled(offer)) {
      return false;
    }
    if (!getExactMatchedProfession(student, offer)) {
      return false;
    }
    if (!config.respectRadius) {
      return true;
    }
    return getMatchDistanceMeta(student, offer).isWithinRadius;
  });
}

function getStudentActivatedAlternativeProfessions(student) {
  const rawList = Array.isArray(student && student.activatedAlternativeProfessions)
    ? student.activatedAlternativeProfessions
    : [];
  const seen = new Set();

  return rawList.reduce(function(list, entry) {
    const profession = typeof entry === "string"
      ? entry
      : (entry && entry.profession ? entry.profession : "");
    const normalizedProfession = normalizeProfessionText(profession);
    if (!normalizedProfession || seen.has(normalizedProfession)) {
      return list;
    }
    seen.add(normalizedProfession);
    list.push({
      profession: String(profession || "").trim(),
      familyKey: typeof entry === "object" && entry ? String(entry.familyKey || "") : "",
      familyLabel: typeof entry === "object" && entry ? String(entry.familyLabel || "") : "",
      activatedAt: typeof entry === "object" && entry ? String(entry.activatedAt || "") : ""
    });
    return list;
  }, []);
}

function getActivatedAlternativeProfessionMatch(student, offer) {
  if (!student || !offer) return null;

  const activatedProfessions = getStudentActivatedAlternativeProfessions(student);
  if (!activatedProfessions.length) return null;

  const offerProfessions = getOfferProfessionList(offer);
  for (let index = 0; index < activatedProfessions.length; index++) {
    const activatedEntry = activatedProfessions[index];
    const matchedProfession = offerProfessions.find(function(entry) {
      return normalizeProfessionText(entry) === normalizeProfessionText(activatedEntry.profession);
    });
    if (matchedProfession) {
      return {
        matchedProfession: matchedProfession,
        familyKey: activatedEntry.familyKey || "",
        familyLabel: activatedEntry.familyLabel || "",
        activatedAt: activatedEntry.activatedAt || ""
      };
    }
  }

  return null;
}

function activateStudentAlternativeProfession(studentArg, professionData) {
  if (!studentArg || !professionData || !professionData.profession) return null;

  const students = loadStudents();
  const studentIndex = students.findIndex(function(entry) {
    return entry.id === studentArg.id || (studentArg.profilCode && entry.profilCode === studentArg.profilCode);
  });
  if (studentIndex === -1) return null;

  const current = students[studentIndex];
  const activatedList = getStudentActivatedAlternativeProfessions(current);
  const normalizedProfession = normalizeProfessionText(professionData.profession);
  const alreadyActive = activatedList.some(function(entry) {
    return normalizeProfessionText(entry.profession) === normalizedProfession;
  });
  if (alreadyActive) {
    return current;
  }

  const nextEntry = {
    profession: String(professionData.profession || "").trim(),
    familyKey: String(professionData.familyKey || "").trim(),
    familyLabel: String(professionData.familyLabel || "").trim(),
    activatedAt: new Date().toISOString()
  };
  const nextStudents = students.slice();
  nextStudents[studentIndex] = {
    ...current,
    activatedAlternativeProfessions: activatedList.concat(nextEntry)
  };
  saveStudents(nextStudents);
  return nextStudents[studentIndex];
}

function deactivateStudentAlternativeProfession(studentArg, profession) {
  if (!studentArg || !profession) return null;

  const students = loadStudents();
  const studentIndex = students.findIndex(function(entry) {
    return entry.id === studentArg.id || (studentArg.profilCode && entry.profilCode === studentArg.profilCode);
  });
  if (studentIndex === -1) return null;

  const current = students[studentIndex];
  const remaining = getStudentActivatedAlternativeProfessions(current).filter(function(entry) {
    return normalizeProfessionText(entry.profession) !== normalizeProfessionText(profession);
  });

  const nextStudents = students.slice();
  nextStudents[studentIndex] = {
    ...current,
    activatedAlternativeProfessions: remaining
  };
  saveStudents(nextStudents);
  return nextStudents[studentIndex];
}

function getAlternativeMatchedProfession(student, offer, offers) {
  if (!student || !offer) return null;
  if (getExactMatchedProfession(student, offer)) return null;

  const offerList = Array.isArray(offers) ? offers : loadOffers();
  if (hasExactProfessionMatchForStudent(student, offerList, { respectRadius: true })) return null;

  const studentFamily = getProfessionFamily(student.beruf);
  if (!studentFamily) return null;

  const alternativeProfession = getOfferProfessionList(offer).find(function(entry) {
    const offerFamily = getProfessionFamily(entry);
    return !!(offerFamily && offerFamily.key === studentFamily.key);
  });

  if (!alternativeProfession) return null;

  return {
    matchedProfession: alternativeProfession,
    familyKey: studentFamily.key,
    familyLabel: studentFamily.label
  };
}

function buildAlternativeMatchExplanation(student, matchedProfession, familyLabel) {
  const desiredProfession = String(student && student.beruf ? student.beruf : "dein Wunschberuf").trim() || "dein Wunschberuf";
  const proposedProfession = String(matchedProfession || "der vorgeschlagene Ausbildungsberuf").trim() || "der vorgeschlagene Ausbildungsberuf";
  const sharedFamily = String(familyLabel || "demselben Berufsfeld").trim() || "demselben Berufsfeld";

  return 'Dein Wunschberuf "' + desiredProfession + '" und der vorgeschlagene Ausbildungsberuf "' + proposedProfession + '" liegen beide im Berufsfeld "' + sharedFamily + '". Weil aktuell kein direkter Treffer für "' + desiredProfession + '" im Portal vorhanden ist, zeigen wir dir diese Alternative als nächsten passenden Einstieg.';
}

function getStudentAlternativeProfessionSuggestions(studentArg, options) {
  const config = options || {};
  const student = studentArg || null;
  if (!student || !String(student.beruf || "").trim()) return [];
  if (!isStudentApprenticeshipSearchActive(student)) return [];

  const studentFamily = getProfessionFamily(student.beruf);
  if (!studentFamily) return [];

  const offerList = (Array.isArray(config.offers) ? config.offers : loadOffers()).filter(function(offer) {
    return isFirmAccountReleased(offer);
  });
  const requests = loadFullProfileRequests();
  const activatedSet = new Set(getStudentActivatedAlternativeProfessions(student).map(function(entry) {
    return normalizeProfessionText(entry.profession);
  }));
  const normalizedDesiredProfession = normalizeProfessionText(student.beruf);
  const suggestionMap = new Map();

  offerList.forEach(function(offer) {
    const distanceMeta = getMatchDistanceMeta(student, offer);
    if (!distanceMeta.isWithinRadius) return;

    const offerSummary = buildFirmQuickProfileSummaryData(offer, null);
    getOfferProfessionList(offer).forEach(function(professionEntry) {
      const profession = String(professionEntry || "").trim();
      const normalizedProfession = normalizeProfessionText(profession);
      if (!normalizedProfession || normalizedProfession === normalizedDesiredProfession || activatedSet.has(normalizedProfession)) {
        return;
      }

      const professionFamily = getProfessionFamily(profession);
      if (!professionFamily || professionFamily.key !== studentFamily.key) {
        return;
      }

      if (isStudentFirmMatchSuppressed(student, offer, profession, requests)) {
        return;
      }

      const offerKey = String(offer.id || offer.userId || offer.userEmail || offerSummary.name || profession);
      const existing = suggestionMap.get(normalizedProfession);
      if (existing) {
        if (!existing.offerKeys.has(offerKey)) {
          existing.offerKeys.add(offerKey);
          existing.companyCount += 1;
          if (existing.sampleCompanies.length < 3) {
            existing.sampleCompanies.push({
              name: offerSummary.name || "Firma",
              city: offerSummary.city || "-"
            });
          }
        }
        if (!Number.isFinite(existing.nearestDistanceKm) || compareDistanceAsc(distanceMeta.distanceKm, existing.nearestDistanceKm) < 0) {
          existing.nearestDistanceKm = distanceMeta.distanceKm;
          existing.nearestDistanceLabel = distanceMeta.distanceLabel;
        }
        if (offerSupportsInclusionMatch(offer)) {
          existing.hasInclusionOption = true;
        }
        return;
      }

      suggestionMap.set(normalizedProfession, {
        profession: profession,
        familyKey: studentFamily.key,
        familyLabel: studentFamily.label,
        companyCount: 1,
        nearestDistanceKm: distanceMeta.distanceKm,
        nearestDistanceLabel: distanceMeta.distanceLabel,
        hasInclusionOption: offerSupportsInclusionMatch(offer),
        sampleCompanies: [{
          name: offerSummary.name || "Firma",
          city: offerSummary.city || "-"
        }],
        offerKeys: new Set([offerKey])
      });
    });
  });

  return Array.from(suggestionMap.values())
    .sort(function(left, right) {
      if (right.companyCount !== left.companyCount) {
        return right.companyCount - left.companyCount;
      }
      const distanceCompare = compareDistanceAsc(left.nearestDistanceKm, right.nearestDistanceKm);
      if (distanceCompare !== 0) {
        return distanceCompare;
      }
      return String(left.profession || "").localeCompare(String(right.profession || ""), "de");
    })
    .map(function(entry) {
      return {
        profession: entry.profession,
        familyKey: entry.familyKey,
        familyLabel: entry.familyLabel,
        companyCount: entry.companyCount,
        nearestDistanceKm: entry.nearestDistanceKm,
        nearestDistanceLabel: entry.nearestDistanceLabel,
        hasInclusionOption: entry.hasInclusionOption,
        sampleCompanies: entry.sampleCompanies
      };
    });
}

var BEHINDERUNGSART_LABELS = {
  "koerperlich-motorisch": "Körperlich-motorische Einschränkung",
  "chronisch-krank": "Chronische Erkrankung",
  "sehbeeintraechtigung": "Sehbeeinträchtigung",
  "blindheit": "Blindheit",
  "hoerbeeintraechtigung": "Hörbeeinträchtigung",
  "taubheit": "Gehörlosigkeit / Taubheit",
  "taubblind": "Taubblindheit",
  "lernbehinderung": "Lernbehinderung",
  "geistige-behinderung": "Geistige Behinderung",
  "legasthenie": "Legasthenie / Lese-Rechtschreib-Störung",
  "dyskalkulie": "Dyskalkulie",
  "adhs": "ADHS",
  "autismus": "Autismus-Spektrum",
  "psychisch": "Psychische Erkrankung",
  "angststoerung": "Angststörung",
  "depression": "Depression",
  "sprachbehinderung": "Sprachbehinderung / Stottern",
  "mehrfachbehinderung": "Mehrfachbehinderung",
  "sonstige": "Sonstige Beeinträchtigung"
};

function getBehinderungsArtLabel(value) {
  if (!value) return "";
  return BEHINDERUNGSART_LABELS[value] || value;
}

function syncStudentDisabilityFields(options) {
  const config = options || {};
  const behinderungInput = document.getElementById(config.selectId || "behinderung");
  const detailsGroup = document.getElementById(config.groupId || "behinderungDetailsGroup");
  const artInput = document.getElementById(config.artId || "behinderungsArt");
  const gradInput = document.getElementById(config.gradeId || "behinderungsGrad");
  const isActive = studentNeedsInclusionSupport({ behinderung: behinderungInput && behinderungInput.value });

  if (detailsGroup) {
    detailsGroup.hidden = !isActive;
  }

  [artInput, gradInput].forEach(function(input) {
    if (!input) return;
    input.disabled = !isActive;
    input.required = isActive;
    if (!isActive && config.clearWhenHidden) {
      input.value = "";
    }
  });

  return isActive;
}

function offerSupportsInclusionMatch(offer) {
  const value = normalizeAnswerValue(offer && offer.platzBehindert);
  return value === "ja" || value === "yes" || value === "true" || value === "1";
}

function isInternshipDateMatchVisible(studentArg, offerArg) {
  const student = studentArg && typeof studentArg === "object" ? studentArg : {};
  const offer = offerArg && typeof offerArg === "object" ? offerArg : {};
  const isInternshipContext = !!(student.isInternship || offer.isInternship);
  if (!isInternshipContext) {
    return true;
  }

  const studentStart = normalizeInternshipDateValue(student.praktikumStartdatum);
  const studentEnd = normalizeInternshipDateValue(student.praktikumEnddatum);
  const offerStart = normalizeInternshipDateValue(offer.praktikumStartdatum);
  const offerEnd = normalizeInternshipDateValue(offer.praktikumEnddatum);

  if (!studentStart || !studentEnd || !offerStart || !offerEnd) {
    return false;
  }

  const overlapStart = studentStart > offerStart ? studentStart : offerStart;
  const overlapEnd = studentEnd < offerEnd ? studentEnd : offerEnd;
  return overlapStart <= overlapEnd;
}

function getMatchMeta(student, offer, options) {
  if (window.AzubiMatchDiscovery && typeof window.AzubiMatchDiscovery.getMatchMeta === "function") {
    return window.AzubiMatchDiscovery.getMatchMeta(student, offer, options);
  }

  const distanceMeta = getMatchDistanceMeta(student, offer);

  if (!isStudentSearchActiveForOffer(student, offer)) {
    return {
      matchedProfession: "",
      isVisibleMatch: false,
      isInclusionMatch: false,
      isAlternativeMatch: false,
      isActivatedAlternativeProfession: false,
      alternativeFamilyKey: "",
      alternativeFamilyLabel: "",
      alternativeExplanation: "",
      matchLabel: "Direktes Match",
      distanceKm: distanceMeta.distanceKm,
      distanceLabel: distanceMeta.distanceLabel,
      isDistanceKnown: distanceMeta.isDistanceKnown,
      isWithinRadius: distanceMeta.isWithinRadius,
      studentRadiusValue: distanceMeta.studentRadiusValue,
      studentRadiusLabel: distanceMeta.studentRadiusLabel,
      offerRadiusValue: distanceMeta.offerRadiusValue,
      offerRadiusLabel: distanceMeta.offerRadiusLabel
    };
  }

  if (!isFirmApprenticeshipMatchingEnabled(offer)) {
    return {
      matchedProfession: "",
      isVisibleMatch: false,
      isInclusionMatch: false,
      isAlternativeMatch: false,
      isActivatedAlternativeProfession: false,
      alternativeFamilyKey: "",
      alternativeFamilyLabel: "",
      alternativeExplanation: "",
      matchLabel: "Direktes Match",
      distanceKm: distanceMeta.distanceKm,
      distanceLabel: distanceMeta.distanceLabel,
      isDistanceKnown: distanceMeta.isDistanceKnown,
      isWithinRadius: distanceMeta.isWithinRadius,
      studentRadiusValue: distanceMeta.studentRadiusValue,
      studentRadiusLabel: distanceMeta.studentRadiusLabel,
      offerRadiusValue: distanceMeta.offerRadiusValue,
      offerRadiusLabel: distanceMeta.offerRadiusLabel
    };
  }

  const config = options || {};
  const allOffers = Array.isArray(config.allOffers) ? config.allOffers : loadOffers();
  const exactMatchedProfession = getExactMatchedProfession(student, offer);
  const activatedAlternativeMatch = exactMatchedProfession ? null : getActivatedAlternativeProfessionMatch(student, offer);
  const alternativeMatch = exactMatchedProfession || activatedAlternativeMatch ? null : getAlternativeMatchedProfession(student, offer, allOffers);
  const matchedProfession = exactMatchedProfession
    || (activatedAlternativeMatch && activatedAlternativeMatch.matchedProfession)
    || (alternativeMatch && alternativeMatch.matchedProfession)
    || "";
  const isActivatedAlternativeProfession = !exactMatchedProfession && !!activatedAlternativeMatch;
  const isAlternativeMatch = !exactMatchedProfession && !activatedAlternativeMatch && !!alternativeMatch;
  const isInclusionMatch = !!matchedProfession && studentNeedsInclusionSupport(student) && offerSupportsInclusionMatch(offer);
  let matchLabel = "Direktes Match";
  if (isAlternativeMatch && isInclusionMatch) {
    matchLabel = "Inklusions-Berufsfeld-Match";
  } else if (isActivatedAlternativeProfession && isInclusionMatch) {
    matchLabel = "Aktivierter Inklusions-Match";
  } else if (isInclusionMatch) {
    matchLabel = "Inklusions-Match";
  } else if (isActivatedAlternativeProfession) {
    matchLabel = "Aktivierter Alternativberuf";
  } else if (isAlternativeMatch) {
    matchLabel = "Berufsfeld-Match";
  }

  const alternativeFamilyLabel = alternativeMatch
    ? alternativeMatch.familyLabel
    : (activatedAlternativeMatch ? activatedAlternativeMatch.familyLabel : "");
  const alternativeExplanation = isAlternativeMatch
    ? buildAlternativeMatchExplanation(student, matchedProfession, alternativeFamilyLabel)
    : "";

  return {
    matchedProfession: matchedProfession,
    isVisibleMatch: !!matchedProfession && distanceMeta.isWithinRadius && isInternshipDateMatchVisible(student, offer),
    isInclusionMatch: isInclusionMatch,
    isAlternativeMatch: isAlternativeMatch,
    isActivatedAlternativeProfession: isActivatedAlternativeProfession,
    alternativeFamilyKey: alternativeMatch ? alternativeMatch.familyKey : (activatedAlternativeMatch ? activatedAlternativeMatch.familyKey : ""),
    alternativeFamilyLabel: alternativeFamilyLabel,
    alternativeExplanation: alternativeExplanation,
    matchLabel: matchLabel,
    distanceKm: distanceMeta.distanceKm,
    distanceLabel: distanceMeta.distanceLabel,
    isDistanceKnown: distanceMeta.isDistanceKnown,
    isWithinRadius: distanceMeta.isWithinRadius,
    studentRadiusValue: distanceMeta.studentRadiusValue,
    studentRadiusLabel: distanceMeta.studentRadiusLabel,
    offerRadiusValue: distanceMeta.offerRadiusValue,
    offerRadiusLabel: distanceMeta.offerRadiusLabel
  };
}

function readBlobAsDataUrl(blob) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result);
    reader.onerror = () => reject(new Error("Datei konnte nicht gelesen werden."));
    reader.readAsDataURL(blob);
  });
}

function dataUrlSizeBytes(dataUrl) {
  const raw = String(dataUrl || "");
  const commaIndex = raw.indexOf(",");
  if (commaIndex === -1) return 0;
  const base64 = raw.slice(commaIndex + 1);
  const padding = base64.endsWith("==") ? 2 : base64.endsWith("=") ? 1 : 0;
  return Math.max(0, Math.floor((base64.length * 3) / 4) - padding);
}

function canvasToBlob(canvas, mimeType, quality) {
  return new Promise((resolve, reject) => {
    canvas.toBlob((blob) => {
      if (!blob) {
        reject(new Error("Bild konnte nicht verarbeitet werden."));
        return;
      }
      resolve(blob);
    }, mimeType, quality);
  });
}

function loadImageFromFile(file) {
  return new Promise((resolve, reject) => {
    const url = URL.createObjectURL(file);
    const image = new Image();
    image.onload = () => {
      URL.revokeObjectURL(url);
      resolve(image);
    };
    image.onerror = () => {
      URL.revokeObjectURL(url);
      reject(new Error("Bild konnte nicht geladen werden."));
    };
    image.src = url;
  });
}

async function shrinkImageToSize(file, maxSizeBytes) {
  const image = await loadImageFromFile(file);
  const mimeType = file.type || "image/jpeg";
  const originalWidth = image.naturalWidth || image.width;
  const originalHeight = image.naturalHeight || image.height;

  let scale = 1;
  let quality = 0.9;
  let bestBlob = file;

  for (let attempt = 0; attempt < 10; attempt++) {
    const width = Math.max(200, Math.round(originalWidth * scale));
    const height = Math.max(200, Math.round(originalHeight * scale));

    const canvas = document.createElement("canvas");
    canvas.width = width;
    canvas.height = height;

    const ctx = canvas.getContext("2d");
    if (!ctx) throw new Error("Bildverarbeitung nicht verfügbar.");
    ctx.drawImage(image, 0, 0, width, height);

    const blob = await canvasToBlob(canvas, mimeType, quality);
    if (blob.size < bestBlob.size) bestBlob = blob;
    if (blob.size <= maxSizeBytes) return blob;

    if (quality > 0.45) {
      quality -= 0.1;
    } else {
      scale *= 0.85;
    }
  }

  return bestBlob;
}

function isPdfDocumentFile(file) {
  const type = String((file && file.type) || "").toLowerCase();
  const name = String((file && file.name) || "").toLowerCase();
  return type === "application/pdf" || name.endsWith(".pdf");
}

function isImageFile(file) {
  const type = String((file && file.type) || "").toLowerCase();
  const name = String((file && file.name) || "").toLowerCase();
  return type.startsWith("image/") || /\.(png|jpe?g|webp|gif)$/i.test(name);
}

function createPngFileName(file, fallbackName) {
  const sourceName = String((file && file.name) || fallbackName || "dokument").trim() || "dokument";
  const baseName = sourceName.replace(/\.[^.]+$/i, "");
  return baseName + ".png";
}

function loadScriptOnce(src, marker) {
  return new Promise((resolve, reject) => {
    if (!isSameOriginRuntimeUrl(src)) {
      reject(new Error("Externe Script-Requests sind deaktiviert."));
      return;
    }

    const existing = document.querySelector("script[data-loader='" + marker + "']");
    if (existing) {
      if (existing.getAttribute("data-ready") === "1") {
        resolve();
      } else {
        existing.addEventListener("load", () => resolve());
        existing.addEventListener("error", () => reject(new Error("Bibliothek konnte nicht geladen werden.")));
      }
      return;
    }

    const script = document.createElement("script");
    script.src = src;
    script.async = true;
    script.setAttribute("data-loader", marker);
    script.onload = () => {
      script.setAttribute("data-ready", "1");
      resolve();
    };
    script.onerror = () => reject(new Error("Bibliothek konnte nicht geladen werden."));
    document.head.appendChild(script);
  });
}

function getRuntimeAssetBaseUrl() {
  if (window.__azubiMatchAssetBaseUrl) {
    return window.__azubiMatchAssetBaseUrl;
  }

  const scriptElements = Array.from(document.querySelectorAll("script[src]"));
  const matchingScripts = scriptElements.filter(function(entry) {
    const source = String(entry.getAttribute("src") || "").trim();
    return /(^|\/)script\.js(?:[?#].*)?$/i.test(source);
  });
  const ownScript = matchingScripts.length ? matchingScripts[matchingScripts.length - 1] : null;

  if (ownScript && ownScript.src) {
    window.__azubiMatchAssetBaseUrl = new URL(".", ownScript.src).toString();
    return window.__azubiMatchAssetBaseUrl;
  }

  window.__azubiMatchAssetBaseUrl = new URL(".", window.location.href).toString();
  return window.__azubiMatchAssetBaseUrl;
}

function getRuntimeAssetUrl(relativePath) {
  const relative = String(relativePath || "").replace(/^\/+/, "");
  return new URL(relative, getRuntimeAssetBaseUrl()).toString();
}

function isLocalFileRuntime() {
  return window.location && window.location.protocol === "file:";
}

async function loadModuleOnce(relativePath, cacheKey) {
  const key = String(cacheKey || relativePath || uniqueId("module")).trim();
  const cache = window.__azubiMatchModuleCache || (window.__azubiMatchModuleCache = {});

  if (!cache[key]) {
    const source = getRuntimeAssetUrl(relativePath);
    if (!isSameOriginRuntimeUrl(source)) {
      throw new Error("Externe Script-Requests sind deaktiviert.");
    }

    cache[key] = import(source).catch(function(error) {
      delete cache[key];
      throw error;
    });
  }

  return cache[key];
}

async function loadLegacyGlobalOnce(relativePath, marker, globalName, validator) {
  const existingValue = window[globalName];
  if (validator(existingValue)) {
    return existingValue;
  }

  await loadScriptOnce(getRuntimeAssetUrl(relativePath), marker);
  const loadedValue = window[globalName];
  if (!validator(loadedValue)) {
    throw new Error("Die lokale Bibliothek " + globalName + " konnte nicht initialisiert werden.");
  }

  return loadedValue;
}

async function loadPdfLibLibrary() {
  let PDFLib = window.PDFLib;
  if (!PDFLib || !PDFLib.PDFDocument) {
    if (isLocalFileRuntime()) {
      PDFLib = await loadLegacyGlobalOnce(
        "vendor/pdf-lib/pdf-lib.legacy.min.js",
        "pdf-lib-legacy",
        "PDFLib",
        function(candidate) {
          return !!candidate && typeof candidate.PDFDocument === "function";
        }
      );
    } else {
      PDFLib = await loadModuleOnce("vendor/pdf-lib/pdf-lib.esm.min.js", "pdf-lib");
    }

    if (!PDFLib || !PDFLib.PDFDocument) {
      throw new Error("Die lokale PDF-Library konnte nicht initialisiert werden.");
    }

    window.PDFLib = PDFLib;
  }

  return PDFLib;
}

async function loadPdfJsWorkerLegacy() {
  const existingWorker = window.pdfjsWorker;
  if (existingWorker && typeof existingWorker.WorkerMessageHandler === "function") {
    return existingWorker;
  }

  if (!window.__azubiMatchPdfJsWorkerPromise) {
    window.__azubiMatchPdfJsWorkerPromise = new Promise(function(resolve, reject) {
      const workerUrl = getRuntimeAssetUrl("vendor/pdfjs/pdf.worker.legacy.min.js");
      const iframe = document.createElement("iframe");
      iframe.src = "about:blank";
      iframe.hidden = true;
      iframe.setAttribute("aria-hidden", "true");
      document.body.appendChild(iframe);

      const cleanupWithError = function(error) {
        iframe.remove();
        reject(error);
      };

      const frameWindow = iframe.contentWindow;
      const frameDocument = frameWindow && frameWindow.document;
      if (!frameWindow || !frameDocument) {
        cleanupWithError(new Error("Der lokale PDF-Worker konnte nicht initialisiert werden."));
        return;
      }

      const script = frameDocument.createElement("script");
      script.src = workerUrl;
      script.async = true;
      script.onload = function() {
        try {
          const workerGlobal = frameWindow.pdfjsWorker;
          if (!workerGlobal || typeof workerGlobal.WorkerMessageHandler !== "function") {
            throw new Error("Die lokale Bibliothek pdfjsWorker konnte nicht initialisiert werden.");
          }

          window.pdfjsWorker = workerGlobal;
          window.__azubiMatchPdfJsWorkerFrame = iframe;
          resolve(workerGlobal);
        } catch (error) {
          cleanupWithError(error);
        }
      };
      script.onerror = function() {
        cleanupWithError(new Error("Der lokale PDF-Worker konnte nicht geladen werden."));
      };

      frameDocument.head.appendChild(script);
    }).catch(function(error) {
      delete window.__azubiMatchPdfJsWorkerPromise;
      throw error;
    });
  }

  return window.__azubiMatchPdfJsWorkerPromise;
}

async function configurePdfJsLibrary(pdfjsLib) {
  if (!pdfjsLib || typeof pdfjsLib.getDocument !== "function") {
    throw new Error("Die lokal eingebundene pdf.js-Bibliothek konnte nicht initialisiert werden.");
  }

  if (isLocalFileRuntime()) {
    if (pdfjsLib.GlobalWorkerOptions) {
      pdfjsLib.GlobalWorkerOptions.workerSrc = getRuntimeAssetUrl("vendor/pdfjs/pdf.worker.legacy.min.js");
    }
    return pdfjsLib;
  }

  if (pdfjsLib.GlobalWorkerOptions) {
    pdfjsLib.GlobalWorkerOptions.workerSrc = getRuntimeAssetUrl("vendor/pdfjs/pdf.worker.min.js");
  }

  return pdfjsLib;
}

function createPdfDocumentTask(pdfjsLib, source) {
  const taskOptions = source && typeof source === "object" ? { ...source } : {};
  if (isLocalFileRuntime()) {
    taskOptions.disableWorker = true;
  }
  return pdfjsLib.getDocument(taskOptions);
}

async function createConfiguredPdfDocumentTask(pdfjsLib, source) {
  if (isLocalFileRuntime()) {
    await loadPdfJsWorkerLegacy();
  }
  return createPdfDocumentTask(pdfjsLib, source);
}

async function loadPdfJsLibrary() {
  if (window.pdfjsLib && typeof window.pdfjsLib.getDocument === "function") {
    return await configurePdfJsLibrary(window.pdfjsLib);
  }

  if (isLocalFileRuntime()) {
    const localPdfJsLib = await loadLegacyGlobalOnce(
      "vendor/pdfjs/pdf.legacy.min.js",
      "pdfjs-legacy",
      "pdfjsLib",
      function(candidate) {
        return !!candidate && typeof candidate.getDocument === "function";
      }
    );

    window.pdfjsLib = localPdfJsLib;
    return await configurePdfJsLibrary(localPdfJsLib);
  }

  let pdfjsLib = null;
  try {
    pdfjsLib = await loadModuleOnce("vendor/pdfjs/pdf.min.js", "pdfjs");
  } catch (moduleError) {
    const legacyPdfJsLib = await loadLegacyGlobalOnce(
      "vendor/pdfjs/pdf.legacy.min.js",
      "pdfjs-legacy-http",
      "pdfjsLib",
      function(candidate) {
        return !!candidate && typeof candidate.getDocument === "function";
      }
    ).catch(function(legacyError) {
      const moduleMessage = moduleError && moduleError.message
        ? moduleError.message
        : "Das Modul konnte nicht geladen werden.";
      const legacyMessage = legacyError && legacyError.message
        ? legacyError.message
        : "Der Legacy-Fallback konnte nicht geladen werden.";
      throw new Error("pdf.js konnte weder als Modul noch ueber den Legacy-Fallback geladen werden. Modul: " + moduleMessage + " Legacy: " + legacyMessage);
    });

    window.pdfjsLib = legacyPdfJsLib;
    return await configurePdfJsLibrary(legacyPdfJsLib);
  }

  window.pdfjsLib = pdfjsLib;
  return await configurePdfJsLibrary(pdfjsLib);
}

async function convertPdfFirstPageToPng(file, maxSizeBytes) {
  const pdfjsLib = await loadPdfJsLibrary();
  const pdfBytes = await file.arrayBuffer();
  const loadingTask = await createConfiguredPdfDocumentTask(pdfjsLib, { data: pdfBytes });
  const pdf = await loadingTask.promise;
  const page = await pdf.getPage(1);

  let scale = 2;
  let bestBlob = null;

  for (let attempt = 0; attempt < 8; attempt++) {
    const viewport = page.getViewport({ scale: scale });
    const canvas = document.createElement("canvas");
    canvas.width = Math.max(1, Math.round(viewport.width));
    canvas.height = Math.max(1, Math.round(viewport.height));

    const ctx = canvas.getContext("2d");
    if (!ctx) throw new Error("PDF konnte nicht in ein Bild umgewandelt werden.");

    await page.render({ canvasContext: ctx, viewport: viewport }).promise;
    const blob = await canvasToBlob(canvas, "image/png");

    if (!bestBlob || blob.size < bestBlob.size) {
      bestBlob = blob;
    }
    if (blob.size <= maxSizeBytes) {
      return blob;
    }

    scale *= 0.8;
  }

  if (!bestBlob) {
    throw new Error("PDF konnte nicht in PNG umgewandelt werden.");
  }

  return bestBlob;
}

async function convertImageFileToPng(file, maxSizeBytes) {
  const image = await loadImageFromFile(file);
  const originalWidth = image.naturalWidth || image.width;
  const originalHeight = image.naturalHeight || image.height;

  let scale = 1;
  let bestBlob = null;

  for (let attempt = 0; attempt < 10; attempt++) {
    const width = Math.max(200, Math.round(originalWidth * scale));
    const height = Math.max(200, Math.round(originalHeight * scale));
    const canvas = document.createElement("canvas");
    canvas.width = width;
    canvas.height = height;

    const ctx = canvas.getContext("2d");
    if (!ctx) throw new Error("Bild konnte nicht in PNG umgewandelt werden.");
    ctx.drawImage(image, 0, 0, width, height);

    const blob = await canvasToBlob(canvas, "image/png");
    if (!bestBlob || blob.size < bestBlob.size) {
      bestBlob = blob;
    }
    if (blob.size <= maxSizeBytes) {
      return blob;
    }

    scale *= 0.85;
  }

  if (!bestBlob) {
    throw new Error("Bild konnte nicht in PNG umgewandelt werden.");
  }

  return bestBlob;
}

async function convertDocumentToPng(file, maxSizeBytes) {
  if (isPdfDocumentFile(file)) {
    return convertPdfFirstPageToPng(file, maxSizeBytes);
  }

  if (isImageFile(file)) {
    return convertImageFileToPng(file, maxSizeBytes);
  }

  throw new Error(
    "Datei " + (file && file.name ? file.name : "")
    + " kann nicht als PNG gespeichert werden. Bitte PDF, JPG oder PNG hochladen."
  );
}

async function shrinkPdfToSize(file, maxSizeBytes) {
  const PDFLib = await loadPdfLibLibrary();

  const PDFDocument = PDFLib.PDFDocument;
  const inputBytes = await file.arrayBuffer();
  const sourceDoc = await PDFDocument.load(inputBytes, { updateMetadata: false });

  let bestBlob = file;

  const compactBytes = await sourceDoc.save({
    useObjectStreams: true,
    addDefaultPage: false,
    updateFieldAppearances: false
  });
  const compactBlob = new Blob([compactBytes], { type: "application/pdf" });
  if (compactBlob.size < bestBlob.size) bestBlob = compactBlob;
  if (compactBlob.size <= maxSizeBytes) return compactBlob;

  const rebuiltDoc = await PDFDocument.create();
  const indices = sourceDoc.getPageIndices();
  const pages = await rebuiltDoc.copyPages(sourceDoc, indices);
  pages.forEach((page) => rebuiltDoc.addPage(page));
  const rebuiltBytes = await rebuiltDoc.save({ useObjectStreams: true, addDefaultPage: false });
  const rebuiltBlob = new Blob([rebuiltBytes], { type: "application/pdf" });
  if (rebuiltBlob.size < bestBlob.size) bestBlob = rebuiltBlob;

  return bestBlob;
}

async function fileToDataUrl(file, options) {
  const opts = options || {};
  const maxSizeBytes = typeof opts.maxSizeBytes === "number" ? opts.maxSizeBytes : (5 * 1024 * 1024);
  const maxPdfSizeBytes = typeof opts.maxPdfSizeBytes === "number" ? opts.maxPdfSizeBytes : Math.round(2.5 * 1024 * 1024);
  const autoResizeImages = opts.autoResizeImages !== false;
  const autoCompressPdf = opts.autoCompressPdf !== false;
  const effectiveMaxSizeBytes = isPdfDocumentFile(file) ? maxPdfSizeBytes : maxSizeBytes;
  const limitMbText = (effectiveMaxSizeBytes / (1024 * 1024)).toFixed(1).replace(/\.0$/, "");

  let sourceBlob = file;

  if (sourceBlob.size > effectiveMaxSizeBytes && autoResizeImages && String(file.type || "").startsWith("image/")) {
    sourceBlob = await shrinkImageToSize(file, effectiveMaxSizeBytes);
  }

  if (sourceBlob.size > effectiveMaxSizeBytes && autoCompressPdf && isPdfDocumentFile(file)) {
    sourceBlob = await shrinkPdfToSize(file, effectiveMaxSizeBytes);
  }

  if (sourceBlob.size > effectiveMaxSizeBytes) {
    if (isPdfDocumentFile(file)) {
      throw new Error("Datei " + (file.name || "") + " ist zu groß (max. " + limitMbText + " MB). PDF wurde automatisch komprimiert, ist aber weiterhin zu groß.");
    }
    throw new Error("Datei " + (file.name || "") + " ist zu groß (max. " + limitMbText + " MB). Bei Bildern bitte Auflösung reduzieren.");
  }

  return readBlobAsDataUrl(sourceBlob);
}

async function collectFileData(inputId, options) {
  const input = document.getElementById(inputId);
  const file = input && input.files && input.files[0] ? input.files[0] : null;
  if (!file) {
    return null;
  }

  const opts = options || {};
  const maxSize = typeof opts.maxSizeBytes === "number" ? opts.maxSizeBytes : (2 * 1024 * 1024);
  const shouldConvertToPng = opts.convertToPng === true || opts.convertPdfToPng === true;

  if (shouldConvertToPng) {
    const pngBlob = await convertDocumentToPng(file, maxSize);
    const dataUrl = await readBlobAsDataUrl(pngBlob);
    const pngName = createPngFileName(file, "dokument");
    return {
      name: pngName,
      type: "image/png",
      size: pngBlob.size,
      dataUrl: dataUrl,
      convertedToPng: true,
      convertedFromPdf: isPdfDocumentFile(file)
    };
  }

  const dataUrl = await fileToDataUrl(file, { maxSizeBytes: maxSize, autoResizeImages: true });
  return {
    name: file.name,
    type: file.type || "application/octet-stream",
    size: dataUrlSizeBytes(dataUrl) || file.size,
    dataUrl: dataUrl
  };
}

function loadStudents() {
  return readJson(STORAGE_KEYS.students, []).map(function(entry) {
    if (!entry || typeof entry !== "object") {
      return entry;
    }
    return {
      ...entry,
      apprenticeshipSearchStatus: normalizeStudentSearchStatus(entry.apprenticeshipSearchStatus),
      internshipSearchStatus: normalizeStudentSearchStatus(entry.internshipSearchStatus)
    };
  });
}

function saveStudents(list) {
  writeJson(STORAGE_KEYS.students, list);
  if (typeof verschiebeMatchesInMatchOrdner === 'function') {
    try { verschiebeMatchesInMatchOrdner(); } catch(e) { /* ignore */ }
  }
}

const STUDENT_SEARCH_STATUS_ACTIVE = "active";
const STUDENT_SEARCH_STATUS_PAUSED = "paused";

function normalizeStudentSearchStatus(value) {
  return String(value || "").trim().toLowerCase() === STUDENT_SEARCH_STATUS_PAUSED
    ? STUDENT_SEARCH_STATUS_PAUSED
    : STUDENT_SEARCH_STATUS_ACTIVE;
}

function getStudentApprenticeshipSearchStatus(student) {
  return normalizeStudentSearchStatus(student && student.apprenticeshipSearchStatus);
}

function getStudentInternshipSearchStatus(recordArg, authArg) {
  const record = recordArg && typeof recordArg === "object" ? recordArg : null;
  if (record && (record.searchStatus || record.internshipSearchStatus)) {
    return normalizeStudentSearchStatus(record.searchStatus || record.internshipSearchStatus);
  }

  const auth = authArg || getStoredStudentAuth();
  const mainStudent = auth ? findStudentByAuth(auth) : null;
  return normalizeStudentSearchStatus(mainStudent && mainStudent.internshipSearchStatus);
}

function isStudentApprenticeshipSearchActive(student) {
  return getStudentApprenticeshipSearchStatus(student) !== STUDENT_SEARCH_STATUS_PAUSED;
}

function isStudentInternshipSearchActive(recordArg, authArg) {
  return getStudentInternshipSearchStatus(recordArg, authArg) !== STUDENT_SEARCH_STATUS_PAUSED;
}

function isStudentSearchActiveForOffer(student, offer, authArg) {
  const isInternshipContext = !!((student && student.isInternship) || (offer && offer.isInternship));
  return isInternshipContext
    ? isStudentInternshipSearchActive(student, authArg)
    : isStudentApprenticeshipSearchActive(student);
}

function getStudentMatchingVisibilityStatus(student) {
  if (!student) {
    return "missing";
  }
  if (!student.verified) {
    return "pending";
  }
  if (!isStudentApprenticeshipSearchActive(student)) {
    return "paused";
  }
  return "active";
}

function getStudentMatchingVisibilityText(student) {
  const status = getStudentMatchingVisibilityStatus(student);
  if (status === "active") {
    return "Profil aktiv im Matching";
  }
  if (status === "paused") {
    return "Ausbildungsplatzsuche pausiert";
  }
  if (status === "pending") {
    return "Profil gespeichert, wartet auf Prüfung";
  }
  return "Unternehmen sehen zuerst nur dieses Kurzprofil. Vollständige Unterlagen bleiben bis zu deiner Freigabe geschützt.";
}

function updateStudentSearchPreferences(authArg, changesArg) {
  const auth = authArg || getStoredStudentAuth();
  const changes = changesArg && typeof changesArg === "object" ? changesArg : {};
  if (!auth) {
    return null;
  }

  const students = loadStudents();
  const studentIndex = students.findIndex(function(entry) {
    return !!entry && (
      entry.id === getActiveStudentId()
      || entry.userId === auth.id
      || normalizeText(entry.userEmail) === normalizeText(auth.email)
      || normalizeText(entry.email) === normalizeText(auth.email)
    );
  });

  const now = new Date().toISOString();
  let nextStudent = studentIndex !== -1 ? { ...students[studentIndex] } : null;
  let didChangeStudent = false;

  if (nextStudent && Object.prototype.hasOwnProperty.call(changes, "apprenticeshipSearchStatus")) {
    const nextStatus = normalizeStudentSearchStatus(changes.apprenticeshipSearchStatus);
    if (nextStudent.apprenticeshipSearchStatus !== nextStatus) {
      nextStudent.apprenticeshipSearchStatus = nextStatus;
      didChangeStudent = true;
    }
  }

  if (nextStudent && Object.prototype.hasOwnProperty.call(changes, "internshipSearchStatus")) {
    const nextStatus = normalizeStudentSearchStatus(changes.internshipSearchStatus);
    if (nextStudent.internshipSearchStatus !== nextStatus) {
      nextStudent.internshipSearchStatus = nextStatus;
      didChangeStudent = true;
    }
  }

  if (nextStudent && didChangeStudent) {
    nextStudent.updatedAt = now;
    students[studentIndex] = nextStudent;
    saveStudents(students);
  }

  let internshipStudent = auth ? findInternshipStudentByAuth(auth) : null;
  if (Object.prototype.hasOwnProperty.call(changes, "internshipSearchStatus")) {
    const nextInternshipStatus = normalizeStudentSearchStatus(changes.internshipSearchStatus);
    const records = loadInternshipStudents();
    let didChangeInternshipRecord = false;
    const nextRecords = records.map(function(entry) {
      if (!entry || typeof entry !== "object") {
        return entry;
      }
      const matchesAuth = entry.userId === auth.id
        || normalizeText(entry.userEmail) === normalizeText(auth.email)
        || normalizeText(entry.email) === normalizeText(auth.email);
      const matchesStudent = !!(nextStudent && (
        entry.baseStudentId === nextStudent.id
        || (nextStudent.profilCode && entry.profilCode === nextStudent.profilCode)
      ));
      if (!matchesAuth && !matchesStudent) {
        return entry;
      }
      if (normalizeStudentSearchStatus(entry.searchStatus) === nextInternshipStatus) {
        return entry;
      }
      didChangeInternshipRecord = true;
      return {
        ...entry,
        searchStatus: nextInternshipStatus,
        updatedAt: now
      };
    });
    if (didChangeInternshipRecord) {
      saveInternshipStudents(nextRecords);
      internshipStudent = findInternshipStudentByAuth(auth, nextRecords);
    } else {
      internshipStudent = findInternshipStudentByAuth(auth, records);
    }
  }

  return {
    student: nextStudent || (auth ? findStudentByAuth(auth) : null),
    internshipStudent: internshipStudent
  };
}

