function getNormalizedFirmBillingPlan(value) {
  const normalized = String(value || "").trim().toLowerCase();
  const aliased = FIRM_SUBSCRIPTION_PLAN_KEY_ALIASES[normalized] || normalized;
  return Object.prototype.hasOwnProperty.call(FIRM_SUBSCRIPTION_PLANS, aliased)
    ? aliased
    : DEFAULT_FIRM_BILLING_PLAN_KEY;
}

function getFirmBillingPlanDefinition(planLike) {
  if (planLike && typeof planLike === "object") {
    const keyFromObject = planLike.billingPlan || planLike.billingPlanKey || planLike.key;
    return FIRM_SUBSCRIPTION_PLANS[getNormalizedFirmBillingPlan(keyFromObject)];
  }
  return FIRM_SUBSCRIPTION_PLANS[getNormalizedFirmBillingPlan(planLike)];
}

function doesFirmPlanRequirePaymentApproval(planLike) {
  return false;
}

function doesFirmPlanChargeMonthlyBase(planLike) {
  return getFirmBillingPlanDefinition(planLike).monthlyPriceCents > 0;
}

function getFirmBillingPlanKey(offer) {
  return getFirmBillingPlanDefinition(offer).key;
}

function isFirmApprenticeshipMatchingEnabled(offer) {
  return getFirmBillingPlanDefinition(offer).apprenticeshipMatchesEnabled !== false;
}

function isFirmInternshipOnlyPlan(offer) {
  return getFirmBillingPlanKey(offer) === "internship";
}

function getFirmCalendarCapabilities(planLike) {
  const plan = getFirmBillingPlanDefinition(planLike);
  return {
    interviewIcsEnabled: plan.calendarInterviewIcsEnabled !== false,
    interviewExternalLinksEnabled: !!plan.calendarInterviewExternalLinksEnabled,
    interviewConversationActionsEnabled: !!plan.calendarInterviewConversationActionsEnabled,
    interviewOverviewEnabled: !!plan.calendarInterviewOverviewEnabled,
    internshipPlannerEnabled: !!plan.calendarInternshipPlannerEnabled,
    internshipIcsEnabled: !!plan.calendarInternshipIcsEnabled,
    internshipExternalLinksEnabled: !!plan.calendarInternshipExternalLinksEnabled,
    internshipOccupancyEnabled: !!plan.calendarInternshipOccupancyEnabled
  };
}

function buildFirmCalendarAccessSummary(planLike) {
  const capabilities = getFirmCalendarCapabilities(planLike);
  const items = [];
  if (capabilities.interviewIcsEnabled || capabilities.internshipIcsEnabled) {
    items.push("ICS-Exporte");
  }
  if (capabilities.interviewExternalLinksEnabled || capabilities.internshipExternalLinksEnabled) {
    items.push("Outlook- und Google-Links");
  }
  if (capabilities.interviewOverviewEnabled) {
    items.push("zentrale Terminübersicht");
  }
  if (capabilities.internshipOccupancyEnabled) {
    items.push("Belegungskalender");
  }
  if (!items.length) {
    return "Kalenderfunktionen werden erst mit einem Monatstarif freigeschaltet.";
  }
  return "Aktuell enthalten: " + items.join(", ") + ".";
}

function buildFirmCalendarUpgradeHint(featureKey, planLike) {
  const plan = getFirmBillingPlanDefinition(planLike);
  if (featureKey === "internship-planner") {
    return plan.key === "no_subscription"
      ? "Die Kalenderplanung ist ab dem Basic-Abo freigeschaltet."
      : "Diese Kalenderplanung ist im aktuellen Tarif nicht enthalten.";
  }
  if (featureKey === "interview-conversation") {
    if (plan.key === "basic") {
      return "Kalenderzugriff im Kontaktverlauf ist ab Basic + verfügbar.";
    }
    if (plan.key === "no_subscription") {
      return "Kalenderfunktionen starten ab Basic. Kalenderzugriff im Kontaktverlauf gibt es ab Basic +.";
    }
    return "Diese Kalenderfunktion ist im aktuellen Tarif nicht enthalten.";
  }
  if (featureKey === "interview-links" || featureKey === "internship-links") {
    if (plan.key === "basic") {
      return "Outlook- und Google-Kalenderlinks sind ab Basic + verfügbar.";
    }
    if (plan.key === "no_subscription") {
      return "Kalenderfunktionen starten ab Basic. Outlook- und Google-Links gibt es ab Basic +.";
    }
    return "Diese Kalenderfunktion ist im aktuellen Tarif nicht enthalten.";
  }
  if (featureKey === "interview-overview" || featureKey === "internship-occupancy") {
    if (plan.key === "no_subscription" || plan.key === "basic" || plan.key === "basic_plus") {
      return "Die zentrale Termin- und Belegungsübersicht ist ab Pro verfügbar.";
    }
    return "Diese Kalenderfunktion ist im aktuellen Tarif nicht enthalten.";
  }
  return plan.key === "no_subscription"
    ? "Kalenderfunktionen werden erst mit einem Monatstarif freigeschaltet."
    : "Diese Kalenderfunktion ist im aktuellen Tarif nicht enthalten.";
}

function getFirmBillingPlanMonthlyPriceLabel(planLike) {
  const plan = getFirmBillingPlanDefinition(planLike);
  if (!doesFirmPlanChargeMonthlyBase(plan)) {
    return "Keine Monatsgebühr";
  }
  return new Intl.NumberFormat("de-DE", {
    style: "currency",
    currency: "EUR"
  }).format(plan.monthlyPriceCents / 100) + " netto / Monat";
}

function getFirmBillingPlanRuleSummary(planLike) {
  return getFirmBillingPlanDefinition(planLike).releaseRuleLabel;
}

function getFirmBillingPlanSelectionCopy(planLike) {
  return getFirmBillingPlanDefinition(planLike).selectionCopy;
}

function getFirmBillingPlanAvailabilityCopy(planLike) {
  return getFirmBillingPlanDefinition(planLike).portalAvailabilityLabel;
}

function getFirmBillingDashboardPlanKeys() {
  return Object.keys(FIRM_SUBSCRIPTION_PLANS).filter(function(planKey) {
    return getFirmBillingPlanDefinition(planKey).showInBillingActions !== false;
  });
}

function normalizeFirmSelfServiceBillingPlan(value, fallbackValue) {
  const normalizedValue = getNormalizedFirmBillingPlan(value);
  if (FIRM_SELF_SERVICE_BILLING_PLAN_KEYS.includes(normalizedValue)) {
    return normalizedValue;
  }
  const normalizedFallback = getNormalizedFirmBillingPlan(fallbackValue || DEFAULT_FIRM_BILLING_PLAN_KEY);
  return FIRM_SELF_SERVICE_BILLING_PLAN_KEYS.includes(normalizedFallback)
    ? normalizedFallback
    : DEFAULT_FIRM_BILLING_PLAN_KEY;
}

function getFirmAdditionalRequestPriceLabel(planLike) {
  const plan = getFirmBillingPlanDefinition(planLike);
  if (Number.isFinite(plan.additionalReleasePriceCents)) {
    return formatEuroAmountFromCents(plan.additionalReleasePriceCents);
  }
  return String(plan.additionalRequestPriceLabel || FIRM_CONTACT_REQUEST_FEE_COPY.pricePendingLabel).trim();
}

function buildFirmContactRequestPricingSentence(planLike) {
  const plan = getFirmBillingPlanDefinition(planLike);
  const includedLimit = Math.max(0, Math.round(plan.includedReleasesPerMonth || 0));

  if (includedLimit <= 0) {
    if (Number.isFinite(plan.additionalReleasePriceCents)) {
      return "Im Tarif " + plan.label + " wird jede Anfrage mit " + getFirmAdditionalRequestPriceLabel(plan) + " in Ihrer Monatsabrechnung erfasst";
    }
    return "Die Preislogik im Tarif " + plan.label + " wird individuell mit Ihrem Betrieb abgestimmt";
  }

  if (Number.isFinite(plan.additionalReleasePriceCents)) {
    return "Im Tarif " + plan.label + " sind pro Monat " + includedLimit + " Anfragen inklusive. Ab der " + (includedLimit + 1) + ". Anfrage werden " + getFirmAdditionalRequestPriceLabel(plan) + " in Ihrer Monatsabrechnung erfasst";
  }

  return "Im Tarif " + plan.label + " sind pro Monat " + includedLimit + " Anfragen inklusive. Weitere Anfragen werden nach Rücksprache mit Ihrem Betrieb individuell abgerechnet";
}

function getFirmLegacyPlanActivationDate(offer) {
  return String(
    (offer && (
      offer.paymentApprovedAt
      || offer.planActivatedAt
      || offer.gespeichertAm
      || offer.createdAt
      || ""
    )) || ""
  ).trim();
}

function startOfLocalDay(value) {
  const date = value instanceof Date ? new Date(value.getTime()) : new Date(value || "");
  if (Number.isNaN(date.getTime())) {
    return null;
  }
  return new Date(date.getFullYear(), date.getMonth(), date.getDate());
}

function shiftLocalDateByDays(value, dayDelta) {
  const date = startOfLocalDay(value);
  if (!date) {
    return null;
  }
  return new Date(date.getFullYear(), date.getMonth(), date.getDate() + Math.round(dayDelta || 0));
}

function getDiffInCalendarDays(startDate, endDate) {
  if (!(startDate instanceof Date) || !(endDate instanceof Date)) {
    return 0;
  }
  const diffMs = endDate.getTime() - startDate.getTime();
  return diffMs > 0 ? Math.round(diffMs / 86400000) : 0;
}

function compareBillingMonthKeys(left, right) {
  const leftKey = String(left || "").trim();
  const rightKey = String(right || "").trim();
  const leftValid = /^\d{4}-\d{2}$/.test(leftKey);
  const rightValid = /^\d{4}-\d{2}$/.test(rightKey);
  if (!leftValid && !rightValid) return 0;
  if (!leftValid) return -1;
  if (!rightValid) return 1;
  return leftKey.localeCompare(rightKey, "de");
}

function shiftBillingMonthKey(monthKey, monthDelta) {
  const date = getBillingMonthDate(monthKey);
  if (!date || !Number.isFinite(monthDelta)) {
    return "";
  }
  return formatBillingMonthKey(new Date(date.getFullYear(), date.getMonth() + Math.round(monthDelta), 1));
}

function getBillingMonthStartDate(monthKey) {
  return getBillingMonthDate(monthKey);
}

function getBillingMonthEndExclusiveDate(monthKey) {
  const date = getBillingMonthDate(monthKey);
  if (!date) {
    return null;
  }
  return new Date(date.getFullYear(), date.getMonth() + 1, 1);
}

function getBillingMonthLastDate(monthKey) {
  const endExclusive = getBillingMonthEndExclusiveDate(monthKey);
  if (!endExclusive) {
    return null;
  }
  return new Date(endExclusive.getFullYear(), endExclusive.getMonth(), 0);
}

function buildFirmPlanHistoryEntry(planLike, startAtValue, extra) {
  const startDate = startOfLocalDay(startAtValue) || startOfLocalDay(new Date());
  const config = extra || {};
  return {
    planKey: getNormalizedFirmBillingPlan(planLike),
    startAt: startDate.toISOString(),
    changeKind: String(config.changeKind || "plan-change").trim() || "plan-change",
    requestedAt: String(config.requestedAt || "").trim(),
    changedAt: String(config.changedAt || startDate.toISOString()).trim()
  };
}

function normalizeFirmPlanHistoryEntries(offer) {
  const rawEntries = Array.isArray(offer && offer.billingPlanHistory)
    ? offer.billingPlanHistory
    : [];
  const entries = rawEntries.map(function(entry) {
    if (!entry || typeof entry !== "object") {
      return null;
    }
    const planKey = getNormalizedFirmBillingPlan(entry.planKey || entry.billingPlan || entry.key);
    const startDate = startOfLocalDay(entry.startAt || entry.effectiveAt || entry.changedAt);
    if (!startDate) {
      return null;
    }
    return {
      planKey: planKey,
      startAt: startDate.toISOString(),
      changeKind: String(entry.changeKind || "plan-change").trim() || "plan-change",
      requestedAt: String(entry.requestedAt || "").trim(),
      changedAt: String(entry.changedAt || startDate.toISOString()).trim()
    };
  }).filter(Boolean).sort(function(left, right) {
    return getFirmBillingEntrySortValue(left.startAt) - getFirmBillingEntrySortValue(right.startAt);
  });

  if (!entries.length && offer && isFirmAccountReleased(offer)) {
    const fallbackStartAt = getFirmLegacyPlanActivationDate(offer) || new Date().toISOString();
    entries.push(buildFirmPlanHistoryEntry(getFirmBillingPlanKey(offer), fallbackStartAt, {
      changeKind: "legacy-plan"
    }));
  }

  return entries.reduce(function(list, entry) {
    const previousEntry = list[list.length - 1];
    if (previousEntry && previousEntry.planKey === entry.planKey && previousEntry.startAt === entry.startAt) {
      return list;
    }
    list.push(entry);
    return list;
  }, []);
}

function getFirmPlanHistory(offer) {
  return normalizeFirmPlanHistoryEntries(offer);
}

function getFirmActivePlanHistoryEntry(offer, atValue) {
  const history = getFirmPlanHistory(offer);
  const referenceDate = startOfLocalDay(atValue || new Date()) || startOfLocalDay(new Date());

  if (!history.length) {
    if (!offer) {
      return null;
    }
    const fallbackStartAt = getFirmLegacyPlanActivationDate(offer)
      || offer.planActivatedAt
      || offer.gespeichertAm
      || offer.createdAt
      || new Date().toISOString();
    return buildFirmPlanHistoryEntry(getFirmBillingPlanKey(offer), fallbackStartAt, {
      changeKind: "current-plan"
    });
  }

  let activeEntry = history[0];
  history.forEach(function(entry) {
    const entryStart = startOfLocalDay(entry.startAt);
    if (entryStart && entryStart.getTime() <= referenceDate.getTime()) {
      activeEntry = entry;
    }
  });
  return activeEntry;
}

function getFirmPlanHistorySegmentKey(entry) {
  if (!entry) {
    return "";
  }
  return String(entry.planKey || "") + "|" + String(entry.startAt || "").trim();
}

function getFirmPendingPlanChange(offer) {
  const rawChange = offer && offer.pendingBillingPlanChange;
  if (!rawChange || typeof rawChange !== "object") {
    return null;
  }

  const effectiveMonthKey = String(rawChange.effectiveMonthKey || formatBillingMonthKey(rawChange.effectiveAt)).trim();
  const effectiveDate = startOfLocalDay(rawChange.effectiveAt || getBillingMonthStartDate(effectiveMonthKey));
  if (!effectiveDate) {
    return null;
  }

  const contractEndMonthKey = String(
    rawChange.contractEndMonthKey
    || formatBillingMonthKey(rawChange.contractEndAt)
    || shiftBillingMonthKey(effectiveMonthKey || formatBillingMonthKey(effectiveDate), -1)
    || ""
  ).trim();
  const contractEndDate = startOfLocalDay(rawChange.contractEndAt || getBillingMonthLastDate(contractEndMonthKey));

  return {
    planKey: getNormalizedFirmBillingPlan(rawChange.planKey || rawChange.billingPlan || rawChange.key),
    effectiveMonthKey: effectiveMonthKey || formatBillingMonthKey(effectiveDate),
    effectiveAt: effectiveDate.toISOString(),
    contractEndMonthKey: contractEndMonthKey,
    contractEndAt: contractEndDate ? contractEndDate.toISOString() : "",
    requestedAt: String(rawChange.requestedAt || "").trim(),
    changeKind: String(rawChange.changeKind || "scheduled-plan-change").trim() || "scheduled-plan-change"
  };
}

function getFirmCancellationSchedule(offer, referenceDateValue) {
  const referenceDate = startOfLocalDay(referenceDateValue || new Date()) || startOfLocalDay(new Date());
  const contractState = getFirmSubscriptionContractState(offer, referenceDate);
  const minimumEndDate = startOfLocalDay(contractState.minimumEndsAt || contractState.contractEndAt || referenceDate);
  const minimumEffectiveDate = minimumEndDate ? shiftLocalDateByDays(minimumEndDate, 1) : shiftLocalDateByDays(referenceDate, 1);
  const noticeEffectiveDate = shiftLocalDateByDays(referenceDate, FIRM_SUBSCRIPTION_CANCELLATION_NOTICE_DAYS);
  const effectiveDate = new Date(Math.max(
    minimumEffectiveDate ? minimumEffectiveDate.getTime() : 0,
    noticeEffectiveDate ? noticeEffectiveDate.getTime() : 0
  ));
  const contractEndDate = shiftLocalDateByDays(effectiveDate, -1);

  return {
    requestedAt: referenceDate ? referenceDate.toISOString() : "",
    noticeDays: FIRM_SUBSCRIPTION_CANCELLATION_NOTICE_DAYS,
    effectiveAt: effectiveDate.toISOString(),
    effectiveMonthKey: formatBillingMonthKey(effectiveDate),
    contractEndAt: contractEndDate ? contractEndDate.toISOString() : "",
    contractEndMonthKey: contractEndDate ? formatBillingMonthKey(contractEndDate) : "",
    minimumEndAt: minimumEndDate ? minimumEndDate.toISOString() : "",
    isFinalMonthProrated: !!(contractEndDate && effectiveDate && formatBillingMonthKey(contractEndDate) === formatBillingMonthKey(effectiveDate)),
    isMinimumTermBlocking: !!(minimumEffectiveDate && noticeEffectiveDate && minimumEffectiveDate.getTime() >= noticeEffectiveDate.getTime())
  };
}

function buildFirmCancellationPolicyHint(offer, referenceDateValue) {
  const resolvedOffer = offer || null;
  const activePlan = getFirmBillingPlanDefinition(resolvedOffer);
  if (!doesFirmPlanChargeMonthlyBase(activePlan)) {
    return "";
  }
  const contractState = getFirmSubscriptionContractState(resolvedOffer, referenceDateValue);
  const cancellationSchedule = getFirmCancellationSchedule(resolvedOffer, referenceDateValue);
  const minimumUntilLabel = contractState.minimumUntilMonthKey
    ? formatBillingMonthLabel(contractState.minimumUntilMonthKey)
    : "";
  const contractEndLabel = formatFirmBillingActionDate(cancellationSchedule.contractEndAt);
  const minimumPart = contractState.minimumTermActive && contractState.minimumUntilMonthKey
    ? ("Mindestlaufzeit bis Ende " + minimumUntilLabel + ". ")
    : "";
  const cancellationPart = contractEndLabel
    ? ("Kündigungen werden mit " + cancellationSchedule.noticeDays + " Tagen Frist zum " + contractEndLabel + " wirksam.")
    : ("Kündigungen werden mit " + cancellationSchedule.noticeDays + " Tagen Frist wirksam.");
  return minimumPart + cancellationPart + " Die Monatsgebühr wird bis zu diesem Datum anteilig berechnet.";
}

function buildFirmPendingPlanChangeDetail(pendingChange) {
  if (!pendingChange) {
    return "";
  }
  const baseLabel = buildFirmPendingPlanChangeLabel(pendingChange);
  const nextPlan = getFirmBillingPlanDefinition(pendingChange.planKey);
  if (String(pendingChange.changeKind || "").trim() === "cancellation" || nextPlan.key === "no_subscription") {
    return baseLabel + ". Die Monatsgebühr wird bis zu diesem Datum anteilig berechnet.";
  }
  return baseLabel;
}

function getFirmPlanSegmentsForMonth(offer, monthKey) {
  const monthStart = getBillingMonthStartDate(monthKey);
  const monthEndExclusive = getBillingMonthEndExclusiveDate(monthKey);
  if (!offer || !monthStart || !monthEndExclusive) {
    return [];
  }

  const history = getFirmPlanHistory(offer);
  const workingHistory = history.length ? history : [getFirmActivePlanHistoryEntry(offer, monthStart)].filter(Boolean);
  const daysInMonth = getDiffInCalendarDays(monthStart, monthEndExclusive);

  return workingHistory.reduce(function(list, entry, index) {
    const entryStart = startOfLocalDay(entry.startAt);
    const nextEntry = workingHistory[index + 1] || null;
    const nextStart = startOfLocalDay(nextEntry && nextEntry.startAt);
    if (!entryStart) {
      return list;
    }

    const segmentStart = new Date(Math.max(entryStart.getTime(), monthStart.getTime()));
    const segmentEndExclusive = new Date(Math.min((nextStart || monthEndExclusive).getTime(), monthEndExclusive.getTime()));
    if (segmentEndExclusive.getTime() <= segmentStart.getTime()) {
      return list;
    }

    const plan = getFirmBillingPlanDefinition(entry.planKey);
    const activeDays = getDiffInCalendarDays(segmentStart, segmentEndExclusive);
    const isProrated = !(segmentStart.getTime() === monthStart.getTime() && segmentEndExclusive.getTime() === monthEndExclusive.getTime());
    const proratedIncludedLimit = (plan.includedReleasesPerMonth || 0) > 0
      ? Math.max(0, Math.ceil((plan.includedReleasesPerMonth * activeDays) / Math.max(1, daysInMonth)))
      : 0;

    list.push({
      segmentKey: getFirmPlanHistorySegmentKey(entry),
      planKey: plan.key,
      plan: plan,
      monthKey: monthKey,
      historyEntry: entry,
      segmentStart: segmentStart.toISOString(),
      segmentEndExclusive: segmentEndExclusive.toISOString(),
      activeDays: activeDays,
      daysInMonth: daysInMonth,
      isProrated: isProrated,
      amountCents: doesFirmPlanChargeMonthlyBase(plan)
        ? Math.max(0, Math.round((plan.monthlyPriceCents * activeDays) / Math.max(1, daysInMonth)))
        : 0,
      proratedIncludedLimit: proratedIncludedLimit
    });
    return list;
  }, []);
}

function getFirmPlanSegmentForDate(offer, dateValue) {
  const referenceDate = startOfLocalDay(dateValue || new Date());
  if (!referenceDate) {
    return null;
  }

  const monthKey = formatBillingMonthKey(referenceDate);
  return getFirmPlanSegmentsForMonth(offer, monthKey).find(function(segment) {
    const segmentStart = startOfLocalDay(segment.segmentStart);
    const segmentEndExclusive = startOfLocalDay(segment.segmentEndExclusive);
    return segmentStart
      && segmentEndExclusive
      && segmentStart.getTime() <= referenceDate.getTime()
      && referenceDate.getTime() < segmentEndExclusive.getTime();
  }) || null;
}

function getFirmSubscriptionContractState(offer, referenceDateValue) {
  const referenceDate = startOfLocalDay(referenceDateValue || new Date()) || startOfLocalDay(new Date());
  const currentMonthKey = formatBillingMonthKey(referenceDate);
  const activeEntry = getFirmActivePlanHistoryEntry(offer, referenceDate);
  const activePlan = getFirmBillingPlanDefinition(activeEntry ? activeEntry.planKey : offer);
  const pendingChange = getFirmPendingPlanChange(offer);
  const hasMonthlySubscription = doesFirmPlanChargeMonthlyBase(activePlan);
  const commitmentStartMonthKey = hasMonthlySubscription
    ? String((offer && offer.subscriptionCommitmentStartMonthKey) || formatBillingMonthKey(activeEntry ? activeEntry.startAt : referenceDate)).trim()
    : "";
  const minimumUntilMonthKey = hasMonthlySubscription
    ? String((offer && offer.subscriptionMinimumUntilMonthKey) || shiftBillingMonthKey(commitmentStartMonthKey, FIRM_SUBSCRIPTION_MINIMUM_MONTHS - 1)).trim()
    : "";
  const minimumEndsAt = minimumUntilMonthKey ? getBillingMonthLastDate(minimumUntilMonthKey) : null;
  const contractEndMonthKey = hasMonthlySubscription
    ? (compareBillingMonthKeys(currentMonthKey, minimumUntilMonthKey) > 0 ? currentMonthKey : minimumUntilMonthKey)
    : currentMonthKey;
  const contractEndAt = hasMonthlySubscription ? getBillingMonthLastDate(contractEndMonthKey) : null;
  const nextEligibleChangeMonthKey = hasMonthlySubscription
    ? shiftBillingMonthKey(contractEndMonthKey, 1)
    : shiftBillingMonthKey(currentMonthKey, 1);

  return {
    currentMonthKey: currentMonthKey,
    activeEntry: activeEntry,
    activePlan: activePlan,
    pendingChange: pendingChange,
    hasMonthlySubscription: hasMonthlySubscription,
    commitmentStartMonthKey: commitmentStartMonthKey,
    minimumUntilMonthKey: minimumUntilMonthKey,
    minimumEndsAt: minimumEndsAt ? minimumEndsAt.toISOString() : "",
    contractEndMonthKey: contractEndMonthKey,
    contractEndAt: contractEndAt ? contractEndAt.toISOString() : "",
    minimumTermActive: !!(hasMonthlySubscription && compareBillingMonthKeys(currentMonthKey, minimumUntilMonthKey) <= 0),
    nextEligibleChangeMonthKey: nextEligibleChangeMonthKey,
    nextEligibleChangeAt: nextEligibleChangeMonthKey
      ? String((getBillingMonthStartDate(nextEligibleChangeMonthKey) || new Date()).toISOString()).trim()
      : ""
  };
}

function getFirmPlanSelectionDraftValue(offer) {
  const pendingChange = getFirmPendingPlanChange(offer);
  return pendingChange ? pendingChange.planKey : getFirmBillingPlanKey(offer);
}

function getFirmPlanChangeIntent(offer, selectedPlanKey, referenceDateValue) {
  const contractState = getFirmSubscriptionContractState(offer, referenceDateValue);
  const currentPlan = contractState.activePlan || getFirmBillingPlanDefinition(offer);
  const nextPlan = getFirmBillingPlanDefinition(selectedPlanKey);

  if (currentPlan.key === nextPlan.key) {
    return {
      mode: "current",
      changeKind: "none",
      currentPlan: currentPlan,
      nextPlan: nextPlan,
      contractEndAt: contractState.contractEndAt,
      contractEndMonthKey: contractState.contractEndMonthKey,
      effectiveAt: "",
      effectiveMonthKey: "",
      resetsMinimum: false
    };
  }

  if (!offer || !isFirmAccountReleased(offer)) {
    return {
      mode: "immediate",
      changeKind: "pre-release",
      currentPlan: currentPlan,
      nextPlan: nextPlan,
      contractEndAt: "",
      contractEndMonthKey: "",
      effectiveAt: new Date().toISOString(),
      effectiveMonthKey: formatBillingMonthKey(new Date()),
      resetsMinimum: doesFirmPlanChargeMonthlyBase(nextPlan)
    };
  }

  if (!doesFirmPlanChargeMonthlyBase(currentPlan)) {
    return {
      mode: "immediate",
      changeKind: doesFirmPlanChargeMonthlyBase(nextPlan) ? "subscription-start" : "plan-change",
      currentPlan: currentPlan,
      nextPlan: nextPlan,
      contractEndAt: "",
      contractEndMonthKey: "",
      effectiveAt: new Date().toISOString(),
      effectiveMonthKey: formatBillingMonthKey(new Date()),
      resetsMinimum: doesFirmPlanChargeMonthlyBase(nextPlan)
    };
  }

  if (doesFirmPlanChargeMonthlyBase(nextPlan) && nextPlan.monthlyPriceCents > currentPlan.monthlyPriceCents) {
    return {
      mode: "immediate",
      changeKind: "upgrade",
      currentPlan: currentPlan,
      nextPlan: nextPlan,
      contractEndAt: "",
      contractEndMonthKey: "",
      effectiveAt: new Date().toISOString(),
      effectiveMonthKey: formatBillingMonthKey(new Date()),
      resetsMinimum: true
    };
  }

  if (!doesFirmPlanChargeMonthlyBase(nextPlan)) {
    const cancellationSchedule = getFirmCancellationSchedule(offer, referenceDateValue);
    return {
      mode: "scheduled",
      changeKind: "cancellation",
      currentPlan: currentPlan,
      nextPlan: nextPlan,
      contractEndAt: cancellationSchedule.contractEndAt,
      contractEndMonthKey: cancellationSchedule.contractEndMonthKey,
      effectiveAt: cancellationSchedule.effectiveAt,
      effectiveMonthKey: cancellationSchedule.effectiveMonthKey,
      resetsMinimum: false,
      noticeDays: cancellationSchedule.noticeDays,
      isFinalMonthProrated: cancellationSchedule.isFinalMonthProrated
    };
  }

  return {
    mode: "scheduled",
    changeKind: "downgrade",
    currentPlan: currentPlan,
    nextPlan: nextPlan,
    contractEndAt: contractState.contractEndAt,
    contractEndMonthKey: contractState.contractEndMonthKey,
    effectiveAt: contractState.nextEligibleChangeAt,
    effectiveMonthKey: contractState.nextEligibleChangeMonthKey,
    resetsMinimum: doesFirmPlanChargeMonthlyBase(nextPlan)
  };
}

function buildFirmBillingPlanEditorHint(offer) {
  if (!offer) {
    return "Der gewählte Tarif steuert Monatsgrundpreis, Anfragekontingent, Kalenderfunktionen und welche Matchbereiche für Ihren Betrieb sichtbar sind. Upgrades sind jederzeit möglich. Downgrades greifen zum Vertragsende. Kündigungen laufen mit 14 Tagen Frist und werden bis zum Wirksamkeitsdatum anteilig berechnet. Vor dem Abschluss eines Monatstarifs bestätigen Sie Preis und AGB in einem separaten Schritt.";
  }

  const contractState = getFirmSubscriptionContractState(offer);
  const pendingChange = contractState.pendingChange;
  const activePlanLabel = contractState.activePlan ? contractState.activePlan.label : getFirmBillingPlanDefinition(offer).label;
  const cancellationHint = buildFirmCancellationPolicyHint(offer);

  if (pendingChange) {
    return "Aktuell aktiv: " + activePlanLabel + ". Bereits vorgemerkt: " + buildFirmPendingPlanChangeDetail(pendingChange) + " Upgrades bleiben jederzeit möglich, Downgrades greifen nur zum Vertragsende. " + cancellationHint;
  }

  if (contractState.hasMonthlySubscription && contractState.minimumTermActive && contractState.minimumUntilMonthKey) {
    return "Aktuell aktiv: " + activePlanLabel + ". Mindestlaufzeit bis Ende " + formatBillingMonthLabel(contractState.minimumUntilMonthKey) + ", danach automatische Monatsverlängerung. Upgrades werden sofort aktiv und starten die 3-monatige Mindestlaufzeit neu. Downgrades greifen nur zum Vertragsende. " + cancellationHint;
  }

  return "Aktuell aktiv: " + activePlanLabel + ". Der gewählte Tarif steuert Monatsgrundpreis, Anfragekontingent, Kalenderfunktionen und sichtbare Matchbereiche. Upgrades sind jederzeit möglich. Downgrades greifen nur zum Vertragsende. " + cancellationHint;
}

function buildFirmPaidPlanConfirmationContext(options) {
  const config = options || {};
  const offer = config.offer || null;
  const nextPlan = getFirmBillingPlanDefinition(config.selectedPlanKey || DEFAULT_FIRM_BILLING_PLAN_KEY);
  const referenceDate = config.referenceDateValue ? new Date(config.referenceDateValue) : new Date();
  const planIntent = config.planIntent || (offer
    ? getFirmPlanChangeIntent(offer, nextPlan.key, referenceDate)
    : {
        mode: "immediate",
        changeKind: doesFirmPlanChargeMonthlyBase(nextPlan) ? "subscription-start" : "plan-change",
        currentPlan: null,
        nextPlan: nextPlan,
        contractEndAt: "",
        contractEndMonthKey: "",
        effectiveAt: referenceDate.toISOString(),
        effectiveMonthKey: formatBillingMonthKey(referenceDate),
        resetsMinimum: doesFirmPlanChargeMonthlyBase(nextPlan)
      });
  const currentPlan = planIntent && planIntent.currentPlan && planIntent.currentPlan.key
    ? planIntent.currentPlan
    : null;
  const requiresConfirmation = doesFirmPlanChargeMonthlyBase(nextPlan) && planIntent.mode !== "current";
  const currentPlanUntilLabel = planIntent && planIntent.contractEndAt
    ? formatFirmBillingActionDate(planIntent.contractEndAt)
    : "";
  const effectiveLabel = !offer || !isFirmAccountReleased(offer)
    ? "Mit Freischaltung Ihres Zugangs"
    : (planIntent.mode === "scheduled" && planIntent.effectiveAt
      ? formatFirmBillingActionDate(planIntent.effectiveAt)
      : "Sofort nach Bestätigung");
  const minimumCommitmentCents = Math.max(0, Math.round(nextPlan.monthlyPriceCents || 0)) * FIRM_SUBSCRIPTION_MINIMUM_MONTHS;
  const rows = [];

  if (currentPlan && currentPlan.key !== nextPlan.key) {
    rows.push({
      label: "Aktuell",
      value: currentPlan.label
    });
  }

  rows.push(
    {
      label: "Tarif",
      value: nextPlan.label
    },
    {
      label: "Leistungsumfang",
      value: getFirmBillingPlanAvailabilityCopy(nextPlan)
    },
    {
      label: "Tarifregel",
      value: getFirmBillingPlanRuleSummary(nextPlan)
    },
    {
      label: "Mindestlaufzeit",
      value: FIRM_SUBSCRIPTION_MINIMUM_MONTHS + " Monate"
    },
    {
      label: "Wirksam ab",
      value: effectiveLabel
    },
    {
      label: "Abrechnung",
      value: "Jeweils im Folgemonat fällig"
    },
    {
      label: "Kündigung",
      value: "Mit " + FIRM_SUBSCRIPTION_CANCELLATION_NOTICE_DAYS + " Tagen Frist, anteilige Berechnung bis zum Wirksamkeitsdatum"
    }
  );

  let title = "Kostenpflichtige Bestellung bestätigen";
  let intro = "Bitte prüfen Sie die Preis- und Vertragsübersicht für das " + nextPlan.label + "-Abo. Mit dem Abschluss beauftragen Sie eine kostenpflichtige Leistung.";

  if (currentPlan && planIntent.changeKind === "upgrade") {
    title = "Kostenpflichtiges Upgrade bestätigen";
    intro = "Bitte prüfen Sie die Preis- und Vertragsübersicht für Ihr Upgrade auf " + nextPlan.label + ". Der neue Tarif gilt sofort nach Bestätigung. Mit dem Abschluss beauftragen Sie eine kostenpflichtige Leistung.";
  } else if (currentPlan && planIntent.mode === "scheduled") {
    title = "Kostenpflichtige Tarifänderung bestätigen";
    intro = "Bitte prüfen Sie die Preis- und Vertragsübersicht für Ihren Wechsel auf " + nextPlan.label + "."
      + (currentPlanUntilLabel ? (" Bis zum " + currentPlanUntilLabel + " bleibt " + currentPlan.label + " aktiv.") : "")
      + " Mit dem Abschluss beauftragen Sie eine kostenpflichtige Leistung.";
  } else if (currentPlan && planIntent.mode === "immediate") {
    title = "Kostenpflichtigen Tarif bestätigen";
    intro = "Bitte prüfen Sie die Preis- und Vertragsübersicht für Ihren Wechsel auf " + nextPlan.label + ". Der neue Tarif gilt sofort nach Bestätigung. Mit dem Abschluss beauftragen Sie eine kostenpflichtige Leistung.";
  } else if (!offer || !isFirmAccountReleased(offer)) {
    intro = "Bitte prüfen Sie die Preis- und Vertragsübersicht für das " + nextPlan.label + "-Abo. Die Mindestlaufzeit startet mit der Freischaltung Ihres Zugangs. Mit dem Abschluss beauftragen Sie eine kostenpflichtige Leistung.";
  }

  return {
    offer: offer,
    nextPlan: nextPlan,
    planIntent: planIntent,
    requiresConfirmation: requiresConfirmation,
    title: title,
    intro: intro,
    rows: rows,
    priceLabel: getFirmBillingPlanMonthlyPriceLabel(nextPlan),
    minimumCommitmentLabel: formatEuroAmountFromCents(minimumCommitmentCents) + " netto",
    pricingNote: buildFirmContactRequestPricingSentence(nextPlan),
    triggerElement: config.triggerElement || null
  };
}

function openFirmPaidPlanConfirmationDialog(context) {
  return new Promise(function(resolve) {
    const previousActiveElement = context && context.triggerElement && typeof context.triggerElement.focus === "function"
      ? context.triggerElement
      : document.activeElement;
    const rowsHtml = (context.rows || []).map(function(row) {
      return ""
        + "<div class='firm-paid-plan-dialog__fact'>"
        + "<dt>" + escapeHtml(row.label) + "</dt>"
        + "<dd>" + escapeHtml(row.value) + "</dd>"
        + "</div>";
    }).join("");
    const pricingNote = String((context && context.pricingNote) || "").trim();
    const overlay = document.createElement("div");
    overlay.className = "firm-paid-plan-dialog";
    overlay.innerHTML = ""
      + "<div class='firm-paid-plan-dialog__panel panel' role='dialog' aria-modal='true' aria-labelledby='firmPaidPlanDialogTitle'>"
      + "<p class='firm-paid-plan-dialog__eyebrow'>Kostenpflichtige Bestellung</p>"
      + "<h3 id='firmPaidPlanDialogTitle' class='firm-paid-plan-dialog__title'>" + escapeHtml(context.title) + "</h3>"
      + "<p class='firm-paid-plan-dialog__copy'>" + escapeHtml(context.intro) + "</p>"
      + "<section class='firm-paid-plan-dialog__document' aria-labelledby='firmPaidPlanDocumentTitle'>"
      + "<div class='firm-paid-plan-dialog__document-head'>"
      + "<p id='firmPaidPlanDocumentTitle' class='firm-paid-plan-dialog__document-title'>Vertrags- und Preisübersicht</p>"
      + "<span class='firm-paid-plan-dialog__document-badge'>" + escapeHtml(context.nextPlan.label) + "</span>"
      + "</div>"
      + "<div class='firm-paid-plan-dialog__price-card'>"
      + "<span class='firm-paid-plan-dialog__price-label'>Monatspreis</span>"
      + "<strong class='firm-paid-plan-dialog__price-value'>" + escapeHtml(context.priceLabel) + "</strong>"
      + "<span class='firm-paid-plan-dialog__price-meta'>Mindestbetrag für " + FIRM_SUBSCRIPTION_MINIMUM_MONTHS + " Monate: " + escapeHtml(context.minimumCommitmentLabel) + "</span>"
      + "</div>"
      + "<dl class='firm-paid-plan-dialog__facts'>" + rowsHtml + "</dl>"
      + (pricingNote
        ? ("<p class='firm-paid-plan-dialog__note'>" + escapeHtml(pricingNote + ".") + "</p>")
        : "")
      + "</section>"
      + "<label class='firma-checkbox-row firm-paid-plan-dialog__checkbox' for='firmPaidPlanTermsCheckbox'>"
      + "<input type='checkbox' id='firmPaidPlanTermsCheckbox'>"
      + "<span>Ich akzeptiere die <a href='nutzungsbedingungen.html' target='_blank' rel='noopener noreferrer'>AGB</a> und den oben ausgewiesenen Preis.</span>"
      + "</label>"
      + "<p class='firm-paid-plan-dialog__status' aria-live='polite'></p>"
      + "<div class='firm-paid-plan-dialog__actions'>"
      + "<button type='button' class='btn ghost small' data-action='cancel'>Abbrechen</button>"
      + "<button type='button' class='btn primary small' data-action='submit' disabled>Kostenpflichtig bestellen</button>"
      + "</div>"
      + "</div>";

    const checkbox = overlay.querySelector("#firmPaidPlanTermsCheckbox");
    const status = overlay.querySelector(".firm-paid-plan-dialog__status");
    const cancelBtn = overlay.querySelector("[data-action='cancel']");
    const submitBtn = overlay.querySelector("[data-action='submit']");

    function closeDialog(result) {
      document.removeEventListener("keydown", handleKeyDown);
      document.body.classList.remove("firm-paid-plan-dialog-open");
      overlay.remove();
      if (previousActiveElement && typeof previousActiveElement.focus === "function") {
        previousActiveElement.focus();
      }
      resolve(result);
    }

    function buildDialogResult(confirmed) {
      return {
        required: true,
        confirmed: confirmed,
        planKey: context.nextPlan.key,
        acceptedAt: confirmed ? new Date().toISOString() : "",
        priceCents: Number(context.nextPlan.monthlyPriceCents || 0)
      };
    }

    function handleKeyDown(event) {
      if (event.key === "Escape") {
        event.preventDefault();
        closeDialog(buildDialogResult(false));
      }
    }

    if (checkbox instanceof HTMLInputElement && submitBtn instanceof HTMLButtonElement) {
      checkbox.addEventListener("change", function() {
        submitBtn.disabled = !checkbox.checked;
        if (status) {
          status.textContent = checkbox.checked
            ? ""
            : "Bitte bestätigen Sie AGB und Preis vor dem Abschluss.";
        }
      });
    }

    if (cancelBtn instanceof HTMLButtonElement) {
      cancelBtn.addEventListener("click", function() {
        closeDialog(buildDialogResult(false));
      });
    }

    if (submitBtn instanceof HTMLButtonElement) {
      submitBtn.addEventListener("click", function() {
        if (!(checkbox instanceof HTMLInputElement) || !checkbox.checked) {
          if (status) {
            status.textContent = "Bitte bestätigen Sie AGB und Preis vor dem Abschluss.";
          }
          return;
        }
        closeDialog(buildDialogResult(true));
      });
    }

    overlay.addEventListener("click", function(event) {
      if (event.target === overlay) {
        closeDialog(buildDialogResult(false));
      }
    });

    document.addEventListener("keydown", handleKeyDown);
    document.body.classList.add("firm-paid-plan-dialog-open");
    document.body.appendChild(overlay);
    if (checkbox instanceof HTMLInputElement) {
      checkbox.focus();
    }
  });
}

function requestFirmPaidPlanOrderConfirmation(options) {
  const context = buildFirmPaidPlanConfirmationContext(options);
  if (!context.requiresConfirmation) {
    return Promise.resolve({
      required: false,
      confirmed: true,
      planKey: context.nextPlan.key,
      acceptedAt: "",
      priceCents: Number(context.nextPlan.monthlyPriceCents || 0)
    });
  }
  return openFirmPaidPlanConfirmationDialog(context);
}

function getFirmSubscriptionActivationDate(offer) {
  if (!offer || !isFirmDocumentsVerified(offer)) {
    return "";
  }

  const activeEntry = getFirmActivePlanHistoryEntry(offer, new Date());
  return String(
    (activeEntry && activeEntry.startAt)
    || getFirmLegacyPlanActivationDate(offer)
    || ""
  ).trim();
}

function loadOffers() {
  const offers = readJson(STORAGE_KEYS.offers, []);
  let didChange = false;
  const today = startOfLocalDay(new Date()) || startOfLocalDay(new Date());

  offers.forEach((offer) => {
    if (!offer || typeof offer !== "object") return;
    const normalizedBillingPlan = getNormalizedFirmBillingPlan(offer.billingPlan);
    if (offer.billingPlan !== normalizedBillingPlan) {
      offer.billingPlan = normalizedBillingPlan;
      didChange = true;
    }
    if (typeof offer.verified !== "boolean") {
      offer.verified = false;
      didChange = true;
    }
    if (typeof offer.paymentApproved !== "boolean") {
      offer.paymentApproved = !!offer.verified;
      didChange = true;
    }
    if (offer.paymentApproved !== !!offer.verified) {
      offer.paymentApproved = !!offer.verified;
      didChange = true;
    }
    const fallbackPlanActivationDate = String(offer.planActivatedAt || offer.gespeichertAm || offer.createdAt || "").trim();
    if (!offer.planActivatedAt && fallbackPlanActivationDate) {
      offer.planActivatedAt = fallbackPlanActivationDate;
      didChange = true;
    }
    if (offer.paymentApproved) {
      const fallbackPaymentApprovedAt = String(offer.paymentApprovedAt || offer.planActivatedAt || offer.gespeichertAm || offer.createdAt || new Date().toISOString()).trim();
      if (!offer.paymentApprovedAt && fallbackPaymentApprovedAt) {
        offer.paymentApprovedAt = fallbackPaymentApprovedAt;
        didChange = true;
      }
    }

    const normalizedPendingChange = getFirmPendingPlanChange(offer);
    if (normalizedPendingChange) {
      const pendingEffectiveDate = startOfLocalDay(normalizedPendingChange.effectiveAt);
      if (pendingEffectiveDate && pendingEffectiveDate.getTime() <= today.getTime()) {
        const nextHistory = getFirmPlanHistory(offer).slice();
        nextHistory.push(buildFirmPlanHistoryEntry(normalizedPendingChange.planKey, normalizedPendingChange.effectiveAt, {
          changeKind: normalizedPendingChange.changeKind,
          requestedAt: normalizedPendingChange.requestedAt,
          changedAt: normalizedPendingChange.effectiveAt
        }));
        offer.billingPlanHistory = normalizeFirmPlanHistoryEntries({
          ...offer,
          billingPlanHistory: nextHistory
        });
        offer.billingPlan = normalizedPendingChange.planKey;
        offer.planActivatedAt = normalizedPendingChange.effectiveAt;
        if (doesFirmPlanChargeMonthlyBase(normalizedPendingChange.planKey)) {
          offer.subscriptionCommitmentStartMonthKey = normalizedPendingChange.effectiveMonthKey;
          offer.subscriptionMinimumUntilMonthKey = shiftBillingMonthKey(normalizedPendingChange.effectiveMonthKey, FIRM_SUBSCRIPTION_MINIMUM_MONTHS - 1);
        } else {
          offer.subscriptionCommitmentStartMonthKey = "";
          offer.subscriptionMinimumUntilMonthKey = "";
        }
        offer.pendingBillingPlanChange = null;
        didChange = true;
      } else {
        const serializedPending = JSON.stringify(offer.pendingBillingPlanChange || null);
        const serializedNormalizedPending = JSON.stringify(normalizedPendingChange);
        if (serializedPending !== serializedNormalizedPending) {
          offer.pendingBillingPlanChange = normalizedPendingChange;
          didChange = true;
        }
      }
    } else if (offer.pendingBillingPlanChange) {
      offer.pendingBillingPlanChange = null;
      didChange = true;
    }

    const normalizedHistory = normalizeFirmPlanHistoryEntries(offer);
    if (JSON.stringify(Array.isArray(offer.billingPlanHistory) ? offer.billingPlanHistory : []) !== JSON.stringify(normalizedHistory)) {
      offer.billingPlanHistory = normalizedHistory;
      didChange = true;
    }

    const activeHistoryEntry = getFirmActivePlanHistoryEntry({
      ...offer,
      billingPlanHistory: normalizedHistory
    }, today);
    if (activeHistoryEntry && isFirmAccountReleased(offer) && offer.billingPlan !== activeHistoryEntry.planKey) {
      offer.billingPlan = activeHistoryEntry.planKey;
      didChange = true;
    }
    if (activeHistoryEntry && isFirmAccountReleased(offer) && offer.planActivatedAt !== activeHistoryEntry.startAt) {
      offer.planActivatedAt = activeHistoryEntry.startAt;
      didChange = true;
    }

    if (activeHistoryEntry && doesFirmPlanChargeMonthlyBase(activeHistoryEntry.planKey) && isFirmAccountReleased(offer)) {
      const commitmentStartMonthKey = String(offer.subscriptionCommitmentStartMonthKey || formatBillingMonthKey(activeHistoryEntry.startAt)).trim();
      const minimumUntilMonthKey = String(offer.subscriptionMinimumUntilMonthKey || shiftBillingMonthKey(commitmentStartMonthKey, FIRM_SUBSCRIPTION_MINIMUM_MONTHS - 1)).trim();
      if (offer.subscriptionCommitmentStartMonthKey !== commitmentStartMonthKey) {
        offer.subscriptionCommitmentStartMonthKey = commitmentStartMonthKey;
        didChange = true;
      }
      if (offer.subscriptionMinimumUntilMonthKey !== minimumUntilMonthKey) {
        offer.subscriptionMinimumUntilMonthKey = minimumUntilMonthKey;
        didChange = true;
      }
    } else {
      if (offer.subscriptionCommitmentStartMonthKey) {
        offer.subscriptionCommitmentStartMonthKey = "";
        didChange = true;
      }
      if (offer.subscriptionMinimumUntilMonthKey) {
        offer.subscriptionMinimumUntilMonthKey = "";
        didChange = true;
      }
    }
  });

  if (didChange) {
    persistOffers(offers);
  }

  return offers;
}

function persistOffers(list) {
  writeJson(STORAGE_KEYS.offers, list);
  if (typeof verschiebeMatchesInMatchOrdner === 'function') {
    try { verschiebeMatchesInMatchOrdner(); } catch(e) { /* ignore */ }
  }
}

function saveOffers(list) {
  persistOffers(list);
  // Nach dem Speichern auf das eigene Firmenprofil weiterleiten, wenn wir uns auf der Profilseite befinden
  if (window.location.pathname.endsWith('firma_profil.html')) {
    const redirectToProfile = function() {
      window.location.href = buildRuntimeUrl("firma_profil.html");
    };
    const pendingSync = waitForServerBackedStorageSync(STORAGE_KEYS.offers, 1400);
    if (pendingSync) {
      pendingSync.finally(function() {
        window.setTimeout(redirectToProfile, 80);
      });
      return;
    }
    setTimeout(redirectToProfile, 400);
  }
}

