function updateStudentRetentionEntry(studentId, patch) {
  if (!studentId) return null;
  const records = loadStudentRetentionCheckins();
  const currentEntry = records[studentId] && typeof records[studentId] === "object" ? records[studentId] : {};
  const nextEntry = { ...currentEntry, ...patch };
  records[studentId] = nextEntry;
  saveStudentRetentionCheckins(records);
  return nextEntry;
}

function formatStudentRetentionTimestamp(value) {
  if (!value) return "";
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return "";
  return date.toLocaleDateString("de-DE", { day: "2-digit", month: "2-digit", year: "numeric" })
    + " um "
    + date.toLocaleTimeString("de-DE", { hour: "2-digit", minute: "2-digit" });
}

function inferStudentSupportTopic(entry) {
  const noteText = String((entry && entry.note) || "").toLowerCase();
  if (/(gesund|krank|stress|erschoepf|panik|angst|schlaf)/.test(noteText)) {
    return "health";
  }
  if (/(ueberforder|überforder|aufgab|unklar|tempo|einarbeit|zu viel|belast)/.test(noteText)) {
    return "overload";
  }
  if (/(konflikt|team|kolleg|ausbilder|chef|betriebsklima|kommunikation|streit)/.test(noteText)) {
    return "conflict";
  }
  if (/(schule|berufsschule|note|pruef|prüfung|unterricht|fehlzeit)/.test(noteText)) {
    return "school";
  }
  if (/(zweifel|motivation|abbruch|kein sinn|beruf passt|falscher beruf)/.test(noteText)) {
    return "motivation";
  }

  const scoreMap = [
    { key: "betriebScore", topic: "conflict" },
    { key: "aufgabenScore", topic: "overload" },
    { key: "schuleScore", topic: "school" },
    { key: "motivationScore", topic: "motivation" }
  ];

  let selected = scoreMap[0];
  let lowestScore = Number((entry && entry[selected.key]) || 99);
  scoreMap.forEach((item) => {
    const score = Number((entry && entry[item.key]) || 99);
    if (score < lowestScore) {
      lowestScore = score;
      selected = item;
    }
  });

  return selected.topic;
}

function getStudentRetentionAssessment(entry) {
  const scoreKeys = ["betriebScore", "aufgabenScore", "schuleScore", "motivationScore"];
  const scores = scoreKeys
    .map((key) => Number((entry && entry[key]) || 0))
    .filter((score) => score > 0);

  if (!scores.length) {
    return {
      state: "empty",
      badge: "Noch kein Check-in",
      title: "Du hast noch keine Probezeit-Einschätzung gespeichert",
      text: "Sobald du deinen Check-in ausfüllst, zeigt dir AzubiMatch frühe Warnsignale und passende nächste Schritte.",
      recommendedTopic: "overload"
    };
  }

  const average = scores.reduce((sum, value) => sum + value, 0) / scores.length;
  const hasCriticalSignal = scores.some((score) => score <= 1);
  const hasWarningSignal = scores.some((score) => score <= 2);
  const recommendedTopic = inferStudentSupportTopic(entry);

  if (hasCriticalSignal || average < 2.2) {
    return {
      state: "urgent",
      badge: "Akuter Handlungsbedarf",
      title: "Dein letzter Check-in zeigt deutlichen Unterstützungsbedarf",
      text: "Bitte warte nicht zu lange. Vereinbare jetzt ein klärendes Gespräch und hole dir früh Unterstützung, bevor aus Belastung ein Abbruch wird.",
      recommendedTopic: recommendedTopic,
      scoreLabel: average.toFixed(1) + " / 4"
    };
  }

  if (hasWarningSignal || average < 3.2) {
    return {
      state: "attention",
      badge: "Frühe Warnzeichen",
      title: "Es gibt Themen, die du jetzt aktiv ansprechen solltest",
      text: "Dein Ausbildungsstart wirkt nicht durchgehend stabil. Mit einem frühen Gespräch und klaren Absprachen lassen sich viele Probleme noch gut lösen.",
      recommendedTopic: recommendedTopic,
      scoreLabel: average.toFixed(1) + " / 4"
    };
  }

  return {
    state: "stable",
    badge: "Stabiler Start",
    title: "Dein letzter Check-in wirkt insgesamt positiv",
    text: "Im Moment deutet vieles auf einen tragfähigen Start hin. Halte kleine Irritationen trotzdem früh fest, damit sie nicht wachsen.",
    recommendedTopic: recommendedTopic,
    scoreLabel: average.toFixed(1) + " / 4"
  };
}

function loadFullProfileRequests() {
  const list = readJson("azubimatch_fullprofile_requests", []);
  if (!Array.isArray(list) || !list.length) {
    return Array.isArray(list) ? list : [];
  }

  const offers = typeof loadOffers === "function" ? loadOffers() : [];
  const students = typeof loadStudents === "function" ? loadStudents() : [];
  let changed = false;

  const migrated = list.map((request) => {
    if (!request || typeof request !== "object") {
      return request;
    }

    const next = { ...request };
    const normalizedStatus = String(next.status || "").trim().toLowerCase();
    const firm = offers.find((offer) => offer.id === next.firmId || offer.userId === next.firmId || offer.userEmail === next.firmEmail);
    const student = students.find((entry) => entry.id === next.studentId || (entry.profilCode && entry.profilCode === next.profilCode));
    const storedProfession = getStoredRequestProfession(next);

    if (storedProfession && !next.matchedProfession) {
      next.matchedProfession = storedProfession;
      changed = true;
    }

    if ((next.matchedProfession || storedProfession) && !next.beruf) {
      next.beruf = next.matchedProfession || storedProfession;
      changed = true;
    }

    if (normalizedStatus === "offen") {
      next.status = "weitergeleitet";
      next.forwardedAt = next.forwardedAt || next.requestedAt || new Date().toISOString();
      changed = true;
    }

    if (!next.shortProfileSnapshot && firm) {
      next.shortProfileSnapshot = {
        name: firm.firma || "",
        branche: firm.branche || "",
        city: firm.ort || firm.stadt || "",
        plz: firm.plz || "",
        professions: getOfferProfessionList(firm),
        benefits: Array.isArray(firm.benefits) ? firm.benefits : []
      };
      changed = true;
    }

    if ((!next.matchedProfession || !next.matchLabel) && student && firm) {
      const matchMeta = getMatchMeta(student, firm, { allOffers: loadOffers() });
      const fallbackProfession = next.matchedProfession || storedProfession || matchMeta.matchedProfession;
      const currentMatchFitsRequest = fallbackProfession && matchMeta.matchedProfession
        && normalizeProfessionText(fallbackProfession) === normalizeProfessionText(matchMeta.matchedProfession);
      if (fallbackProfession && !next.matchedProfession) {
        next.matchedProfession = fallbackProfession;
        changed = true;
      }
      if (fallbackProfession && !next.beruf) {
        next.beruf = fallbackProfession;
        changed = true;
      }
      if (currentMatchFitsRequest && !next.matchLabel) {
        next.matchLabel = matchMeta.matchLabel;
        next.isAlternativeMatch = typeof next.isAlternativeMatch === "boolean" ? next.isAlternativeMatch : matchMeta.isAlternativeMatch;
        next.isActivatedAlternativeProfession = typeof next.isActivatedAlternativeProfession === "boolean" ? next.isActivatedAlternativeProfession : matchMeta.isActivatedAlternativeProfession;
        next.alternativeFamilyLabel = next.alternativeFamilyLabel || matchMeta.alternativeFamilyLabel || "";
        changed = true;
      }
    }

    if (typeof next.isActivatedAlternativeProfession !== "boolean" && student && firm) {
      const matchMeta = getMatchMeta(student, firm, { allOffers: loadOffers() });
      if (matchMeta.matchedProfession && normalizeProfessionText(matchMeta.matchedProfession) === normalizeProfessionText(next.matchedProfession || storedProfession)) {
        next.isActivatedAlternativeProfession = matchMeta.isActivatedAlternativeProfession;
        changed = true;
      }
    }

    const currentStatus = String(next.status || "").trim().toLowerCase();
    if (isPaymentPendingFullProfileRequestStatus(currentStatus)) {
      next.status = "weitergeleitet";
      next.forwardedAt = next.forwardedAt || next.requestedAt || new Date().toISOString();
      changed = true;
    }

    if (next.feeRequired === true) {
      const normalizedBillingStatus = getFullProfileRequestBillingStatus(next);

      if (!next.feeLabel) {
        next.feeLabel = getFirmContactRequestFeeLabel(next, firm);
        changed = true;
      }

      if (next.feeAcknowledgedByFirm !== true) {
        next.feeAcknowledgedByFirm = true;
        changed = true;
      }

      if (!next.feeAcknowledgedAt) {
        next.feeAcknowledgedAt = next.requestedAt || next.forwardedAt || new Date().toISOString();
        changed = true;
      }

      if (next.billingStatus !== normalizedBillingStatus) {
        next.billingStatus = normalizedBillingStatus;
        changed = true;
      }

      if (normalizedBillingStatus === "billable") {
        const billingTriggeredAt = next.billingTriggeredAt || next.decisionAt || next.forwardedAt || next.requestedAt || new Date().toISOString();
        if (next.billingTriggeredAt !== billingTriggeredAt) {
          next.billingTriggeredAt = billingTriggeredAt;
          changed = true;
        }
        const invoiceMonth = next.invoiceMonth || formatBillingMonthKey(billingTriggeredAt);
        if (next.invoiceMonth !== invoiceMonth) {
          next.invoiceMonth = invoiceMonth;
          changed = true;
        }
      }

      const normalizedAmount = getFirmContactRequestAmountCents(next);
      if (Number.isFinite(normalizedAmount) && next.unitPriceCents !== normalizedAmount) {
        next.unitPriceCents = normalizedAmount;
        changed = true;
      }

      if (normalizedBillingStatus === "cancelled" && next.invoiceMonth) {
        next.invoiceMonth = "";
        changed = true;
      }
    }

    return next;
  });

  if (normalizeManagedFullProfileRequestBillingData(migrated, offers)) {
    changed = true;
  }

  if (changed) {
    writeJson("azubimatch_fullprofile_requests", migrated);
  }

  return migrated;
}

function saveFullProfileRequests(list) {
  const requests = Array.isArray(list) ? list : [];
  normalizeManagedFullProfileRequestBillingData(requests, loadOffers());
  writeJson("azubimatch_fullprofile_requests", requests);
}

