function renderMailTemplateString(template, values, mode) {
  const replacements = values && typeof values === "object" ? values : {};
  const htmlMode = mode === "html";

  return String(template || "").replace(/\{\{\s*([a-z0-9_]+)\s*\}\}/gi, function (match, key) {
    const rawValue = Object.prototype.hasOwnProperty.call(replacements, key) ? replacements[key] : "";
    const normalizedValue = rawValue == null ? "" : String(rawValue);
    return htmlMode ? escapeHtml(normalizedValue) : normalizedValue;
  });
}

function buildWelcomeEmailPayload(user, type) {
  const normalizedType = type === "firm" ? "firm" : "student";
  const welcomeTemplate = WELCOME_EMAIL_TEMPLATES[normalizedType] || WELCOME_EMAIL_TEMPLATES.student;
  const recipientEmail = String(user && user.email || "").trim();
  const recipientName = String(user && user.name || "").trim() || (normalizedType === "firm" ? "Team" : "du");
  const loginUrl = buildRuntimeUrl("anmeldung.html");
  const portalUrl = buildRuntimeUrl(normalizedType === "firm" ? "firma_profil.html" : "bewerber_profil.html");
  const supportName = normalizedType === "firm"
    ? "AzubiMatch | Unternehmensservice"
    : "AzubiMatch | Bewerbendenservice";
  const templateId = normalizedType === "firm"
    ? String(EMAIL_SETTINGS.firmWelcomeTemplateId || EMAIL_SETTINGS.otcTemplateId || EMAIL_SETTINGS.templateId || "").trim()
    : String(EMAIL_SETTINGS.studentWelcomeTemplateId || EMAIL_SETTINGS.otcTemplateId || EMAIL_SETTINGS.templateId || "").trim();
  const templateValues = {
    recipient_name: recipientName,
    recipient_email: recipientEmail,
    portal_url: portalUrl,
    login_url: loginUrl,
    support_name: supportName
  };

  return {
    email: recipientEmail,
    name: recipientName,
    title: welcomeTemplate.subject,
    message: renderMailTemplateString(welcomeTemplate.text, templateValues),
    htmlMessage: renderMailTemplateString(welcomeTemplate.html, templateValues, "html"),
    type: normalizedType === "firm" ? "firm-welcome" : "student-welcome",
    emailJsTemplateId: templateId,
    emailJsParams: templateValues
  };
}

function buildStudentWelcomeEmailPayload(user) {
  return buildWelcomeEmailPayload(user, "student");
}

function buildFirmWelcomeEmailPayload(user) {
  return buildWelcomeEmailPayload(user, "firm");
}

async function sendAdminNewRegistrationNotification(user, registrantType) {
  const adminEmail = String(EMAIL_SETTINGS.internalRecipient || "").trim();
  if (!adminEmail || !user) return;
  const normalizedType = registrantType === "firm" ? "Unternehmen" : "Bewerber";
  const registrantName = String(user.name || "").trim() || "–";
  const registrantEmail = String(user.email || "").trim();
  const adminUrl = buildRuntimeUrl("admin.html");
  const subject = "AzubiMatch: Neue Registrierung (" + normalizedType + ")";
  const timestampLabel = new Date().toLocaleString("de-DE");
  const message = [
    "Neue Registrierung auf AzubiMatch:",
    "",
    "Typ: " + normalizedType,
    "Name: " + registrantName,
    "E-Mail: " + registrantEmail,
    "Zeitpunkt: " + timestampLabel,
    "",
    "Admin-Bereich: " + adminUrl
  ].join("\n");
  const templateId = String(EMAIL_SETTINGS.adminAlertTemplateId || EMAIL_SETTINGS.otcTemplateId || "").trim();
  const htmlMessage = buildBrandedNotificationEmailHtml({
    recipientType: "firm",
    preheader: "Im Admin-Bereich liegt eine neue Registrierung zur Prüfung bereit.",
    eyebrow: "Neue Registrierung",
    headline: "Im Admin-Bereich liegt ein neuer Registrierungsfall vor.",
    lead: "Die wichtigsten Daten zur neuen Registrierung sind hier kompakt zusammengefasst.",
    introParagraphs: [
      "Guten Tag,",
      "auf AzubiMatch wurde eine neue Registrierung angelegt."
    ],
    cards: [
      {
        eyebrow: "Registrierungsdaten",
        title: normalizedType + " zur Prüfung",
        rows: [
          { label: "Typ", value: normalizedType },
          { label: "Name", value: registrantName },
          { label: "E-Mail", value: registrantEmail || "–" },
          { label: "Zeitpunkt", value: timestampLabel }
        ]
      }
    ],
    actions: [
      { label: "Admin-Bereich öffnen", url: adminUrl }
    ],
    closingGreeting: "Freundliche Grüße",
    supportName: "AzubiMatch System"
  });
  const emailJsParams = {
    recipient_name: String(EMAIL_SETTINGS.internalRecipientName || "AzubiMatch Team").trim(),
    recipient_email: adminEmail,
    otp_code: "",
    flow_label: "neue Registrierung",
    expires_hint: "",
    message_line: message.replace(/\n/g, "<br>"),
    login_url: adminUrl,
    support_name: "AzubiMatch System"
  };
  await sendNotificationEmail({
    email: adminEmail,
    name: String(EMAIL_SETTINGS.internalRecipientName || "AzubiMatch Team").trim(),
    title: subject,
    message: message,
    htmlMessage: htmlMessage,
    type: "admin-alert",
    emailJsTemplateId: templateId,
    emailJsParams: emailJsParams
  });
}

async function maybeSendStudentWelcomeNotification(user, usersList) {
  if (!user || user.welcomeNotificationSentAt) return false;
  if (!String(user.email || "").trim()) return false;
  await sendNotificationEmail(buildStudentWelcomeEmailPayload(user));
  user.welcomeNotificationSentAt = new Date().toISOString();
  if (Array.isArray(usersList)) {
    saveRegisteredStudentUsers(usersList);
  }
  try {
    await sendAdminNewRegistrationNotification(user, "student");
  } catch (err) {
    console.warn("Admin-Registrierungsbenachrichtigung konnte nicht gesendet werden:", err);
  }
  return true;
}

async function maybeSendFirmWelcomeNotification(user, usersList) {
  if (!user || user.welcomeNotificationSentAt) return false;
  if (!String(user.email || "").trim()) return false;
  await sendNotificationEmail(buildFirmWelcomeEmailPayload(user));
  user.welcomeNotificationSentAt = new Date().toISOString();
  if (Array.isArray(usersList)) {
    saveRegisteredFirmUsers(usersList);
  }
  try {
    await sendAdminNewRegistrationNotification(user, "firm");
  } catch (err) {
    console.warn("Admin-Registrierungsbenachrichtigung konnte nicht gesendet werden:", err);
  }
  return true;
}

