    top_match_profession: firstMatch.matchedProfession || student.beruf || "Passender Ausbildungsberuf",
    top_match_city: summary.city || "-",
    top_match_distance: firstMatch.distanceLabel || "Distanz unbekannt",
    top_match_label: firstMatch.matchLabel || "Direktes Match",
    radius_label: radiusLabel || "dein gewählter Umkreis",
    inclusion_hint: inclusionCount ? (inclusionCount === 1 ? "Darunter befindet sich 1 Inklusions-Match." : "Darunter befinden sich " + inclusionCount + " Inklusions-Matches.") : "",
    dashboard_url: dashboardUrl,
    login_url: loginUrl,
