if (saveBewerber && saveBewerber.dataset.boundStudentSave !== "1") {
  saveBewerber.dataset.boundStudentSave = "1";
  saveBewerber.addEventListener("click", async () => {
    const name = (document.getElementById("name") || {}).value || "";
    let beruf = (document.getElementById("beruf") || {}).value || "";
    const stadt = (document.getElementById("stadt") || {}).value || "";
    const grundschuleVon = (document.getElementById("grundschuleVon") || {}).value || "";
    const grundschuleBis = (document.getElementById("grundschuleBis") || {}).value || "";
    const weiterfuehrendeVon = (document.getElementById("weiterfuehrendeVon") || {}).value || "";
    const weiterfuehrendeSchulform = (document.getElementById("weiterfuehrendeSchulform") || {}).value || "";
    const weiterfuehrendeBis = (document.getElementById("weiterfuehrendeBis") || {}).value || "";
    const wahlfach = (document.getElementById("wahlfach") || {}).value || "";
    const noteMathe = (document.getElementById("noteMathe") || {}).value || "";
    const noteDeutsch = (document.getElementById("noteDeutsch") || {}).value || "";
    const noteEnglisch = (document.getElementById("noteEnglisch") || {}).value || "";
      const plz = (document.getElementById("plz") || {}).value || "";
    const noteWahlfach = (document.getElementById("noteWahlfach") || {}).value || "";
    const out = document.getElementById("bewerberStatus");

    const studentBerufSuggestion = getProfessionSuggestion(beruf);
    if (studentBerufSuggestion && !studentBerufSuggestion.exact && studentBerufSuggestion.needsSuggestion) {
      const acceptCorrection = confirm("Möglicher Tippfehler beim Wunschberuf erkannt. Meinten Sie: \"" + studentBerufSuggestion.value + "\"?");
      if (acceptCorrection) {
        beruf = studentBerufSuggestion.value;
        const berufInputEl = document.getElementById("beruf");
        if (berufInputEl) berufInputEl.value = beruf;
      }
    }

    if (!name.trim() || !beruf.trim() || !stadt.trim() || !grundschuleVon.trim() || !grundschuleBis.trim() || !weiterfuehrendeVon.trim() || !weiterfuehrendeSchulform.trim() || !weiterfuehrendeBis.trim() || !wahlfach.trim() || !noteMathe.trim() || !noteDeutsch.trim() || !noteEnglisch.trim() || !noteWahlfach.trim()) {
      if (out) out.textContent = "Bitte alle Daten vollständig ausfüllen. Nur vollständige Profile mit Lebenslauf können für Betriebe sichtbar sein.";
      return;
    }

    if (Number(grundschuleVon) > Number(grundschuleBis)) {
      if (out) out.textContent = "Beim Grundschulbesuch muss 'von Jahr' kleiner oder gleich 'bis Jahr' sein.";
      return;
    }

    if (Number(weiterfuehrendeVon) > Number(weiterfuehrendeBis)) {
      if (out) out.textContent = "Bei der weiterführenden Schule muss 'von Jahr' kleiner oder gleich 'bis Jahr' sein.";
      return;
    }

    const grades = [noteMathe, noteDeutsch, noteEnglisch, noteWahlfach].map((value) => Number(value));
    const invalidGrade = grades.some((grade) => Number.isNaN(grade) || !Number.isInteger(grade) || grade < 1 || grade > 6);
    if (invalidGrade) {
      if (out) out.textContent = "Noten müssen ganze Zahlen von 1 bis 6 sein.";
      return;
    }

    let lebenslaufData;
    let anschreibenData;
    let zeugnisData;
    let weiteresDokumentData;
    let profilBildData;
    try {
      lebenslaufData = await collectFileData("lebenslaufFile");
      anschreibenData = await collectFileData("anschreibenFile");
      zeugnisData = await collectFileData("zeugnisFile");
      weiteresDokumentData = await collectFileData("weiteresDokumentFile");
      profilBildData = await collectFileData("profilBildFile");
    } catch (err) {
      if (out) out.textContent = err.message;
      return;
    }

    const students = loadStudents();
    const auth = getStoredStudentAuth();
    let activeId = getActiveStudentId();

    let existing = students.find((s) => s.id === activeId);

    // Erlaube gleiche Namen, aber E-Mail und Stadt müssen unterschiedlich sein
    if (!existing) {
      existing = students.find((s) =>
        normalizeText(s.name) === normalizeText(name) &&
        ((auth && s.userEmail === auth.email) || (s.stadt && s.stadt.trim().toLowerCase() === stadt.trim().toLowerCase()))
      );
    }

    const now = new Date().toISOString();

    if (!existing) {
      existing = { id: uniqueId("BID"), createdAt: now };
      students.push(existing);
    }

    if (!existing.profilCode) {
      existing.profilCode = createProfileCode();
    }

    existing.name = name.trim();
    if (auth) {
      existing.userId = auth.id;
      existing.userEmail = auth.email;
    }
    existing.beruf = beruf.trim();
    existing.stadt = stadt.trim();
    existing.grundschuleVon = grundschuleVon.trim();
    existing.grundschuleBis = grundschuleBis.trim();
    existing.weiterfuehrendeVon = weiterfuehrendeVon.trim();
    existing.weiterfuehrendeSchulform = weiterfuehrendeSchulform.trim();
    existing.weiterfuehrendeBis = weiterfuehrendeBis.trim();
    existing.wahlfach = wahlfach.trim();
    existing.noteMathe = noteMathe.trim();
    existing.noteDeutsch = noteDeutsch.trim();
    existing.noteEnglisch = noteEnglisch.trim();
    existing.noteWahlfach = noteWahlfach.trim();
    // Backward compatibility: preserve old consent value when present.
    if (typeof existing.vollprofilFreigegeben !== "boolean") {
      existing.vollprofilFreigegeben = !!existing.datenfreigabeEinwilligung;
    }
    existing.updatedAt = now;
    if (lebenslaufData) existing.lebenslauf = lebenslaufData;
    if (anschreibenData) existing.anschreiben = anschreibenData;
    if (zeugnisData) existing.zeugnis = zeugnisData;
    if (weiteresDokumentData) existing.weiteresDokument = weiteresDokumentData;
    if (profilBildData) existing.profilBild = profilBildData;

    saveStudents(students);
    try {
      const registeredUsers = loadRegisteredStudentUsers();
      const linkedUser = registeredUsers.find(function(user) {
        return (auth && auth.id && user.id === auth.id)
          || (auth && auth.email && normalizeText(user.email) === normalizeText(auth.email));
      });
      await maybeSendStudentWelcomeNotification(linkedUser, registeredUsers);
    } catch (err) {
      console.warn("Willkommensmail für Bewerbende konnte nicht gesendet werden:", err);
    }
    try {
      await maybeSendStudentPossibleMatchNotification(existing, students);
    } catch (err) {
      console.warn("Match-Benachrichtigung für Bewerbende konnte nicht gesendet werden:", err);
    }
    setActiveStudentId(existing.id);
    renderStudentMessages(existing.id);

    if (out) {
      out.textContent = "Profil gespeichert. Dein Profil ist vollständig und kann zusammen mit deinen angegebenen Daten für Betriebe sichtbar gemacht werden.";
    }

    navigateWithTransition(getStudentProfileDashboardUrl(), "Dein persönliches Profil wird geöffnet...");
  });
}

function getBerufliste() {
  const items = document.querySelectorAll(".beruf-item");
  const berufe = [];
  items.forEach(function(item) {
    const beruf = item.getAttribute("data-beruf");
    if (beruf) berufe.push(beruf);
  });
  return berufe;
}

function renderBerufliste() {
  const container = document.getElementById("berufliste");
  if (!container) return;
  const berufe = getBerufliste();
  if (!berufe.length) {
    container.innerHTML = "<p class='status' style='color: #94a3b8; font-size: 0.9rem;'>Keine Berufe hinzugefügt. Bitte oben einen Beruf eintragen und ➕ klicken.</p>";
    return;
  }
  container.innerHTML = berufe.map(function(beruf) {
    return "<div class='beruf-item' data-beruf='" + escapeHtml(beruf) + "'>"
      + "<span class='beruf-name'>" + escapeHtml(beruf) + "</span>"
      + "<button class='beruf-remove-btn' title='Beruf entfernen'>✕</button>"
      + "</div>";
  }).join("");
}

function getSelectedFirmBillingPlanValue() {
  const selectedInput = document.querySelector('input[name="firmBillingPlan"]:checked');
  return normalizeFirmSelfServiceBillingPlan(
    selectedInput ? selectedInput.value : DEFAULT_FIRM_BILLING_PLAN_KEY,
    DEFAULT_FIRM_BILLING_PLAN_KEY
  );
}

function setSelectedFirmBillingPlanValue(value) {
  const normalizedValue = normalizeFirmSelfServiceBillingPlan(value, DEFAULT_FIRM_BILLING_PLAN_KEY);
  const inputs = document.querySelectorAll('input[name="firmBillingPlan"]');
  inputs.forEach(function(input) {
    input.checked = input.value === normalizedValue;
  });
}

function setFirmBillingPlanSelectionState(isLocked, hintText) {
  const inputs = document.querySelectorAll('input[name="firmBillingPlan"]');
  inputs.forEach(function(input) {
    input.disabled = !!isLocked;
    const card = input.closest('.firm-plan-card');
    if (!card) return;
    card.classList.toggle('firm-plan-card--disabled', !!isLocked);
    if (isLocked) {
      card.setAttribute('aria-disabled', 'true');
    } else {
      card.removeAttribute('aria-disabled');
    }
  });

  const planHint = document.getElementById('firmBillingPlanHint');
  if (planHint && hintText) {
    planHint.textContent = hintText;
  }
}

function addBeruf(beruf) {
  if (!beruf || !beruf.trim()) return;
  const trimmed = beruf.trim();
  let resolvedBeruf = trimmed;

  const suggestion = getProfessionSuggestion(trimmed);
  if (suggestion && suggestion.exact) {
    resolvedBeruf = suggestion.value;
  } else if (suggestion && suggestion.needsSuggestion) {
    const accept = confirm("Möglicher Tippfehler erkannt. Meinten Sie: \"" + suggestion.value + "\"?");
    if (!accept) {
      return;
    }
    resolvedBeruf = suggestion.value;
  }

  const existing = document.querySelector(".beruf-item[data-beruf='" + escapeHtml(resolvedBeruf).replace(/'/g, "\\'") + "']");
  if (existing) {
    // alert("Dieser Beruf existiert bereits.");
    return;
  }
  const container = document.getElementById("berufliste");
  if (!container) return;
  
  const item = document.createElement("div");
  item.className = "beruf-item";
  item.setAttribute("data-beruf", resolvedBeruf);
  item.innerHTML = "<span class='beruf-name'>" + escapeHtml(resolvedBeruf) + "</span>"
    + "<button class='beruf-remove-btn' title='Beruf entfernen'>✕</button>";
  
  container.appendChild(item);
}

const saveFirma = document.getElementById("saveFirma");
// --- END SIMULATION ---
if (saveFirma) {
  saveFirma.addEventListener("click", async () => {
    const currentFirmAuth = getStoredFirmAuth();
    const existingOffer = findFirmOfferByAuth(currentFirmAuth);
    const selectedBillingPlan = getSelectedFirmBillingPlanValue();
    const firma = (document.getElementById("firma") || {}).value || "";
    const strasse = (document.getElementById("strasse") || {}).value || "";
    const plz = (document.getElementById("plz") || {}).value || "";
    const ort = (document.getElementById("ort") || {}).value || "";
    const anrede = normalizeFirmSalutationValue((document.getElementById("anrede") || {}).value || "");
    const ansprechpartner = (document.getElementById("ansprechpartner") || {}).value || "";
    const ihkMitgliedsnummer = (document.getElementById("ihkMitgliedsnummer") || {}).value || "";
    const matchUmkreis = normalizeMatchRadiusValue((document.getElementById("matchUmkreis") || {}).value || "");
    const berufe = getBerufliste();
    const platzBehindert = normalizeFirmInclusionValue((document.getElementById("platzBehindert") || {}).value || "");
    const startdatum = (document.getElementById("startdatum") || {}).value || "";
    const out = document.getElementById("firmaStatus");

    if (existingOffer && isFirmMainProfileLocked(existingOffer) && !isPortalEditModeRequested()) {
      if (out) out.textContent = "Die Stammdaten des Hauptprofils sind nach der Registrierung gesperrt. Änderungen laufen nur noch über Ansprechpartner und Kurzprofil.";
      return;
    }

    if (!/^[0-9]{5}$/.test(plz.trim())) {
      if (out) out.textContent = "Bitte eine gültige PLZ (5 Ziffern) angeben.";
      return;
    }

    if (!firma.trim() || !strasse.trim() || !plz.trim() || !ort.trim() || !anrede || !ansprechpartner.trim() || !ihkMitgliedsnummer.trim() || !berufe.length || !platzBehindert || !startdatum) {
      if (out) out.textContent = "Bitte alle Felder (Firmenname, Straße, PLZ, Ort, Anrede, Ansprechperson, IHK Mitgliedsnummer, Match-Umkreis, Ausbildungsberufe, Platz für Behinderung, Startdatum) ausfüllen.";
      return;
    }

    const offers = loadOffers();
    const firmAuth = getStoredFirmAuth();
    const existingStoredOffer = findFirmOfferByAuth(firmAuth, offers);
    const now = new Date();
    const nowIso = now.toISOString();
    const nowMonthKey = formatBillingMonthKey(now);
    const currentActivePlanKey = existingStoredOffer ? getFirmBillingPlanKey(existingStoredOffer) : selectedBillingPlan;
    const existingPendingPlanChange = existingStoredOffer ? getFirmPendingPlanChange(existingStoredOffer) : null;
    const selectedMatchesPendingPlan = !!(existingPendingPlanChange && existingPendingPlanChange.planKey === selectedBillingPlan);
    const previewPlanIntent = existingStoredOffer ? getFirmPlanChangeIntent(existingStoredOffer, selectedBillingPlan, now) : null;
    const shouldRequestPaidPlanConfirmation = existingStoredOffer
      ? (!selectedMatchesPendingPlan
        && !(existingPendingPlanChange && selectedBillingPlan === currentActivePlanKey)
        && doesFirmPlanChargeMonthlyBase(selectedBillingPlan)
        && previewPlanIntent.mode !== "current")
      : doesFirmPlanChargeMonthlyBase(selectedBillingPlan);
    let paidPlanConfirmation = {
      required: false,
      confirmed: true,
      planKey: getNormalizedFirmBillingPlan(selectedBillingPlan),
      acceptedAt: "",
      priceCents: Number(getFirmBillingPlanDefinition(selectedBillingPlan).monthlyPriceCents || 0)
    };

    if (shouldRequestPaidPlanConfirmation) {
      paidPlanConfirmation = await requestFirmPaidPlanOrderConfirmation({
        offer: existingStoredOffer,
        selectedPlanKey: selectedBillingPlan,
        planIntent: previewPlanIntent,
        referenceDateValue: now,
        triggerElement: saveFirma
      });
      if (!paidPlanConfirmation.confirmed) {
        if (out) out.textContent = "Kostenpflichtige Bestellung abgebrochen.";
        return;
      }
    }


    let gewerbeanmeldung = null;
    const gewerbeanmeldungFile = document.getElementById("gewerbeanmeldung").files[0];
    if (gewerbeanmeldungFile) {
      try {
        gewerbeanmeldung = await collectFileData("gewerbeanmeldung");
      } catch (e) {
        if (out) out.textContent = "Gewerbeanmeldung konnte nicht hochgeladen werden: " + e.message;
        return;
      }
    }

    let ausbildungDerAusbilder = null;
    const ausbildungDerAusbilderFile = document.getElementById("ausbildungDerAusbilder").files[0];
    if (ausbildungDerAusbilderFile) {
      try {
        ausbildungDerAusbilder = await collectFileData("ausbildungDerAusbilder");
      } catch (e) {
        if (out) out.textContent = "Ausbildung der Ausbilder konnte nicht hochgeladen werden: " + e.message;
        return;
      }
    }

    let firmenlogo = null;
    const firmenlogoFile = document.getElementById("firmenlogo").files[0];
    if (firmenlogoFile) {
      try {
        firmenlogo = await collectFileData("firmenlogo");
      } catch (e) {
        if (out) out.textContent = "Firmenlogo konnte nicht hochgeladen werden: " + e.message;
        return;
      }
    }

    const nextGewerbeanmeldung = gewerbeanmeldung || (existingStoredOffer && existingStoredOffer.gewerbeanmeldung) || null;
    const nextAusbildungDerAusbilder = ausbildungDerAusbilder || (existingStoredOffer && existingStoredOffer.ausbildungDerAusbilder) || null;
    const nextFirmenlogo = firmenlogo || (existingStoredOffer && existingStoredOffer.firmenlogo) || null;
    const documentsChanged = firmVerificationDocumentsChanged(existingStoredOffer, {
      gewerbeanmeldung: nextGewerbeanmeldung,
      ausbildungDerAusbilder: nextAusbildungDerAusbilder,
      firmenlogo: nextFirmenlogo
    });
    let persistedBillingPlan = existingStoredOffer ? currentActivePlanKey : selectedBillingPlan;
    let nextPlanActivatedAt = existingStoredOffer
      ? (existingStoredOffer.planActivatedAt || getFirmLegacyPlanActivationDate(existingStoredOffer) || nowIso)
      : nowIso;
    let nextBillingPlanHistory = existingStoredOffer ? getFirmPlanHistory(existingStoredOffer).slice() : [];
    let nextPendingBillingPlanChange = selectedMatchesPendingPlan ? existingPendingPlanChange : null;
    let nextSubscriptionCommitmentStartMonthKey = existingStoredOffer ? String(existingStoredOffer.subscriptionCommitmentStartMonthKey || "").trim() : "";
    let nextSubscriptionMinimumUntilMonthKey = existingStoredOffer ? String(existingStoredOffer.subscriptionMinimumUntilMonthKey || "").trim() : "";
    let planStatusMessage = "";

    if (existingStoredOffer) {
      if (selectedMatchesPendingPlan) {
        planStatusMessage = buildFirmPendingPlanChangeLabel(existingPendingPlanChange) + " bleibt bestehen.";
      } else if (existingPendingPlanChange && selectedBillingPlan === currentActivePlanKey) {
        nextPendingBillingPlanChange = null;
        planStatusMessage = "Die vorgemerkte Tarifumstellung wurde entfernt. Aktiver Tarif bleibt " + getFirmBillingPlanDefinition(currentActivePlanKey).label + ".";
      } else {
        const planIntent = getFirmPlanChangeIntent(existingStoredOffer, selectedBillingPlan, new Date());
        if (planIntent.mode === "scheduled") {
          nextPendingBillingPlanChange = {
            planKey: planIntent.nextPlan.key,
            effectiveMonthKey: planIntent.effectiveMonthKey,
            effectiveAt: planIntent.effectiveAt,
            contractEndMonthKey: planIntent.contractEndMonthKey,
            contractEndAt: planIntent.contractEndAt,
            requestedAt: nowIso,
            changeKind: planIntent.changeKind
          };
          persistedBillingPlan = currentActivePlanKey;
          planStatusMessage = buildFirmPendingPlanChangeLabel(nextPendingBillingPlanChange) + ". Bis dahin bleibt " + planIntent.currentPlan.label + " aktiv." + (planIntent.changeKind === "cancellation" ? " Die Monatsgebühr wird bis zum Wirksamkeitsdatum anteilig berechnet." : "");
        } else if (planIntent.mode === "immediate") {
          persistedBillingPlan = planIntent.nextPlan.key;
          nextPendingBillingPlanChange = null;
          nextPlanActivatedAt = nowIso;
          if (!documentsChanged && isFirmAccountReleased(existingStoredOffer)) {
            nextBillingPlanHistory.push(buildFirmPlanHistoryEntry(planIntent.nextPlan.key, nowIso, {
              changeKind: planIntent.changeKind,
              requestedAt: nowIso,
              changedAt: nowIso
            }));
          }
          if (doesFirmPlanChargeMonthlyBase(planIntent.nextPlan)) {
            nextSubscriptionCommitmentStartMonthKey = planIntent.effectiveMonthKey || nowMonthKey;
            nextSubscriptionMinimumUntilMonthKey = shiftBillingMonthKey(nextSubscriptionCommitmentStartMonthKey, FIRM_SUBSCRIPTION_MINIMUM_MONTHS - 1);
          } else {
            nextSubscriptionCommitmentStartMonthKey = "";
            nextSubscriptionMinimumUntilMonthKey = "";
          }
          if (planIntent.changeKind === "upgrade") {
            planStatusMessage = "Upgrade auf " + planIntent.nextPlan.label + " ist sofort aktiv. Die Mindestlaufzeit läuft nun bis Ende " + formatBillingMonthLabel(nextSubscriptionMinimumUntilMonthKey) + ".";
          } else if (doesFirmPlanChargeMonthlyBase(planIntent.nextPlan)) {
            planStatusMessage = "Tarifwechsel auf " + planIntent.nextPlan.label + " ist sofort aktiv. Die Mindestlaufzeit läuft nun bis Ende " + formatBillingMonthLabel(nextSubscriptionMinimumUntilMonthKey) + ".";
          } else {
            planStatusMessage = "Tarifwechsel auf " + planIntent.nextPlan.label + " ist sofort aktiv.";
          }
        }
      }
    } else if (doesFirmPlanChargeMonthlyBase(selectedBillingPlan)) {
      planStatusMessage = "Gewählter Monatstarif gespeichert. Die 3-monatige Mindestlaufzeit startet mit der Freischaltung.";
    } else {
      planStatusMessage = "Gewählter Tarif gespeichert.";
    }

    if (nextBillingPlanHistory.length) {
      nextBillingPlanHistory = normalizeFirmPlanHistoryEntries({
        ...(existingStoredOffer || {}),
        billingPlanHistory: nextBillingPlanHistory
      });
    }

    const payload = {
      id: existingStoredOffer && existingStoredOffer.id ? existingStoredOffer.id : uniqueId("FID"),
      firma: firma.trim(),
      userId: firmAuth && firmAuth.id ? firmAuth.id : "",
      userEmail: firmAuth && firmAuth.email ? firmAuth.email : "",
      strasse: strasse.trim(),
      plz: plz.trim(),
      ort: ort.trim(),
      anrede: anrede,
      ansprechpartner: ansprechpartner.trim(),
      ihkMitgliedsnummer: ihkMitgliedsnummer.trim(),
      matchUmkreis: matchUmkreis,
      berufe: berufe,
      platzBehindert: platzBehindert,
      startdatum: startdatum,
      billingPlan: persistedBillingPlan,
      billingPlanHistory: nextBillingPlanHistory,
      pendingBillingPlanChange: nextPendingBillingPlanChange,
      subscriptionCommitmentStartMonthKey: nextSubscriptionCommitmentStartMonthKey,
      subscriptionMinimumUntilMonthKey: nextSubscriptionMinimumUntilMonthKey,
      planActivatedAt: nextPlanActivatedAt,
      paymentApprovedAt: existingStoredOffer
        ? (existingStoredOffer.paymentApprovedAt || "")
        : "",
      firmPaidPlanConfirmationAt: paidPlanConfirmation.required && paidPlanConfirmation.confirmed
        ? paidPlanConfirmation.acceptedAt
        : (existingStoredOffer ? String(existingStoredOffer.firmPaidPlanConfirmationAt || "") : ""),
      firmPaidPlanConfirmationPlanKey: paidPlanConfirmation.required && paidPlanConfirmation.confirmed
        ? paidPlanConfirmation.planKey
        : (existingStoredOffer ? String(existingStoredOffer.firmPaidPlanConfirmationPlanKey || "") : ""),
      firmPaidPlanConfirmationPriceCents: paidPlanConfirmation.required && paidPlanConfirmation.confirmed
        ? paidPlanConfirmation.priceCents
        : (existingStoredOffer && Number.isFinite(existingStoredOffer.firmPaidPlanConfirmationPriceCents)
          ? Number(existingStoredOffer.firmPaidPlanConfirmationPriceCents)
          : 0),
      gewerbeanmeldung: nextGewerbeanmeldung,
      ausbildungDerAusbilder: nextAusbildungDerAusbilder,
      firmenlogo: nextFirmenlogo,
      verified: existingStoredOffer ? !!existingStoredOffer.verified : false,
      paymentApproved: existingStoredOffer
        ? !!existingStoredOffer.paymentApproved
        : false,
      gespeichertAm: nowIso,
      registrierungAbgeschlossen: true
    };

    if (documentsChanged) {
      payload.verified = false;
      payload.paymentApproved = false;
      payload.paymentApprovedAt = "";
    } else if (existingStoredOffer && isFirmAccountReleased(existingStoredOffer)) {
      payload.verified = true;
      payload.paymentApproved = true;
      if (!payload.paymentApprovedAt) {
        payload.paymentApprovedAt = existingStoredOffer.paymentApprovedAt || nowIso;
      }
    } else if (!firmHasAllVerificationDocuments(payload)) {
      payload.verified = false;
      payload.paymentApproved = false;
      payload.paymentApprovedAt = "";
    } else if (payload.verified) {
      payload.paymentApproved = true;
      if (!payload.paymentApprovedAt) {
        payload.paymentApprovedAt = nowIso;
      }
    }

    const filteredOffers = offers.filter(function(offer) {
      return !firmOfferMatchesAuth(offer, firmAuth);
    });
    filteredOffers.unshift(payload);
    saveOffers(filteredOffers);
    if (paidPlanConfirmation && paidPlanConfirmation.required && paidPlanConfirmation.confirmed) {
      try {
        const subscriptionStatusMessage = await maybeSendFirmSubscriptionConfirmation(payload, {
          selectedPlanKey: selectedBillingPlan,
          planIntent: previewPlanIntent,
          acceptedAt: paidPlanConfirmation.acceptedAt,
          referenceOffer: existingStoredOffer || null
        });
        if (subscriptionStatusMessage) {
          planStatusMessage = (planStatusMessage ? (planStatusMessage + " ") : "") + subscriptionStatusMessage;
        }
      } catch (error) {
        const detail = error && typeof error.message === "string" && error.message.trim()
          ? (": " + error.message.trim())
          : ".";
        planStatusMessage = (planStatusMessage ? (planStatusMessage + " ") : "") + "Die Vertragsbestätigung konnte nicht versendet werden" + detail;
      }
    }
    try {
      const registeredFirmUsers = loadRegisteredFirmUsers();
      const linkedUser = registeredFirmUsers.find(function(user) {
        return (firmAuth && firmAuth.id && user.id === firmAuth.id)
          || (firmAuth && firmAuth.email && normalizeText(user.email) === normalizeText(firmAuth.email));
      });
      await maybeSendFirmWelcomeNotification(linkedUser, registeredFirmUsers);
    } catch (err) {
      console.warn("Willkommensmail für Firmen konnte nicht gesendet werden:", err);
    }
    try {
      await maybeSendFirmPossibleMatchNotification(payload, filteredOffers);
    } catch (err) {
      console.warn("Match-Benachrichtigung für Firmen konnte nicht gesendet werden:", err);
    }

    if (out) {
      let statusMessage = "";
      if (documentsChanged) {
        statusMessage = "Hauptprofil aktualisiert. Da Prüfunterlagen geändert wurden, wird die Dokumentenprüfung erneut benötigt.";
      } else if (payload.verified) {
        statusMessage = "Hauptprofil aktualisiert. Die Dokumentenprüfung bleibt bestehen; der Firmenzugang ist direkt freigeschaltet.";
      } else {
        statusMessage = "Angebot mit " + berufe.length + " Beruf(en) gespeichert. Passende Profile sind verfügbar, sobald Ihre Unterlagen geprüft wurden.";
      }
      out.textContent = planStatusMessage ? (statusMessage + " " + planStatusMessage) : statusMessage;
    }

    const redirectToFirmProfile = function() {
      navigateWithTransition("firma_profil.html", "Firmenprofil wird geöffnet...");
    };

    const pendingOfferSync = waitForServerBackedStorageSync(STORAGE_KEYS.offers, 1800);
    if (pendingOfferSync) {
      try {
        await pendingOfferSync;
      } catch (error) {
        console.warn("Angebots-Sync vor Weiterleitung fehlgeschlagen:", error);
      }
    }

    document.getElementById("gewerbeanmeldung").value = "";
    const gewerbeanmeldungStatus = document.getElementById("gewerbeanmeldungStatus");
    if (gewerbeanmeldungStatus) gewerbeanmeldungStatus.textContent = "PDF, JPG oder PNG, max. 5 MB";
    if (gewerbeanmeldungStatus) gewerbeanmeldungStatus.style.color = "#6b7280";

    document.getElementById("ausbildungDerAusbilder").value = "";
    const ausbildungDerAusbilderStatus = document.getElementById("ausbildungDerAusbilderStatus");
    if (ausbildungDerAusbilderStatus) ausbildungDerAusbilderStatus.textContent = "PDF, JPG oder PNG, max. 5 MB";
    if (ausbildungDerAusbilderStatus) ausbildungDerAusbilderStatus.style.color = "#6b7280";

    document.getElementById("firmenlogo").value = "";
    const firmenlogoStatus = document.getElementById("firmenlogoStatus");
    if (firmenlogoStatus) firmenlogoStatus.textContent = "JPG, PNG oder SVG, max. 5 MB";
    if (firmenlogoStatus) firmenlogoStatus.style.color = "#6b7280";

    renderMatches();

    redirectToFirmProfile();
  });
}

const btnAddBeruf = document.getElementById("btnAddBeruf");
const berufInput = document.getElementById("berufInput");
if (btnAddBeruf && berufInput) {
  btnAddBeruf.addEventListener("click", function() {
    const beruf = berufInput.value || "";
    if (!beruf.trim()) {
      // alert("Bitte einen Ausbildungsberuf eingeben.");
      return;
    }
    addBeruf(beruf);
    berufInput.value = "";
    attachBeruflChangeListeners();
  });
  berufInput.addEventListener("keypress", function(e) {
    if (e.key === "Enter") {
      btnAddBeruf.click();
    }
  });
}

const berufliste = document.getElementById("berufliste");
if (berufliste) {
  attachBeruflChangeListeners();
}

function attachBeruflChangeListeners() {
  const removeButtons = document.querySelectorAll(".beruf-remove-btn");
  removeButtons.forEach(function(btn) {
    btn.removeEventListener("click", handleBeruflRemove);
    btn.addEventListener("click", handleBeruflRemove);
  });
}

function handleBeruflRemove(e) {
  e.preventDefault();
  const item = e.target.closest(".beruf-item");
  if (item) {
    item.remove();
    const container = document.getElementById("berufliste");
    if (container && !container.querySelector(".beruf-item")) {
      container.innerHTML = "<p class='status' style='color: #94a3b8; font-size: 0.9rem;'>Keine Berufe hinzugefügt. Bitte oben einen Beruf eintragen und ➕ klicken.</p>";
    }
  }
}

function normalizeProfessionCollection(values) {
  const list = [];
  (Array.isArray(values) ? values : []).forEach(function(entry) {
    const trimmed = String(entry || "").trim();
    if (!trimmed) return;
    const exists = list.some(function(candidate) {
      return normalizeProfessionText(candidate) === normalizeProfessionText(trimmed);
    });
    if (!exists) {
      list.push(trimmed);
    }
  });
  return list;
}

const INTERNSHIP_WEEKDAY_OPTIONS = [
  { value: "monday", shortLabel: "Mo", label: "Montag" },
  { value: "tuesday", shortLabel: "Di", label: "Dienstag" },
  { value: "wednesday", shortLabel: "Mi", label: "Mittwoch" },
  { value: "thursday", shortLabel: "Do", label: "Donnerstag" },
  { value: "friday", shortLabel: "Fr", label: "Freitag" },
  { value: "saturday", shortLabel: "Sa", label: "Samstag" }
];

const INTERNSHIP_WEEKDAY_LABELS = INTERNSHIP_WEEKDAY_OPTIONS.reduce(function(result, entry) {
  result[entry.value] = entry;
  return result;
}, {});

const INTERNSHIP_TIME_SLOT_OPTIONS = [
  { value: "morning", label: "Vormittags" },
  { value: "afternoon", label: "Nachmittags" }
];

const INTERNSHIP_TIME_SLOT_LABELS = INTERNSHIP_TIME_SLOT_OPTIONS.reduce(function(result, entry) {
  result[entry.value] = entry;
  return result;
}, {});

function normalizeInternshipWeekdays(values) {
  const rawValues = Array.isArray(values)
    ? values
    : (typeof values === "string" ? values.split(",") : []);
  const normalized = [];

  INTERNSHIP_WEEKDAY_OPTIONS.forEach(function(option) {
    const hasValue = rawValues.some(function(entry) {
      const normalizedEntry = normalizeText(entry);
      return normalizedEntry === option.value || normalizedEntry === normalizeText(option.label);
    });
    if (hasValue) {
      normalized.push(option.value);
    }
  });

  return normalized;
}

function getCheckedInternshipWeekdays(fieldName, root) {
  const scope = root instanceof Element ? root : document;
  return normalizeInternshipWeekdays(
    Array.from(scope.querySelectorAll('input[name="' + String(fieldName || "") + '"]:checked')).map(function(input) {
      return input.value;
    })
  );
}

function setCheckedInternshipWeekdays(fieldName, values, root) {
  const scope = root instanceof Element ? root : document;
  const normalizedValues = normalizeInternshipWeekdays(values);
  Array.from(scope.querySelectorAll('input[name="' + String(fieldName || "") + '"]')).forEach(function(input) {
    input.checked = normalizedValues.includes(String(input.value || "").trim());
  });
}

function normalizeInternshipTimeSlots(values) {
  const rawValues = Array.isArray(values)
    ? values
    : (typeof values === "string" ? values.split(",") : []);
  const normalized = [];

  INTERNSHIP_TIME_SLOT_OPTIONS.forEach(function(option) {
    const hasValue = rawValues.some(function(entry) {
      const normalizedEntry = normalizeText(entry);
      return normalizedEntry === option.value || normalizedEntry === normalizeText(option.label);
    });
    if (hasValue) {
      normalized.push(option.value);
    }
  });

  return normalized;
}

function getCheckedInternshipTimeSlots(fieldName, root) {
  const scope = root instanceof Element ? root : document;
  return normalizeInternshipTimeSlots(
    Array.from(scope.querySelectorAll('input[name="' + String(fieldName || "") + '"]:checked')).map(function(input) {
      return input.value;
    })
  );
}

function setCheckedInternshipTimeSlots(fieldName, values, root) {
  const scope = root instanceof Element ? root : document;
  const normalizedValues = normalizeInternshipTimeSlots(values);
  Array.from(scope.querySelectorAll('input[name="' + String(fieldName || "") + '"]')).forEach(function(input) {
    input.checked = normalizedValues.includes(String(input.value || "").trim());
  });
}

const INTERNSHIP_DATEPICKER_CSS_URL = "https://cdn.jsdelivr.net/npm/flatpickr@4.6.13/dist/flatpickr.min.css";
const INTERNSHIP_DATEPICKER_JS_URL = "https://cdn.jsdelivr.net/npm/flatpickr@4.6.13/dist/flatpickr.min.js";
const INTERNSHIP_DATEPICKER_LOCALE_URL = "https://cdn.jsdelivr.net/npm/flatpickr@4.6.13/dist/l10n/de.js";

let internshipDatepickerReadyPromise = null;

function buildInternshipIsoDateValue(yearValue, monthValue, dayValue) {
  const year = Number(yearValue);
  const month = Number(monthValue);
  const day = Number(dayValue);
  if (!Number.isInteger(year) || !Number.isInteger(month) || !Number.isInteger(day)) return "";
  if (month < 1 || month > 12 || day < 1 || day > 31) return "";

  const normalized = String(year).padStart(4, "0")
    + "-" + String(month).padStart(2, "0")
    + "-" + String(day).padStart(2, "0");
  const asDate = new Date(normalized + "T00:00:00");
  if (Number.isNaN(asDate.getTime())) return "";
  if (asDate.getFullYear() !== year || asDate.getMonth() + 1 !== month || asDate.getDate() !== day) return "";
  return normalized;
}

function normalizeInternshipDateValue(value) {
  const trimmed = String(value || "").trim();
  if (!trimmed) return "";

  const isoMatch = trimmed.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (isoMatch) {
    return buildInternshipIsoDateValue(isoMatch[1], isoMatch[2], isoMatch[3]);
  }

  const germanMatch = trimmed.match(/^(\d{1,2})\.(\d{1,2})\.(\d{4})$/);
  if (germanMatch) {
    return buildInternshipIsoDateValue(germanMatch[3], germanMatch[2], germanMatch[1]);
  }

  return "";
}

function formatInternshipDateValue(value) {
  const normalizedValue = normalizeInternshipDateValue(value);
  if (!normalizedValue) return "";
  const asDate = new Date(normalizedValue + "T00:00:00");
  if (Number.isNaN(asDate.getTime())) return normalizedValue;
  return asDate.toLocaleDateString("de-DE", {
    day: "2-digit",
    month: "2-digit",
    year: "numeric"
  });
}

function formatInternshipDateRange(startDate, endDate) {
  const normalizedStart = normalizeInternshipDateValue(startDate);
  const normalizedEnd = normalizeInternshipDateValue(endDate);
  if (!normalizedStart || !normalizedEnd) return "";
  return formatInternshipDateValue(normalizedStart) + " bis " + formatInternshipDateValue(normalizedEnd);
}

function formatInternshipWeekdayList(values, emptyLabel) {
  const labels = normalizeInternshipWeekdays(values).map(function(value) {
    return INTERNSHIP_WEEKDAY_LABELS[value] ? INTERNSHIP_WEEKDAY_LABELS[value].label : value;
  });
  return labels.length ? labels.join(", ") : String(emptyLabel || "Keine festen Tage");
}

function formatInternshipTimeSlotList(values, emptyLabel) {
  const normalizedValues = normalizeInternshipTimeSlots(values);
  if (!normalizedValues.length) {
    return String(emptyLabel || "Keine Tageszeit gewählt");
  }
  if (normalizedValues.length === INTERNSHIP_TIME_SLOT_OPTIONS.length) {
    return "Vormittags und nachmittags";
  }
  return normalizedValues.map(function(value) {
    return INTERNSHIP_TIME_SLOT_LABELS[value] ? INTERNSHIP_TIME_SLOT_LABELS[value].label : value;
  }).join(", ");
}

function validateInternshipAvailabilityInput(options) {
  const config = options || {};
  const rawStartDate = String(config.startDate || "").trim();
  const rawEndDate = String(config.endDate || "").trim();
  const startDate = normalizeInternshipDateValue(rawStartDate);
  const endDate = normalizeInternshipDateValue(rawEndDate);
  const days = normalizeInternshipWeekdays(config.days);
  const timeSlots = normalizeInternshipTimeSlots(config.timeSlots);
  const hasPartialDate = (!!rawStartDate || !!rawEndDate) && (!startDate || !endDate);

  if (hasPartialDate) {
    return {
      ok: false,
      message: config.partialMessage || "Bitte vervollständige Start- und Enddatum oder entferne die unvollständige Zeitraumangabe."
    };
  }

  if (startDate && endDate && startDate > endDate) {
    return {
      ok: false,
      message: config.orderMessage || "Das Enddatum muss nach dem Startdatum liegen."
    };
  }

  if (config.requireAvailability && !startDate && !endDate && !days.length && !timeSlots.length) {
    return {
      ok: false,
      message: config.requiredMessage || "Bitte gib mindestens einen Zeitraum, feste Tage oder eine Tageszeit an."
    };
  }

  return {
    ok: true,
    startDate: startDate,
    endDate: endDate,
    days: days,
    timeSlots: timeSlots,
    hasRange: !!(startDate && endDate),
    hasDays: !!days.length,
    hasTimeSlots: !!timeSlots.length
  };
}

function ensureInternshipDatepickerStylesheet() {
  if (typeof document === "undefined" || !document.head) return;
  if (document.querySelector('link[data-internship-datepicker-style="1"]')) return;

  const link = document.createElement("link");
  link.rel = "stylesheet";
  link.href = INTERNSHIP_DATEPICKER_CSS_URL;
  link.dataset.internshipDatepickerStyle = "1";
  document.head.appendChild(link);
}

function loadInternshipDatepickerScript(src) {
  if (typeof document === "undefined" || !document.head) {
    return Promise.resolve(false);
  }

  return new Promise(function(resolve, reject) {
    const existing = document.querySelector('script[data-internship-datepicker-script="' + src + '"]');
    if (existing) {
      if (existing.dataset.loaded === "1") {
        resolve(true);
        return;
      }
      existing.addEventListener("load", function() {
        resolve(true);
      }, { once: true });
      existing.addEventListener("error", function() {
        reject(new Error("Konnte Script nicht laden: " + src));
      }, { once: true });
      return;
    }

    const script = document.createElement("script");
    script.src = src;
    script.async = false;
    script.dataset.internshipDatepickerScript = src;
    script.addEventListener("load", function() {
      script.dataset.loaded = "1";
      resolve(true);
    }, { once: true });
    script.addEventListener("error", function() {
      reject(new Error("Konnte Script nicht laden: " + src));
    }, { once: true });
    document.head.appendChild(script);
  });
}

function ensureInternshipDatepickerReady() {
  ensureInternshipDatepickerStylesheet();

  if (typeof window !== "undefined" && typeof window.flatpickr === "function") {
    return Promise.resolve(true);
  }

  if (internshipDatepickerReadyPromise) {
    return internshipDatepickerReadyPromise;
  }

  internshipDatepickerReadyPromise = loadInternshipDatepickerScript(INTERNSHIP_DATEPICKER_JS_URL)
    .then(function() {
      return loadInternshipDatepickerScript(INTERNSHIP_DATEPICKER_LOCALE_URL).catch(function() {
        return false;
      });
    })
    .then(function() {
      return typeof window !== "undefined" && typeof window.flatpickr === "function";
    })
    .catch(function() {
      return false;
    });

  return internshipDatepickerReadyPromise;
}

function prepareInternshipDateInput(input) {
  if (!(input instanceof HTMLInputElement)) return;
  if (input.dataset.internshipDatePrepared === "1") return;

  input.dataset.internshipDateOriginalType = input.getAttribute("type") || input.type || "date";
  input.dataset.internshipDatePrepared = "1";
  input.type = "text";
  input.autocomplete = "off";
  input.setAttribute("inputmode", "none");
  if (!input.placeholder) {
    input.placeholder = "TT.MM.JJJJ";
  }
}

function restoreNativeInternshipDateInput(input) {
  if (!(input instanceof HTMLInputElement)) return;
  if (input._flatpickr) return;

  const originalType = input.dataset.internshipDateOriginalType || input.getAttribute("type") || input.type || "date";
  input.type = originalType === "text" ? "date" : originalType;
  input.autocomplete = "off";
  input.removeAttribute("inputmode");
  if (input.placeholder === "TT.MM.JJJJ") {
    input.removeAttribute("placeholder");
  }
  delete input.dataset.internshipDatePrepared;
}

function getInternshipDatepickerLocale() {
  if (typeof window !== "undefined"
    && typeof window.flatpickr === "function"
    && window.flatpickr.l10ns
    && window.flatpickr.l10ns.de) {
    return window.flatpickr.l10ns.de;
  }
  return "de";
}

function initInternshipDateInput(input) {
  if (!(input instanceof HTMLInputElement)) return null;
  if (typeof window === "undefined" || typeof window.flatpickr !== "function") return null;

  prepareInternshipDateInput(input);

  let picker = null;
  try {
    picker = input._flatpickr || window.flatpickr(input, {
      locale: getInternshipDatepickerLocale(),
      dateFormat: "Y-m-d",
      altInput: true,
      altFormat: "d.m.Y",
      altInputClass: "input internship-date-display",
      allowInput: false,
      disableMobile: true,
      monthSelectorType: "static",
      nextArrow: "›",
      prevArrow: "‹"
    });
  } catch (error) {
    restoreNativeInternshipDateInput(input);
    return null;
  }

  if (picker && picker.altInput instanceof HTMLInputElement) {
    picker.altInput.readOnly = true;
    picker.altInput.autocomplete = "off";
    picker.altInput.setAttribute("inputmode", "none");
    if (!picker.altInput.placeholder) {
      picker.altInput.placeholder = "TT.MM.JJJJ";
    }
  }

  return picker;
}

function setInternshipDateInputValue(input, value) {
  if (!(input instanceof HTMLInputElement)) return;

  const normalizedValue = normalizeInternshipDateValue(value);

  if (input._flatpickr) {
    input._flatpickr.setDate(normalizedValue || "", false, "Y-m-d");
    return;
  }

  input.value = normalizedValue || "";
}

function bindInternshipDateRange(startInput, endInput) {
  if (!(startInput instanceof HTMLInputElement) || !(endInput instanceof HTMLInputElement)) return;

  const syncBounds = function() {
    const startValue = normalizeInternshipDateValue(startInput.value);
    const endValue = normalizeInternshipDateValue(endInput.value);

    startInput.max = endValue || "";
    endInput.min = startValue || "";

    if (startInput._flatpickr) {
      startInput._flatpickr.set("maxDate", endValue || null);
    }
    if (endInput._flatpickr) {
      endInput._flatpickr.set("minDate", startValue || null);
    }
  };

  if (startInput.dataset.internshipDateRangeBound !== "1") {
    startInput.dataset.internshipDateRangeBound = "1";
    endInput.dataset.internshipDateRangeBound = "1";
    startInput.addEventListener("change", syncBounds);
    endInput.addEventListener("change", syncBounds);
  }

  ensureInternshipDatepickerReady().then(function(isReady) {
    if (!isReady) {
      restoreNativeInternshipDateInput(startInput);
      restoreNativeInternshipDateInput(endInput);
      syncBounds();
      return;
    }

    initInternshipDateInput(startInput);
    initInternshipDateInput(endInput);
    setInternshipDateInputValue(startInput, startInput.value);
    setInternshipDateInputValue(endInput, endInput.value);
    syncBounds();
  });
}

function buildInternshipAvailabilityLabel(entryArg, options) {
  const entry = entryArg && typeof entryArg === "object" ? entryArg : {};
  const config = options || {};
  const startDate = normalizeInternshipDateValue(config.startDate || entry.praktikumStartdatum);
  const endDate = normalizeInternshipDateValue(config.endDate || entry.praktikumEnddatum);
  const days = normalizeInternshipWeekdays(config.days || entry.praktikumTage);
  const timeSlots = normalizeInternshipTimeSlots(config.timeSlots != null ? config.timeSlots : entry.praktikumZeitfenster);
  const note = String(config.note != null ? config.note : (entry.praktikumZeitraum || "")).trim();
  const parts = [];

  if (startDate && endDate) {
    parts.push(formatInternshipDateRange(startDate, endDate));
  }

  if (days.length) {
    parts.push("Tage: " + formatInternshipWeekdayList(days, ""));
  }

  if (timeSlots.length) {
    parts.push("Tageszeit: " + formatInternshipTimeSlotList(timeSlots, ""));
  }

  if (note) {
    parts.push(note);
  }

  return parts.length ? parts.join(" • ") : String(config.fallback || "Noch keine Zeitangaben hinterlegt.");
}

function evaluateInternshipScheduleFit(studentArg, offerArg) {
  const student = studentArg && typeof studentArg === "object" ? studentArg : {};
  const offer = offerArg && typeof offerArg === "object" ? offerArg : {};
  const studentStart = normalizeInternshipDateValue(student.praktikumStartdatum);
  const studentEnd = normalizeInternshipDateValue(student.praktikumEnddatum);
  const offerStart = normalizeInternshipDateValue(offer.praktikumStartdatum);
  const offerEnd = normalizeInternshipDateValue(offer.praktikumEnddatum);
  const studentDays = normalizeInternshipWeekdays(student.praktikumTage);
  const offerDays = normalizeInternshipWeekdays(offer.praktikumTage);
  const studentTimeSlots = normalizeInternshipTimeSlots(student.praktikumZeitfenster);
  const offerTimeSlots = normalizeInternshipTimeSlots(offer.praktikumZeitfenster);
  const sharedDays = studentDays.filter(function(day) {
    return offerDays.includes(day);
  });
  const sharedTimeSlots = studentTimeSlots.filter(function(slot) {
    return offerTimeSlots.includes(slot);
  });

  let overlapStart = "";
  let overlapEnd = "";
  let dateState = "unknown";
  let dayState = "unknown";
  let timeState = "unknown";

  if (studentStart && studentEnd && offerStart && offerEnd) {
    overlapStart = studentStart > offerStart ? studentStart : offerStart;
    overlapEnd = studentEnd < offerEnd ? studentEnd : offerEnd;
    dateState = overlapStart <= overlapEnd ? "fit" : "conflict";
  } else if (studentStart && studentEnd) {
    dateState = "student-only";
  } else if (offerStart && offerEnd) {
    dateState = "offer-only";
  }

  if (studentDays.length && offerDays.length) {
    dayState = sharedDays.length ? "fit" : "conflict";
  } else if (studentDays.length) {
    dayState = "student-only";
  } else if (offerDays.length) {
    dayState = "offer-only";
  }

  if (studentTimeSlots.length && offerTimeSlots.length) {
    timeState = sharedTimeSlots.length ? "fit" : "conflict";
  } else if (studentTimeSlots.length) {
    timeState = "student-only";
  } else if (offerTimeSlots.length) {
    timeState = "offer-only";
  }

  let state = "pending";
  let label = "Kalenderplanung offen";
  let detail = "Ergänzen Sie auf beiden Seiten Zeitraum, feste Tage oder eine Tageszeit, damit der Termin-Fit klar bewertet werden kann.";

  if (dateState === "conflict" || dayState === "conflict" || timeState === "conflict") {
    state = "conflict";
    label = "Termin-Fit unklar";
    detail = dateState === "conflict"
      ? "Die angegebenen Zeiträume überschneiden sich aktuell nicht."
      : (dayState === "conflict"
        ? "Die festen Tage überschneiden sich aktuell nicht. Bitte Termin oder Wochentage abstimmen."
        : "Die gewählten Tageszeiten überschneiden sich aktuell nicht. Bitte Vormittag oder Nachmittag abstimmen.");
  } else if (dateState === "fit" && dayState === "fit" && timeState === "fit") {
    state = "fit";
    label = "Zeiten passen";
    detail = "Zeitraum, feste Tage und Tageszeit überschneiden sich. Gemeinsame Tage: "
      + formatInternshipWeekdayList(sharedDays, "-")
      + ". Gemeinsame Tageszeit: "
      + formatInternshipTimeSlotList(sharedTimeSlots, "-")
      + ".";
  } else if (dateState === "fit" && dayState === "fit") {
    state = "fit";
    label = "Zeitraum passt";
    detail = "Zeitraum und feste Tage überschneiden sich. Gemeinsame Tage: " + formatInternshipWeekdayList(sharedDays, "-") + ". Die Tageszeit kann bei Bedarf noch abgestimmt werden.";
  } else if (dateState === "fit" && timeState === "fit") {
    state = "fit";
    label = "Zeitraum passt";
    detail = "Zeitraum und Tageszeit passen zusammen. Ergänzen Sie für die genaue Planung bei Bedarf noch feste Tage.";
  } else if (dayState === "fit" && timeState === "fit") {
    state = "fit";
    label = "Zeiten passen";
    detail = "Feste Tage und Tageszeit passen bereits zusammen. Ergänzen Sie für die genaue Planung noch einen Zeitraum.";
  } else if (dateState === "fit") {
    state = "fit";
    label = "Zeitraum passt";
    detail = "Die Zeiträume überschneiden sich. Feste Tage können bei Bedarf noch abgestimmt werden.";
  } else if (dayState === "fit") {
    state = "fit";
    label = "Tage passen";
    detail = "Die festen Tage überschneiden sich bereits. Ergänzen Sie für die genaue Planung noch einen Zeitraum.";
  } else if (timeState === "fit") {
    state = "fit";
    label = "Tageszeit passt";
    detail = "Die ausgewählten Tageszeiten überschneiden sich bereits. Ergänzen Sie für die genaue Planung noch Zeitraum oder feste Tage.";
  } else if ((studentStart && studentEnd) || studentDays.length || studentTimeSlots.length) {
    state = "pending";
    label = "Betriebsplanung ergänzen";
    detail = "Der Schüler hat bereits Zeitangaben hinterlegt. Ergänzen Sie im Betrieb Zeitraum, feste Tage oder eine Tageszeit, damit der Kalender-Fit sichtbar wird.";
  } else if ((offerStart && offerEnd) || offerDays.length || offerTimeSlots.length) {
    state = "pending";
    label = "Schüler-Zeiten fehlen";
    detail = "Für dieses Match fehlen auf Schülerseite noch strukturierte Zeitangaben. Ohne Zeitraum, feste Tage oder Tageszeit ist keine belastbare Kalenderplanung möglich.";
  }

  return {
    state: state,
    label: label,
    detail: detail,
    chipClass: state === "fit"
      ? "firm-match-chip--schedule-fit"
      : (state === "conflict" ? "firm-match-chip--schedule-conflict" : "firm-match-chip--schedule-pending"),
    studentAvailability: buildInternshipAvailabilityLabel(student, { fallback: "Schüler hat noch keine strukturierten Zeitangaben hinterlegt." }),
    offerAvailability: buildInternshipAvailabilityLabel(offer, { fallback: "Im Betrieb ist noch keine strukturierte Planung hinterlegt." }),
    sharedDays: sharedDays,
    sharedTimeSlots: sharedTimeSlots,
    overlapStart: dateState === "fit" ? overlapStart : "",
    overlapEnd: dateState === "fit" ? overlapEnd : ""
  };
}

function getInternshipStudentScheduleKey(studentArg) {
  const student = studentArg && typeof studentArg === "object" ? studentArg : {};
  return String(student.id || student.profilCode || student.baseStudentId || student.userId || student.userEmail || "").trim();
}

function loadInternshipCalendarEntries() {
  return readJson(STORAGE_KEYS.internshipCalendarEntries, []);
}

function saveInternshipCalendarEntries(list) {
  writeJson(STORAGE_KEYS.internshipCalendarEntries, Array.isArray(list) ? list : []);
}

function resolveInternshipCalendarEntry(entry, authArg) {
  const auth = authArg || getStoredFirmAuth();
  const data = entry && typeof entry === "object" ? entry : {};
  return {
    ...data,
    id: String(data.id || uniqueId("praktikum_kalender")).trim(),
    firmUserId: String(data.firmUserId || (auth && auth.id) || "").trim(),
    firmUserEmail: String(data.firmUserEmail || (auth && auth.email) || "").trim(),
    studentId: String(data.studentId || "").trim(),
    studentName: String(data.studentName || "").trim(),
    profession: String(data.profession || "").trim(),
    startDate: normalizeInternshipDateValue(data.startDate),
    endDate: normalizeInternshipDateValue(data.endDate),
    days: normalizeInternshipWeekdays(data.days),
    note: String(data.note || "").trim(),
    processCompleted: !!data.processCompleted,
    createdAt: data.createdAt || new Date().toISOString(),
    updatedAt: data.updatedAt || data.createdAt || new Date().toISOString()
  };
}

function loadFirmInternshipCalendarEntries(authArg) {
  const auth = authArg || getStoredFirmAuth();
  if (!auth) return [];
  return loadInternshipCalendarEntries()
    .map(function(entry) {
      return resolveInternshipCalendarEntry(entry, auth);
    })
    .filter(function(entry) {
      return entry.firmUserId === auth.id || normalizeText(entry.firmUserEmail) === normalizeText(auth.email);
    })
    .sort(function(left, right) {
      const leftDate = normalizeInternshipDateValue(left.startDate) || String(left.updatedAt || "");
      const rightDate = normalizeInternshipDateValue(right.startDate) || String(right.updatedAt || "");
      return String(leftDate).localeCompare(String(rightDate));
    });
}

function findFirmInternshipCalendarEntry(studentId, authArg) {
  const targetId = String(studentId || "").trim();
  if (!targetId) return null;
  return loadFirmInternshipCalendarEntries(authArg).find(function(entry) {
    return String(entry.studentId || "").trim() === targetId;
  }) || null;
}

function buildFirmInternshipCalendarDraft(matchEntry, authArg) {
  const auth = authArg || getStoredFirmAuth();
  const student = matchEntry && matchEntry.student ? matchEntry.student : {};
  const offer = matchEntry && matchEntry.offer ? matchEntry.offer : {};
  const studentId = getInternshipStudentScheduleKey(student);
  const existingEntry = findFirmInternshipCalendarEntry(studentId, auth);
  const scheduleFit = matchEntry && matchEntry.scheduleFit
    ? matchEntry.scheduleFit
    : evaluateInternshipScheduleFit(student, offer);
  const defaultDays = existingEntry && existingEntry.days.length
    ? existingEntry.days
    : (scheduleFit.sharedDays.length ? scheduleFit.sharedDays : (student.praktikumTage && student.praktikumTage.length ? student.praktikumTage : offer.praktikumTage));

  return {
    entryId: existingEntry ? existingEntry.id : "",
    studentId: studentId,
    studentName: String(student.name || student.profilCode || "Profil").trim(),
    profession: String(matchEntry && matchEntry.matchedProfession || student.beruf || "Praktikumsbereich").trim(),
    startDate: normalizeInternshipDateValue(existingEntry ? existingEntry.startDate : (scheduleFit.overlapStart || student.praktikumStartdatum || offer.praktikumStartdatum)),
    endDate: normalizeInternshipDateValue(existingEntry ? existingEntry.endDate : (scheduleFit.overlapEnd || student.praktikumEnddatum || offer.praktikumEnddatum)),
    days: normalizeInternshipWeekdays(defaultDays),
    note: String(existingEntry ? existingEntry.note : (student.praktikumHinweis || offer.praktikumHinweis || "")).trim(),
    processCompleted: existingEntry ? !!existingEntry.processCompleted : false,
    availabilityText: "Schüler: " + scheduleFit.studentAvailability + " | Betrieb: " + scheduleFit.offerAvailability,
    statusText: existingEntry
      ? "Kalendereintrag geladen. Sie können ihn jetzt anpassen."
      : "Matchdaten in die Kalenderplanung übernommen. Prüfen Sie Zeitraum und feste Tage vor dem Speichern."
  };
}

function getInternshipSchedulePriority(scheduleFitArg) {
  const scheduleFit = scheduleFitArg && typeof scheduleFitArg === "object" ? scheduleFitArg : {};
  if (scheduleFit.state === "fit") return 4;
  if (scheduleFit.state === "pending") return 1;
  if (scheduleFit.state === "conflict") return -2;
  return 0;
}

function enrichInternshipMatchEntry(entryArg, authArg) {
  const entry = entryArg && typeof entryArg === "object" ? entryArg : {};
  const student = entry.student ? resolveInternshipStudentRecord(entry.student) : null;
  const offer = entry.offer ? resolveInternshipOfferRecord(entry.offer, authArg) : null;
  const scheduleFit = student && offer ? evaluateInternshipScheduleFit(student, offer) : evaluateInternshipScheduleFit({}, {});
  const schedulePriority = getInternshipSchedulePriority(scheduleFit);
  const studentId = student ? getInternshipStudentScheduleKey(student) : "";

  return {
    ...entry,
    student: student || entry.student,
    offer: offer || entry.offer,
    scheduleFit: scheduleFit,
    schedulePriority: schedulePriority,
    combinedScore: Number(entry.score || 0) + schedulePriority,
    calendarEntry: studentId ? findFirmInternshipCalendarEntry(studentId, authArg) : null
  };
}

function findInternshipStudentRecordByScheduleKey(studentId) {
  const targetId = String(studentId || "").trim();
  if (!targetId) return null;
  return loadInternshipStudents().map(function(entry) {
    return resolveInternshipStudentRecord(entry);
  }).find(function(entry) {
    return getInternshipStudentScheduleKey(entry) === targetId;
  }) || null;
}

function getFirmInternshipCalendarElements() {
  const section = document.getElementById("firmInternshipCalendarSection");
  const planner = document.getElementById("firmInternshipCalendarPlanner");
  const studentName = document.getElementById("firmInternshipCalendarStudentName");
  const availability = document.getElementById("firmInternshipCalendarAvailability");
  const entryIdInput = document.getElementById("firmInternshipCalendarEntryId");
  const studentIdInput = document.getElementById("firmInternshipCalendarStudentId");
  const studentNameValueInput = document.getElementById("firmInternshipCalendarStudentNameValue");
  const professionValueInput = document.getElementById("firmInternshipCalendarProfessionValue");
  const startDateInput = document.getElementById("firmInternshipCalendarStartDate");
  const endDateInput = document.getElementById("firmInternshipCalendarEndDate");
  const noteInput = document.getElementById("firmInternshipCalendarNote");
  const processCheckbox = document.getElementById("firmInternshipCalendarProcessComplete");
  const saveButton = document.getElementById("saveFirmInternshipCalendarEntry");
  const resetButton = document.getElementById("resetFirmInternshipCalendarPlanner");
  const exportActions = document.getElementById("firmInternshipCalendarExportActions");
  const outlookLink = document.getElementById("firmInternshipCalendarOutlookLink");
  const googleLink = document.getElementById("firmInternshipCalendarGoogleLink");
  const icsButton = document.getElementById("downloadFirmInternshipCalendarIcs");
  const planNote = document.getElementById("firmInternshipCalendarPlanNote");
  const status = document.getElementById("firmInternshipCalendarStatus");
  const entries = document.getElementById("firmInternshipCalendarEntries");
  const occupancy = document.getElementById("firmInternshipOccupancyCalendar");

  if (!section || !planner || !studentName || !availability || !entryIdInput || !studentIdInput || !studentNameValueInput || !professionValueInput || !startDateInput || !endDateInput || !noteInput || !processCheckbox || !saveButton || !resetButton || !status || !entries) {
    return null;
  }

  return {
    section: section,
    planner: planner,
    studentName: studentName,
    availability: availability,
    entryIdInput: entryIdInput,
    studentIdInput: studentIdInput,
    studentNameValueInput: studentNameValueInput,
    professionValueInput: professionValueInput,
    startDateInput: startDateInput,
    endDateInput: endDateInput,
    noteInput: noteInput,
    processCheckbox: processCheckbox,
    saveButton: saveButton,
    resetButton: resetButton,
    exportActions: exportActions,
    outlookLink: outlookLink,
    googleLink: googleLink,
    icsButton: icsButton,
    planNote: planNote,
    status: status,
    entries: entries,
    occupancy: occupancy
  };
}

function buildCurrentFirmInternshipCalendarPlannerEntry(authArg) {
  const elements = getFirmInternshipCalendarElements();
  if (!elements) return null;

  const studentId = String(elements.studentIdInput.value || "").trim();
  const studentName = String(elements.studentNameValueInput.value || "").trim();
  const startDate = normalizeInternshipDateValue(elements.startDateInput.value);
  const endDate = normalizeInternshipDateValue(elements.endDateInput.value);

  if (!studentId || !studentName || !startDate || !endDate) return null;

  return resolveInternshipCalendarEntry({
    id: String(elements.entryIdInput.value || "planner-" + studentId).trim(),
    studentId: studentId,
    studentName: studentName,
    profession: String(elements.professionValueInput.value || "").trim(),
    startDate: startDate,
    endDate: endDate,
    days: getCheckedInternshipWeekdays("firmInternshipCalendarDays", elements.planner),
    note: elements.noteInput.value.trim(),
    processCompleted: elements.processCheckbox.checked
  }, authArg || getStoredFirmAuth());
}

function updateFirmInternshipCalendarExportActions(authArg) {
  const elements = getFirmInternshipCalendarElements();
  if (!elements || !(elements.exportActions instanceof HTMLElement) || !(elements.outlookLink instanceof HTMLAnchorElement) || !(elements.googleLink instanceof HTMLAnchorElement) || !(elements.icsButton instanceof HTMLButtonElement)) {
    return;
  }

  const auth = authArg || getStoredFirmAuth();
  const liveOffer = auth ? (findFirmOfferByAuth(auth, loadOffers()) || null) : null;
  const calendarCapabilities = getFirmCalendarCapabilities(liveOffer);
  const plannerEntry = buildCurrentFirmInternshipCalendarPlannerEntry(auth);
  const calendarOptions = { auth: auth };
  const meta = plannerEntry ? buildInternshipCalendarEntryMeta(plannerEntry, calendarOptions) : null;
  const outlookUrl = meta ? buildInternshipCalendarEntryOutlookUrl(plannerEntry, calendarOptions) : "";
  const googleUrl = meta ? buildInternshipCalendarEntryGoogleCalendarUrl(plannerEntry, calendarOptions) : "";
  const hasOutlookAction = !!(meta && calendarCapabilities.internshipExternalLinksEnabled && outlookUrl);
  const hasGoogleAction = !!(meta && calendarCapabilities.internshipExternalLinksEnabled && googleUrl);
  const hasIcsAction = !!(meta && calendarCapabilities.internshipIcsEnabled);
  const hasExportActions = !!(calendarCapabilities.internshipPlannerEnabled && (hasOutlookAction || hasGoogleAction || hasIcsAction));

  elements.exportActions.hidden = !hasExportActions;
  elements.outlookLink.hidden = !hasOutlookAction;
  elements.googleLink.hidden = !hasGoogleAction;
  elements.icsButton.hidden = !hasIcsAction;

  if (hasOutlookAction) {
    elements.outlookLink.href = outlookUrl;
  } else {
    elements.outlookLink.removeAttribute("href");
  }

  if (hasGoogleAction) {
    elements.googleLink.href = googleUrl;
  } else {
    elements.googleLink.removeAttribute("href");
  }
}

function getTodayInternshipDateValue() {
  const today = new Date();
  return buildInternshipIsoDateValue(today.getFullYear(), today.getMonth() + 1, today.getDate());
}

function getFirmInternshipCalendarOccupancyStatus(entryArg, todayValueArg) {
  const entry = resolveInternshipCalendarEntry(entryArg);
  const todayValue = normalizeInternshipDateValue(todayValueArg) || getTodayInternshipDateValue();

  if (!entry.startDate || !entry.endDate) {
    return { key: "planned", label: "Geplant" };
  }
  if (todayValue && todayValue < entry.startDate) {
    return { key: "upcoming", label: "Bevorstehend" };
  }
  if (todayValue && todayValue > entry.endDate) {
    return { key: "completed", label: "Abgeschlossen" };
  }
  return { key: "active", label: "Belegt" };
}

function formatFirmInternshipOccupancyMonthLabel(dateValue) {
  const normalizedDate = normalizeInternshipDateValue(dateValue);
  if (!normalizedDate) return "Ohne Datumsangabe";

  const monthDate = new Date(normalizedDate.slice(0, 7) + "-01T00:00:00");
  if (Number.isNaN(monthDate.getTime())) return normalizedDate;

  return monthDate.toLocaleDateString("de-DE", {
    month: "long",
    year: "numeric"
  });
}

function renderFirmInternshipOccupancyCalendar(entriesArg, optionsArg) {
  const elements = getFirmInternshipCalendarElements();
  const container = elements && elements.occupancy;
  if (!(container instanceof HTMLElement)) return;

  const options = optionsArg && typeof optionsArg === "object" ? optionsArg : {};

  if (options.lockedHintText) {
    container.innerHTML = ""
      + "<article class='internship-calendar-card'>"
      + "<div class='internship-calendar-card__header'>"
      + "<div>"
      + "<p class='internship-calendar-card__eyebrow'>Tarif-Hinweis</p>"
      + "<h3 class='internship-calendar-card__title'>Belegungskalender ab Pro</h3>"
      + "<p class='internship-calendar-card__subtitle'>" + escapeHtml(options.lockedHintText) + "</p>"
      + "</div>"
      + "</div>"
      + "</article>";
    return;
  }

  const entries = Array.isArray(entriesArg)
    ? entriesArg.map(function(entry) {
        return resolveInternshipCalendarEntry(entry);
      })
    : [];

  if (!entries.length) {
    container.innerHTML = "<p class='status'>Noch keine gespeicherten Praktikumsbelegungen vorhanden.</p>";
    return;
  }

  const todayValue = getTodayInternshipDateValue();
  let activeCount = 0;
  let upcomingCount = 0;
  let completedCount = 0;
  const monthGroups = new Map();

  entries.forEach(function(entry) {
    const status = getFirmInternshipCalendarOccupancyStatus(entry, todayValue);
    if (status.key === "active") activeCount += 1;
    if (status.key === "upcoming") upcomingCount += 1;
    if (status.key === "completed") completedCount += 1;

    const monthKey = entry.startDate ? entry.startDate.slice(0, 7) : "ohne-datum";
    if (!monthGroups.has(monthKey)) {
      monthGroups.set(monthKey, []);
    }
    monthGroups.get(monthKey).push({ entry: entry, status: status });
  });

  const orderedMonthKeys = Array.from(monthGroups.keys()).sort(function(left, right) {
    if (left === "ohne-datum") return 1;
    if (right === "ohne-datum") return -1;
    return String(left).localeCompare(String(right));
  });

  container.innerHTML = ""
    + "<div class='internship-occupancy-board'>"
    + "<div class='internship-occupancy-board__summary'>"
    + "<span class='internship-occupancy-chip internship-occupancy-chip--planned'><strong>" + entries.length + "</strong><span>geplant</span></span>"
    + "<span class='internship-occupancy-chip internship-occupancy-chip--active'><strong>" + activeCount + "</strong><span>aktuell belegt</span></span>"
    + "<span class='internship-occupancy-chip internship-occupancy-chip--upcoming'><strong>" + upcomingCount + "</strong><span>bevorstehend</span></span>"
    + "<span class='internship-occupancy-chip internship-occupancy-chip--completed'><strong>" + completedCount + "</strong><span>abgeschlossen</span></span>"
    + "</div>"
    + orderedMonthKeys.map(function(monthKey) {
        const items = monthGroups.get(monthKey) || [];
        items.sort(function(left, right) {
          return String(left.entry.startDate || "").localeCompare(String(right.entry.startDate || ""));
        });
        return ""
          + "<section class='internship-occupancy-month'>"
          + "<div class='internship-occupancy-month__header'>"
          + "<h3 class='internship-occupancy-month__title'>" + escapeHtml(formatFirmInternshipOccupancyMonthLabel(items[0] && items[0].entry && items[0].entry.startDate)) + "</h3>"
          + "<span class='internship-occupancy-month__count'>" + items.length + " " + (items.length === 1 ? "Belegung" : "Belegungen") + "</span>"
          + "</div>"
          + "<div class='internship-occupancy-month__list'>"
          + items.map(function(item) {
              const plannedRange = formatInternshipDateRange(item.entry.startDate, item.entry.endDate) || "Zeitraum offen";
              const weekdayText = item.entry.days.length
                ? formatInternshipWeekdayList(item.entry.days, "")
                : "Keine festen Tage hinterlegt";
              return ""
                + "<article class='internship-occupancy-item'>"
                + "<div class='internship-occupancy-item__header'>"
                + "<div>"
                + "<p class='internship-calendar-card__eyebrow'>Belegter Praktikumsplatz</p>"
                + "<h4 class='internship-occupancy-item__title'>" + escapeHtml(item.entry.studentName || "Profil") + "</h4>"
                + "<p class='internship-occupancy-item__subtitle'>" + escapeHtml(item.entry.profession || "Praktikumsbereich") + "</p>"
                + "</div>"
                + "<span class='internship-occupancy-chip internship-occupancy-chip--" + item.status.key + "'>" + escapeHtml(item.status.label) + "</span>"
                + "</div>"
                + "<div class='internship-occupancy-item__meta'>"
                + "<p><strong>Zeitraum:</strong> " + escapeHtml(plannedRange) + "</p>"
                + "<p><strong>Tage:</strong> " + escapeHtml(weekdayText) + "</p>"
                + (item.entry.note ? "<p><strong>Notiz:</strong> " + escapeHtml(item.entry.note) + "</p>" : "")
                + "</div>"
                + "</article>";
            }).join("")
          + "</div>"
          + "</section>";
      }).join("")
    + "</div>";
}

function applyFirmInternshipCalendarDraft(draftArg, options) {
  const elements = getFirmInternshipCalendarElements();
  if (!elements) return;

  const draft = draftArg && typeof draftArg === "object" ? draftArg : {};
  const config = options || {};
  elements.studentName.textContent = draft.studentName || "Noch kein Match ausgewählt";
  elements.availability.textContent = draft.availabilityText || "Wählen Sie unten in einem Match „In Kalender planen“.";
  elements.entryIdInput.value = draft.entryId || "";
  elements.studentIdInput.value = draft.studentId || "";
  elements.studentNameValueInput.value = draft.studentName || "";
  elements.professionValueInput.value = draft.profession || "";
  setInternshipDateInputValue(elements.startDateInput, draft.startDate || "");
  setInternshipDateInputValue(elements.endDateInput, draft.endDate || "");
  elements.noteInput.value = draft.note || "";
  elements.processCheckbox.checked = !!draft.processCompleted;
  setCheckedInternshipWeekdays("firmInternshipCalendarDays", draft.days || [], elements.planner);
  elements.status.textContent = config.statusMessage || draft.statusText || "Kalendereintrag vorbereitet.";
  updateFirmInternshipCalendarExportActions();
}

function resetFirmInternshipCalendarPlanner(statusMessage) {
  applyFirmInternshipCalendarDraft({
    entryId: "",
    studentId: "",
    studentName: "Noch kein Match ausgewählt",
    profession: "",
    startDate: "",
    endDate: "",
    days: [],
    note: "",
    processCompleted: false,
    availabilityText: "Wählen Sie unten in einem Match „In Kalender planen“."
  }, {
    statusMessage: statusMessage || "Wählen Sie unten ein Match aus, um die Planung zu übernehmen."
  });
}

function buildFirmInternshipCalendarDraftFromEntry(entryArg, matchEntryArg) {
  const entry = resolveInternshipCalendarEntry(entryArg);
  const matchEntry = matchEntryArg && typeof matchEntryArg === "object" ? matchEntryArg : null;
  const scheduleFit = matchEntry ? matchEntry.scheduleFit : null;
  const savedAvailability = buildInternshipAvailabilityLabel({}, {
    startDate: entry.startDate,
    endDate: entry.endDate,
    days: entry.days,
    note: entry.note,
    fallback: "Noch keine Planung hinterlegt."
  });

  return {
    entryId: entry.id,
    studentId: entry.studentId,
    studentName: entry.studentName || "Profil",
    profession: entry.profession || "Praktikumsbereich",
    startDate: entry.startDate,
    endDate: entry.endDate,
    days: entry.days,
    note: entry.note,
    processCompleted: entry.processCompleted,
    availabilityText: scheduleFit
      ? ("Schüler: " + scheduleFit.studentAvailability + " | Betrieb: " + scheduleFit.offerAvailability)
      : ("Gespeicherte Planung: " + savedAvailability),
    statusText: "Kalendereintrag geladen. Sie können ihn jetzt anpassen."
  };
}

function findFirmInternshipMatchByStudentId(studentId, offerArg, authArg) {
  const targetId = String(studentId || "").trim();
  if (!targetId) return null;
  const auth = authArg || getStoredFirmAuth();
  const sourceOffer = offerArg || findInternshipOfferByAuth(auth);
  const offer = sourceOffer ? resolveInternshipOfferRecord(sourceOffer, auth) : null;
  if (!offer) return null;
  return getInternshipVisibleMatchesForOffer(offer).find(function(entry) {
    return getInternshipStudentScheduleKey(entry.student) === targetId;
  }) || null;
}

function renderFirmInternshipCalendar(authArg, options) {
  const elements = getFirmInternshipCalendarElements();
  if (!elements) return;

  const auth = authArg || getStoredFirmAuth();
  if (!auth) return;

  const config = options || {};
  const liveOffer = findFirmOfferByAuth(auth, loadOffers()) || null;
  const calendarCapabilities = getFirmCalendarCapabilities(liveOffer);
  const sourceOffer = findInternshipOfferByAuth(auth);
  const offer = sourceOffer ? resolveInternshipOfferRecord(sourceOffer, auth) : null;
  const matches = offer ? getInternshipVisibleMatchesForOffer(offer) : [];
  const matchByStudentId = new Map();
  matches.forEach(function(entry) {
    matchByStudentId.set(getInternshipStudentScheduleKey(entry.student), entry);
  });
  const entries = loadFirmInternshipCalendarEntries(auth);

  if (elements.planNote instanceof HTMLElement) {
    const noteParts = [];
    if (!calendarCapabilities.internshipPlannerEnabled) {
      noteParts.push(buildFirmCalendarUpgradeHint("internship-planner", liveOffer));
    } else if (!calendarCapabilities.internshipExternalLinksEnabled) {
      noteParts.push(buildFirmCalendarUpgradeHint("internship-links", liveOffer));
    }
    if (!calendarCapabilities.internshipOccupancyEnabled) {
      noteParts.push(buildFirmCalendarUpgradeHint("internship-occupancy", liveOffer));
    }
    elements.planNote.hidden = !noteParts.length;
    elements.planNote.style.display = noteParts.length ? "block" : "none";
    elements.planNote.textContent = noteParts.join(" ");
  }

  Array.from(elements.planner.querySelectorAll("input, textarea, button")).forEach(function(control) {
    if (!(control instanceof HTMLInputElement) && !(control instanceof HTMLTextAreaElement) && !(control instanceof HTMLButtonElement)) {
      return;
    }
    if (control === elements.icsButton) {
      control.disabled = !calendarCapabilities.internshipPlannerEnabled || !calendarCapabilities.internshipIcsEnabled;
      return;
    }
    control.disabled = !calendarCapabilities.internshipPlannerEnabled;
  });

  if (elements.saveButton.dataset.boundFirmInternshipCalendarSave !== "1") {
    elements.saveButton.dataset.boundFirmInternshipCalendarSave = "1";
    elements.saveButton.addEventListener("click", function() {
      const currentAuth = getStoredFirmAuth();
      if (!currentAuth) {
        elements.status.textContent = "Bitte melden Sie sich zuerst an.";
        return;
      }

      const currentOffer = findFirmOfferByAuth(currentAuth, loadOffers()) || null;
      const currentCalendarCapabilities = getFirmCalendarCapabilities(currentOffer);
      if (!currentCalendarCapabilities.internshipPlannerEnabled) {
        elements.status.textContent = buildFirmCalendarUpgradeHint("internship-planner", currentOffer);
        return;
      }

      const studentId = String(elements.studentIdInput.value || "").trim();
      const studentName = String(elements.studentNameValueInput.value || "").trim();
      const profession = String(elements.professionValueInput.value || "").trim();
      if (!studentId || !studentName) {
        elements.status.textContent = "Bitte wählen Sie zuerst ein passendes Schülerprofil aus den Matches aus.";
        return;
      }

      if (!elements.processCheckbox.checked) {
        elements.status.textContent = "Bitte bestätigen Sie zuerst, dass der Praktikumsbewerbungsprozess abgeschlossen ist, bevor Sie den Schüler in den Kalender übernehmen.";
        return;
      }

      const availability = validateInternshipAvailabilityInput({
        startDate: elements.startDateInput.value,
        endDate: elements.endDateInput.value,
        days: getCheckedInternshipWeekdays("firmInternshipCalendarDays", elements.planner),
        requireAvailability: true,
        requiredMessage: "Bitte hinterlegen Sie für den Kalendereintrag mindestens einen Zeitraum oder feste Tage.",
        partialMessage: "Bitte vervollständigen Sie den geplanten Zeitraum oder entfernen Sie die unvollständige Datumsangabe.",
        orderMessage: "Das geplante Enddatum muss nach dem Startdatum liegen."
      });

      if (!availability.ok) {
        elements.status.textContent = availability.message;
        return;
      }

      const allEntries = loadInternshipCalendarEntries().map(function(entry) {
        return resolveInternshipCalendarEntry(entry, currentAuth);
      });
      const existingEntry = allEntries.find(function(entry) {
        return String(entry.id || "").trim() === String(elements.entryIdInput.value || "").trim();
      }) || findFirmInternshipCalendarEntry(studentId, currentAuth);
      const now = new Date().toISOString();
      const nextEntry = resolveInternshipCalendarEntry({
        ...(existingEntry || {}),
        id: existingEntry && existingEntry.id ? existingEntry.id : uniqueId("praktikum_kalender"),
        firmUserId: currentAuth.id,
        firmUserEmail: currentAuth.email,
        studentId: studentId,
        studentName: studentName,
        profession: profession,
        startDate: availability.startDate,
        endDate: availability.endDate,
        days: availability.days,
        note: elements.noteInput.value.trim(),
        processCompleted: true,
        createdAt: existingEntry && existingEntry.createdAt ? existingEntry.createdAt : now,
        updatedAt: now
      }, currentAuth);

      const nextEntries = allEntries.filter(function(entry) {
        return entry.id !== nextEntry.id;
      });
      saveInternshipCalendarEntries([nextEntry].concat(nextEntries));
      renderFirmInternshipCalendar(currentAuth, {
        selectStudentId: nextEntry.studentId,
        statusMessage: "Kalendereintrag gespeichert. Der Schüler ist jetzt in Ihrer Praktikumsübersicht eingeplant."
      });
      renderFirmInternshipMatches();
    });
  }

  if (elements.resetButton.dataset.boundFirmInternshipCalendarReset !== "1") {
    elements.resetButton.dataset.boundFirmInternshipCalendarReset = "1";
    elements.resetButton.addEventListener("click", function() {
      resetFirmInternshipCalendarPlanner();
    });
  }

  if (elements.planner.dataset.boundFirmInternshipCalendarExportSync !== "1") {
    elements.planner.dataset.boundFirmInternshipCalendarExportSync = "1";
    const syncExportActions = function() {
      updateFirmInternshipCalendarExportActions(getStoredFirmAuth());
    };
    elements.planner.addEventListener("input", syncExportActions);
    elements.planner.addEventListener("change", syncExportActions);
  }

  if (elements.icsButton instanceof HTMLButtonElement && elements.icsButton.dataset.boundFirmInternshipCalendarIcs !== "1") {
    elements.icsButton.dataset.boundFirmInternshipCalendarIcs = "1";
    elements.icsButton.addEventListener("click", function() {
      const currentAuth = getStoredFirmAuth();
      const currentOffer = findFirmOfferByAuth(currentAuth, loadOffers()) || null;
      const currentCalendarCapabilities = getFirmCalendarCapabilities(currentOffer);
      if (!currentCalendarCapabilities.internshipPlannerEnabled || !currentCalendarCapabilities.internshipIcsEnabled) {
        elements.status.textContent = buildFirmCalendarUpgradeHint("internship-links", currentOffer);
        return;
      }
      const plannerEntry = buildCurrentFirmInternshipCalendarPlannerEntry(currentAuth);
      if (!plannerEntry || !downloadInternshipCalendarEntryFile(plannerEntry, { auth: currentAuth })) {
        elements.status.textContent = "Der Kalenderexport für das Praktikum konnte nicht erstellt werden.";
      }
    });
  }

  if (elements.entries.dataset.boundFirmInternshipCalendarActions !== "1") {
    elements.entries.dataset.boundFirmInternshipCalendarActions = "1";
    elements.entries.addEventListener("click", function(event) {
      const downloadButton = event.target.closest("[data-calendar-entry-ics]");
      if (downloadButton) {
        const entryId = String(downloadButton.getAttribute("data-calendar-entry-ics") || "").trim();
        if (!entryId) return;
        const currentAuth = getStoredFirmAuth();
        const currentOffer = findFirmOfferByAuth(currentAuth, loadOffers()) || null;
        const currentCalendarCapabilities = getFirmCalendarCapabilities(currentOffer);
        if (!currentCalendarCapabilities.internshipPlannerEnabled || !currentCalendarCapabilities.internshipIcsEnabled) {
          elements.status.textContent = buildFirmCalendarUpgradeHint("internship-links", currentOffer);
          return;
        }
        const currentEntry = loadFirmInternshipCalendarEntries(currentAuth).find(function(entry) {
          return entry.id === entryId;
        }) || null;
        if (!currentEntry || !downloadInternshipCalendarEntryFile(currentEntry, { auth: currentAuth })) {
          elements.status.textContent = "Die gespeicherte Praktikumsplanung konnte nicht als ICS-Datei erstellt werden.";
        }
        return;
      }

      const editButton = event.target.closest("[data-calendar-entry-edit]");
      if (editButton) {
        const entryId = String(editButton.getAttribute("data-calendar-entry-edit") || "").trim();
        if (!entryId) return;
        const currentAuth = getStoredFirmAuth();
        const currentOffer = findFirmOfferByAuth(currentAuth, loadOffers()) || null;
        const currentCalendarCapabilities = getFirmCalendarCapabilities(currentOffer);
        if (!currentCalendarCapabilities.internshipPlannerEnabled) {
          elements.status.textContent = buildFirmCalendarUpgradeHint("internship-planner", currentOffer);
          return;
        }
        const currentEntry = loadFirmInternshipCalendarEntries(currentAuth).find(function(entry) {
          return entry.id === entryId;
        });
        if (!currentEntry) {
          elements.status.textContent = "Der gewählte Kalendereintrag wurde nicht gefunden.";
          return;
        }
        const currentMatch = findFirmInternshipMatchByStudentId(currentEntry.studentId, null, currentAuth);
        applyFirmInternshipCalendarDraft(buildFirmInternshipCalendarDraftFromEntry(currentEntry, currentMatch));
        elements.section.scrollIntoView({ behavior: "smooth", block: "start" });
        requestAnimationFrame(function () {
          var plannerName = document.getElementById("firmInternshipCalendarStudentName");
          var focusTarget = plannerName || elements.section.querySelector("input, textarea, button");
          if (focusTarget) {
            focusTarget.setAttribute("tabindex", "-1");
            focusTarget.focus({ preventScroll: true });
          }
        });
        return;
      }

      const deleteButton = event.target.closest("[data-calendar-entry-delete]");
      if (deleteButton) {
        const entryId = String(deleteButton.getAttribute("data-calendar-entry-delete") || "").trim();
        if (!entryId) return;
        const currentAuth = getStoredFirmAuth();
        const currentOffer = findFirmOfferByAuth(currentAuth, loadOffers()) || null;
        const currentCalendarCapabilities = getFirmCalendarCapabilities(currentOffer);
        if (!currentCalendarCapabilities.internshipPlannerEnabled) {
          elements.status.textContent = buildFirmCalendarUpgradeHint("internship-planner", currentOffer);
          return;
        }
        const allEntries = loadInternshipCalendarEntries().map(function(entry) {
          return resolveInternshipCalendarEntry(entry, currentAuth);
        });
        const currentEntry = allEntries.find(function(entry) {
          return entry.id === entryId;
        });
        if (!currentEntry) {
          elements.status.textContent = "Der Kalendereintrag wurde nicht gefunden.";
          return;
        }
        saveInternshipCalendarEntries(allEntries.filter(function(entry) {
          return entry.id !== entryId;
        }));
        const selectedEntryId = String(elements.entryIdInput.value || "").trim();
        if (selectedEntryId === entryId) {
          resetFirmInternshipCalendarPlanner("Kalendereintrag entfernt. Wählen Sie ein neues Match aus, um weiterzuplanen.");
        }
        renderFirmInternshipCalendar(currentAuth, {
          statusMessage: "Kalendereintrag entfernt."
        });
        renderFirmInternshipMatches();
      }
    });
  }

  if (!calendarCapabilities.internshipPlannerEnabled) {
    elements.entries.innerHTML = ""
      + "<article class='internship-calendar-card'>"
      + "<div class='internship-calendar-card__header'>"
      + "<div>"
      + "<p class='internship-calendar-card__eyebrow'>Kalender freischalten</p>"
      + "<h3 class='internship-calendar-card__title'>Praktikumsplanung ab Basic</h3>"
      + "<p class='internship-calendar-card__subtitle'>" + escapeHtml(buildFirmCalendarUpgradeHint("internship-planner", liveOffer)) + "</p>"
      + "</div>"
      + "</div>"
      + "<div class='internship-calendar-card__meta'>"
      + "<p><strong>Aktuell:</strong> " + escapeHtml(buildFirmCalendarAccessSummary(liveOffer)) + "</p>"
      + "</div>"
      + "</article>";
    renderFirmInternshipOccupancyCalendar(entries, {
      lockedHintText: buildFirmCalendarUpgradeHint("internship-planner", liveOffer)
    });
    updateFirmInternshipCalendarExportActions(auth);
    elements.status.textContent = config.statusMessage || buildFirmCalendarUpgradeHint("internship-planner", liveOffer);
    return;
  }

  const calendarOptions = { auth: auth };
  elements.entries.innerHTML = entries.length
    ? entries.map(function(entry) {
        const matchEntry = matchByStudentId.get(entry.studentId) || null;
        const scheduleFit = matchEntry ? matchEntry.scheduleFit : null;
        const plannedAvailability = buildInternshipAvailabilityLabel({}, {
          startDate: entry.startDate,
          endDate: entry.endDate,
          days: entry.days,
          note: entry.note,
          fallback: "Noch keine Planung hinterlegt."
        });
        const fitClass = scheduleFit
          ? scheduleFit.chipClass
          : "firm-match-chip--schedule-pending";
        const fitLabel = scheduleFit
          ? scheduleFit.label
          : "Match aktuell nicht sichtbar";
        const outlookUrl = buildInternshipCalendarEntryOutlookUrl(entry, calendarOptions);
        const googleUrl = buildInternshipCalendarEntryGoogleCalendarUrl(entry, calendarOptions);
        return ""
          + "<article class='internship-calendar-card'>"
          + "<div class='internship-calendar-card__header'>"
          + "<div>"
          + "<p class='internship-calendar-card__eyebrow'>Geplanter Praktikant</p>"
          + "<h3 class='internship-calendar-card__title'>" + escapeHtml(entry.studentName || "Profil") + "</h3>"
          + "<p class='internship-calendar-card__subtitle'>" + escapeHtml(entry.profession || "Praktikumsbereich") + "</p>"
          + "</div>"
          + "<div class='internship-calendar-card__chips'>"
          + "<span class='firm-match-chip firm-match-chip--calendar'>Bewerbungsprozess abgeschlossen</span>"
          + "<span class='firm-match-chip " + escapeHtml(fitClass) + "'>" + escapeHtml(fitLabel) + "</span>"
          + "</div>"
          + "</div>"
          + "<div class='internship-calendar-card__meta'>"
          + "<p><strong>Planung:</strong> " + escapeHtml(plannedAvailability) + "</p>"
          + (scheduleFit ? "<p><strong>Aktueller Match-Abgleich:</strong> " + escapeHtml(scheduleFit.detail) + "</p>" : "")
          + (entry.note ? "<p><strong>Notiz:</strong> " + escapeHtml(entry.note) + "</p>" : "")
          + "</div>"
          + "<div class='internship-calendar-card__actions'>"
          + (calendarCapabilities.internshipExternalLinksEnabled && outlookUrl ? "<a class='btn ghost small' target='_blank' rel='noopener noreferrer' href='" + escapeHtml(outlookUrl) + "'>Outlook</a>" : "")
          + (calendarCapabilities.internshipExternalLinksEnabled && googleUrl ? "<a class='btn ghost small' target='_blank' rel='noopener noreferrer' href='" + escapeHtml(googleUrl) + "'>Google</a>" : "")
          + (calendarCapabilities.internshipIcsEnabled ? "<button class='btn ghost small' type='button' data-calendar-entry-ics='" + escapeHtml(entry.id) + "'>ICS laden</button>" : "")
          + "<button class='btn ghost small' type='button' data-calendar-entry-edit='" + escapeHtml(entry.id) + "'>Bearbeiten</button>"
          + "<button class='btn ghost small' type='button' data-calendar-entry-delete='" + escapeHtml(entry.id) + "'>Entfernen</button>"
          + "</div>"
          + "</article>";
      }).join("")
    : "<p class='status'>Noch keine Praktikantinnen oder Praktikanten im Kalender geplant.</p>";

  renderFirmInternshipOccupancyCalendar(entries, !calendarCapabilities.internshipOccupancyEnabled ? {
    lockedHintText: buildFirmCalendarUpgradeHint("internship-occupancy", liveOffer)
  } : null);
  updateFirmInternshipCalendarExportActions(auth);

  if (config.draft) {
    applyFirmInternshipCalendarDraft(config.draft, { statusMessage: config.statusMessage });
    return;
  }

  if (config.selectStudentId) {
    const selectedEntry = entries.find(function(entry) {
      return entry.studentId === config.selectStudentId;
    }) || null;
    if (selectedEntry) {
      applyFirmInternshipCalendarDraft(
        buildFirmInternshipCalendarDraftFromEntry(selectedEntry, matchByStudentId.get(config.selectStudentId) || null),
        { statusMessage: config.statusMessage }
      );
      return;
    }

    const selectedMatch = matchByStudentId.get(config.selectStudentId) || null;
    if (selectedMatch) {
      applyFirmInternshipCalendarDraft(buildFirmInternshipCalendarDraft(selectedMatch, auth), { statusMessage: config.statusMessage });
      return;
    }
  }

  if (config.statusMessage) {
    elements.status.textContent = config.statusMessage;
    return;
  }

  const currentEntryId = String(elements.entryIdInput.value || "").trim();
  if (currentEntryId) {
    const selectedEntry = entries.find(function(entry) {
      return entry.id === currentEntryId;
    }) || null;
    if (selectedEntry) {
      applyFirmInternshipCalendarDraft(buildFirmInternshipCalendarDraftFromEntry(selectedEntry, matchByStudentId.get(selectedEntry.studentId) || null));
      return;
    }
  }

  const currentStudentId = String(elements.studentIdInput.value || "").trim();
  if (currentStudentId) {
    const selectedMatch = matchByStudentId.get(currentStudentId) || null;
    if (selectedMatch) {
      applyFirmInternshipCalendarDraft(buildFirmInternshipCalendarDraft(selectedMatch, auth));
      return;
    }
    const selectedEntry = entries.find(function(entry) {
      return entry.studentId === currentStudentId;
    }) || null;
    if (selectedEntry) {
      applyFirmInternshipCalendarDraft(buildFirmInternshipCalendarDraftFromEntry(selectedEntry, null));
      return;
    }
  }

  resetFirmInternshipCalendarPlanner();
}

function getInternshipProfessionList(listId) {
  const container = document.getElementById(listId);
  if (!container) return [];
  return normalizeProfessionCollection(
    Array.from(container.querySelectorAll("[data-beruf]"))
      .map(function(item) {
        return String(item.getAttribute("data-beruf") || "").trim();
      })
  );
}

function renderInternshipProfessionList(listId, professions) {
  const container = document.getElementById(listId);
  if (!container) return;

  const normalizedProfessions = normalizeProfessionCollection(professions);
  if (!normalizedProfessions.length) {
    container.innerHTML = "<p class='status' style='color: #94a3b8; font-size: 0.9rem;'>Noch keine Praktikumsbereiche hinzugefügt.</p>";
    return;
  }

  container.innerHTML = normalizedProfessions.map(function(profession) {
    const escapedProfession = escapeHtml(profession);
    return ""
      + "<div class='beruf-item' data-beruf='" + escapedProfession + "'>"
      + "<span class='beruf-name'>" + escapedProfession + "</span>"
      + "<button class='btn ghost small praktikum-beruf-remove-btn' type='button' data-list-id='" + escapeHtml(listId) + "' data-beruf='" + escapedProfession + "'>Entfernen</button>"
      + "</div>";
  }).join("");
}

function resolveInternshipProfessionSuggestion(rawValue) {
  const trimmed = String(rawValue || "").trim();
  if (!trimmed) return "";

  const suggestion = getProfessionSuggestion(trimmed);
  if (suggestion && suggestion.exact) {
    return suggestion.value;
  }
  if (suggestion && suggestion.needsSuggestion) {
    const acceptSuggestion = confirm("Möglicher Tippfehler erkannt. Meinten Sie: \"" + suggestion.value + "\"?");
    if (!acceptSuggestion) {
      return "";
    }
    return suggestion.value;
  }
  return trimmed;
}

function bindInternshipProfessionEditor(options) {
  const config = options || {};
  const input = document.getElementById(config.inputId || "");
  const addButton = document.getElementById(config.addButtonId || "");
  const list = document.getElementById(config.listId || "");
  if (!input || !addButton || !list) return;

  if (addButton.dataset.boundInternshipAdd !== "1") {
    addButton.dataset.boundInternshipAdd = "1";
    addButton.addEventListener("click", function() {
      const resolvedProfession = resolveInternshipProfessionSuggestion(input.value);
      if (!resolvedProfession) return;
      const nextProfessions = getInternshipProfessionList(config.listId).concat(resolvedProfession);
      renderInternshipProfessionList(config.listId, nextProfessions);
      input.value = "";
      input.focus();
    });
  }

  if (input.dataset.boundInternshipEnter !== "1") {
    input.dataset.boundInternshipEnter = "1";
    input.addEventListener("keypress", function(event) {
      if (event.key === "Enter") {
        event.preventDefault();
        addButton.click();
      }
    });
  }

  if (list.dataset.boundInternshipRemove !== "1") {
    list.dataset.boundInternshipRemove = "1";
    list.addEventListener("click", function(event) {
      const button = event.target.closest(".praktikum-beruf-remove-btn");
      if (!button) return;
      const listId = button.getAttribute("data-list-id") || config.listId;
      const profession = String(button.getAttribute("data-beruf") || "").trim();
      const nextProfessions = getInternshipProfessionList(listId).filter(function(entry) {
        return normalizeProfessionText(entry) !== normalizeProfessionText(profession);
      });
      renderInternshipProfessionList(listId, nextProfessions);
    });
  }
}

function getCurrentStoredOfferForAuth() {
  const offers = loadOffers();
  const auth = getStoredFirmAuth();
  if (!auth) {
    return offers.length ? offers[0] : null;
  }
  return findFirmOfferByAuth(auth, offers) || (offers.length ? offers[0] : null);
}

function getLatestOfferFromInputsOrStorage() {
  const firma = (document.getElementById("firma") || {}).value || "";
  const strasse = (document.getElementById("strasse") || {}).value || "";
  const plz = (document.getElementById("plz") || {}).value || "";
  const ort = (document.getElementById("ort") || {}).value || "";
  const ansprechpartner = (document.getElementById("ansprechpartner") || {}).value || "";
  const ihkMitgliedsnummer = (document.getElementById("ihkMitgliedsnummer") || {}).value || "";
  const matchUmkreis = (document.getElementById("matchUmkreis") || {}).value || "";
  const billingPlan = getSelectedFirmBillingPlanValue();
  const berufe = getBerufliste();
  const startdatum = (document.getElementById("startdatum") || {}).value || "";

  if (firma.trim() && strasse.trim() && plz.trim() && ort.trim() && ansprechpartner.trim() && ihkMitgliedsnummer.trim() && berufe.length && startdatum) {
    return {
      firma: firma.trim(),
      strasse: strasse.trim(),
      plz: plz.trim(),
      ort: ort.trim(),
      ansprechpartner: ansprechpartner.trim(),
      ihkMitgliedsnummer: ihkMitgliedsnummer.trim(),
      matchUmkreis: normalizeMatchRadiusValue(matchUmkreis),
      billingPlan: billingPlan,
      berufe: berufe,
      startdatum: startdatum
    };
  }

  return getCurrentStoredOfferForAuth();
}

function findInternshipStudentByAuth(auth, records) {
  const students = Array.isArray(records) ? records : loadInternshipStudents();
  if (!auth) return null;
  return students.find(function(entry) {
    return entry.userId === auth.id
      || normalizeText(entry.userEmail) === normalizeText(auth.email)
      || normalizeText(entry.email) === normalizeText(auth.email);
  }) || null;
}

function findInternshipOfferByAuth(auth, records) {
  const offers = Array.isArray(records) ? records : loadInternshipOffers();
  if (!auth) return null;
  return offers.find(function(entry) {
    return entry.userId === auth.id
      || normalizeText(entry.userEmail) === normalizeText(auth.email)
      || normalizeText(entry.email) === normalizeText(auth.email);
  }) || null;
}

function getPortalInputValue(id) {
  const element = document.getElementById(id);
  return element && typeof element.value === "string" ? element.value.trim() : "";
}

function buildInternshipStudentBaseSnapshot(authArg, options) {
  const auth = authArg || getStoredStudentAuth();
  const config = options || {};
  const preferInputs = !!config.preferInputs;
  const student = auth ? (findStudentByAuth(auth) || loadStudents().find(function(entry) {
    return entry.id === auth.id || entry.profilCode === auth.id;
  })) : null;

  function pickValue(inputId, storedValue) {
    const inputValue = preferInputs ? getPortalInputValue(inputId) : "";
    return inputValue || String(storedValue || "").trim();
  }

  return {
    auth: auth,
    sourceStudent: student,
    name: pickValue("name", (student && student.name) || (auth && auth.name) || ""),
    stadt: pickValue("stadt", student && student.stadt),
    plz: pickValue("plz", student && student.plz),
    schulabschluss: pickValue("schulabschluss", student && student.schulabschluss),
    weiterfuehrendeSchulform: pickValue("weiterfuehrendeSchulform", student && student.weiterfuehrendeSchulform),
    matchUmkreis: normalizeMatchRadiusValue(pickValue("matchUmkreis", student && student.matchUmkreis)),
    behinderung: pickValue("behinderung", student && student.behinderung),
    behinderungsArt: pickValue("behinderungsArt", student && student.behinderungsArt),
    behinderungsGrad: pickValue("behinderungsGrad", student && student.behinderungsGrad),
    beruf: pickValue("beruf", student && student.beruf),
    internshipSearchStatus: normalizeStudentSearchStatus(student && student.internshipSearchStatus)
  };
}

function buildInternshipFirmBaseSnapshot(authArg, options) {
  const auth = authArg || getStoredFirmAuth();
  const config = options || {};
  const preferInputs = !!config.preferInputs;
  const offer = auth ? findFirmOfferByAuth(auth) : getCurrentStoredOfferForAuth();

  function pickValue(inputId, storedValue) {
    const inputValue = preferInputs ? getPortalInputValue(inputId) : "";
    return inputValue || String(storedValue || "").trim();
  }

  const inputProfessions = preferInputs && typeof getBerufliste === "function"
    ? getBerufliste()
    : [];
  const professions = inputProfessions.length
    ? inputProfessions
    : getOfferProfessionList(offer);

  return {
    auth: auth,
    sourceOffer: offer,
    firma: pickValue("firma", (offer && offer.firma) || (auth && auth.name) || ""),
    anrede: pickValue("anrede", offer && offer.anrede),
    ansprechpartner: pickValue("ansprechpartner", offer && offer.ansprechpartner),
    strasse: pickValue("strasse", offer && offer.strasse),
    ort: pickValue("ort", offer && (offer.ort || offer.stadt)),
    stadt: pickValue("ort", offer && (offer.ort || offer.stadt)),
    plz: pickValue("plz", offer && offer.plz),
    matchUmkreis: normalizeMatchRadiusValue(pickValue("matchUmkreis", offer && offer.matchUmkreis)),
    platzBehindert: pickValue("platzBehindert", offer && offer.platzBehindert),
    berufe: normalizeProfessionCollection(professions)
  };
}

function resolveInternshipStudentRecord(entry, authArg, options) {
  const data = entry && typeof entry === "object" ? entry : {};
  const base = buildInternshipStudentBaseSnapshot(authArg, options);
  return {
    ...data,
    userId: data.userId || (base.auth && base.auth.id) || (base.sourceStudent && base.sourceStudent.userId) || "",
    userEmail: data.userEmail || data.email || (base.auth && base.auth.email) || (base.sourceStudent && base.sourceStudent.userEmail) || "",
    email: data.email || data.userEmail || (base.auth && base.auth.email) || "",
    profilCode: data.profilCode || (base.sourceStudent && base.sourceStudent.profilCode) || "",
    baseStudentId: data.baseStudentId || (base.sourceStudent && base.sourceStudent.id) || "",
    name: data.name || base.name,
    stadt: data.stadt || base.stadt,
    plz: data.plz || base.plz,
    schulabschluss: data.schulabschluss || base.schulabschluss,
    weiterfuehrendeSchulform: data.weiterfuehrendeSchulform || base.weiterfuehrendeSchulform,
    matchUmkreis: normalizeMatchRadiusValue(data.matchUmkreis || base.matchUmkreis),
    behinderung: data.behinderung || base.behinderung,
    behinderungsArt: data.behinderungsArt || base.behinderungsArt,
    behinderungsGrad: data.behinderungsGrad || base.behinderungsGrad,
    beruf: String(data.beruf || base.beruf || "").trim(),
    praktikumStartdatum: normalizeInternshipDateValue(data.praktikumStartdatum),
    praktikumEnddatum: normalizeInternshipDateValue(data.praktikumEnddatum),
    praktikumTage: normalizeInternshipWeekdays(data.praktikumTage),
    praktikumZeitfenster: normalizeInternshipTimeSlots(data.praktikumZeitfenster),
    praktikumZeitraum: String(data.praktikumZeitraum || "").trim(),
    praktikumKlassenstufe: String(data.praktikumKlassenstufe || "").trim(),
    praktikumHinweis: String(data.praktikumHinweis || "").trim(),
    praktikumsbericht: String(data.praktikumsbericht || data.praktikumBericht || "").trim(),
    searchStatus: normalizeStudentSearchStatus(data.searchStatus || base.internshipSearchStatus),
    isInternship: true
  };
}

function resolveInternshipOfferRecord(entry, authArg, options) {
  const data = entry && typeof entry === "object" ? entry : {};
  const base = buildInternshipFirmBaseSnapshot(authArg, options);
  const resolvedProfessions = Array.isArray(data.berufe) && data.berufe.length
    ? data.berufe
    : base.berufe;

  return {
    ...data,
    userId: data.userId || (base.auth && base.auth.id) || "",
    userEmail: data.userEmail || data.email || (base.auth && base.auth.email) || "",
    email: data.email || data.userEmail || (base.auth && base.auth.email) || "",
    baseOfferId: data.baseOfferId || (base.sourceOffer && base.sourceOffer.id) || "",
    firma: data.firma || base.firma,
    anrede: data.anrede || base.anrede,
    ansprechpartner: data.ansprechpartner || base.ansprechpartner,
    strasse: data.strasse || base.strasse,
    ort: data.ort || data.stadt || base.ort,
    stadt: data.stadt || data.ort || base.stadt,
    plz: data.plz || base.plz,
    matchUmkreis: normalizeMatchRadiusValue(data.matchUmkreis || base.matchUmkreis),
    platzBehindert: data.platzBehindert || base.platzBehindert,
    berufe: normalizeProfessionCollection(resolvedProfessions),
    praktikumStartdatum: normalizeInternshipDateValue(data.praktikumStartdatum),
    praktikumEnddatum: normalizeInternshipDateValue(data.praktikumEnddatum),
    praktikumTage: normalizeInternshipWeekdays(data.praktikumTage),
    praktikumZeitfenster: normalizeInternshipTimeSlots(data.praktikumZeitfenster),
    praktikumZeitraum: String(data.praktikumZeitraum || "").trim(),
    praktikumKlassenstufen: String(data.praktikumKlassenstufen || "").trim(),
    praktikumHinweis: String(data.praktikumHinweis || "").trim(),
    isInternship: true
  };
}

function matchStudents(offer) {
  if (!offer || !isFirmAccountReleased(offer)) return [];
  return getFirmVisibleMatches(offer);
}

function getFirmVisibleMatches(offer) {
  const options = arguments.length > 1 && arguments[1] && typeof arguments[1] === "object"
    ? arguments[1]
    : {};
  const suppressRejectedMatches = options.suppressRejectedMatches !== false;

  if (suppressRejectedMatches && window.AzubiMatchDiscovery && typeof window.AzubiMatchDiscovery.matchStudents === "function") {
    return window.AzubiMatchDiscovery.matchStudents(offer);
  }

  const students = loadStudents();
  const offers = loadOffers();
  const requests = loadFullProfileRequests();
  if (!offer) return [];

  const scored = students.map((student) => {
    const matchMeta = getMatchMeta(student, offer, { allOffers: offers });
    const fitScore = getMatchFitScore(matchMeta);
    const profileCompletenessScore = getMatchProfileCompletenessScore(student);
    const score = fitScore + profileCompletenessScore;

    return {
      student,
      score,
      fitScore,
      profileCompletenessScore,
      matchedProfession: matchMeta.matchedProfession,
      isInclusionMatch: matchMeta.isInclusionMatch,
      isAlternativeMatch: matchMeta.isAlternativeMatch,
      isActivatedAlternativeProfession: matchMeta.isActivatedAlternativeProfession,
      alternativeFamilyLabel: matchMeta.alternativeFamilyLabel,
      matchLabel: matchMeta.matchLabel,
      distanceKm: matchMeta.distanceKm,
      distanceLabel: matchMeta.distanceLabel,
      studentRadiusLabel: matchMeta.studentRadiusLabel,
      offerRadiusLabel: matchMeta.offerRadiusLabel,
      isVisibleMatch: matchMeta.isVisibleMatch
    };
  });

  return scored
    .filter((entry) => entry.isVisibleMatch && (!suppressRejectedMatches || !isStudentFirmMatchSuppressed(entry.student, offer, entry.matchedProfession, requests)))
    .sort((a, b) => {
      if (b.fitScore !== a.fitScore) {
        return b.fitScore - a.fitScore;
      }
      if (b.profileCompletenessScore !== a.profileCompletenessScore) {
        return b.profileCompletenessScore - a.profileCompletenessScore;
      }
      return compareDistanceAsc(a.distanceKm, b.distanceKm);
    });
}

function getFirmMatchStatisticsCount(offer) {
  return getFirmVisibleMatches(offer, { suppressRejectedMatches: false }).length;
}

function getMatchesForStudent(studentArg, options) {
  if (window.AzubiMatchDiscovery && typeof window.AzubiMatchDiscovery.getMatchesForStudent === "function") {
    return window.AzubiMatchDiscovery.getMatchesForStudent(studentArg, options);
  }

  const config = options || {};
  const student = studentArg || null;
  const offers = (Array.isArray(config.offers) ? config.offers : loadOffers()).filter(function(offer) {
    return isFirmAccountReleased(offer);
  });
  const requests = loadFullProfileRequests();
  if (!student) return [];

  return offers
    .map(function(offer) {
      const matchMeta = getMatchMeta(student, offer, { allOffers: offers });
      const fitScore = getMatchFitScore(matchMeta);
      const profileCompletenessScore = getMatchProfileCompletenessScore(student);
      const score = fitScore + profileCompletenessScore;
      return {
        offer: offer,
        summary: buildFirmQuickProfileSummaryData(offer, null),
        score: score,
        fitScore: fitScore,
        profileCompletenessScore: profileCompletenessScore,
        matchedProfession: matchMeta.matchedProfession,
        isInclusionMatch: matchMeta.isInclusionMatch,
        isAlternativeMatch: matchMeta.isAlternativeMatch,
        isActivatedAlternativeProfession: matchMeta.isActivatedAlternativeProfession,
        alternativeFamilyKey: matchMeta.alternativeFamilyKey,
        alternativeFamilyLabel: matchMeta.alternativeFamilyLabel,
        matchLabel: matchMeta.matchLabel,
        distanceKm: matchMeta.distanceKm,
        distanceLabel: matchMeta.distanceLabel,
        studentRadiusLabel: matchMeta.studentRadiusLabel,
        offerRadiusLabel: matchMeta.offerRadiusLabel,
        isVisibleMatch: matchMeta.isVisibleMatch
      };
    })
    .filter(function(entry) {
      return entry.isVisibleMatch && !isStudentFirmMatchSuppressed(student, entry.offer, entry.matchedProfession, requests);
    })
    .sort(function(left, right) {
      if (right.fitScore !== left.fitScore) {
        return right.fitScore - left.fitScore;
      }
      const distanceCompare = compareDistanceAsc(left.distanceKm, right.distanceKm);
      if (distanceCompare !== 0) {
        return distanceCompare;
      }
      return String(left.summary.name || "").localeCompare(String(right.summary.name || ""), "de");
    });
}

function collectCurrentMatchPairs() {
  return loadOffers().filter((offer) => isFirmAccountReleased(offer)).reduce((list, offer) => {
    const pairs = getFirmVisibleMatches(offer, { suppressRejectedMatches: false }).map((entry) => ({
      beruf: entry.matchedProfession,
      student: entry.student,
      firm: offer,
      matchedProfession: entry.matchedProfession,
      isInclusionMatch: entry.isInclusionMatch,
      isAlternativeMatch: entry.isAlternativeMatch,
      isActivatedAlternativeProfession: entry.isActivatedAlternativeProfession,
      alternativeFamilyLabel: entry.alternativeFamilyLabel,
      matchLabel: entry.matchLabel,
      distanceKm: entry.distanceKm,
      distanceLabel: entry.distanceLabel
    }));
    return list.concat(pairs);
  }, []);
}

function renderMatches() {
  const list = document.getElementById("matchList");
  if (!list) return;

  const offer = getLatestOfferFromInputsOrStorage();
  if (!offer) {
    list.innerHTML = "<p class='status'>Speichere zuerst ein Ausbildungsangebot.</p>";
    return;
  }

  if (!isFirmApprenticeshipMatchingEnabled(offer)) {
    list.innerHTML = "<p class='status'>Im Tarif Nur Praktikum sind Ausbildungs-Matches ausgeblendet. Nutzen Sie den separaten Schulpraktikumsbereich für passende Praktikumsprofile.</p>";
    return;
  }

  // Filter matches to only include students with valid, existing IDs
  const students = loadStudents();
  const validMatches = getFirmVisibleMatches(offer, { suppressRejectedMatches: false }).filter(entry => students.some(s => s.id === entry.student.id));
  if (!validMatches.length) {
    list.innerHTML = "<p class='status'>Aktuell wurden keine passenden Profile im gewählten Umkreis gefunden.</p>";
    return;
  }

  const inclusionMatches = validMatches.filter((entry) => entry.isInclusionMatch).length;
  const alternativeMatches = validMatches.filter((entry) => entry.isAlternativeMatch).length;
  const radiusLabel = formatMatchRadiusLabel(offer.matchUmkreis);
  const topScoreMeta = getMatchScoreMeta(validMatches[0]);

  list.innerHTML = "<p style='font-size: 2rem; font-weight: 800; color: #1e3a8a; text-align: center; margin: 1.5rem 0;'>" + validMatches.length + "</p>"
    + "<p style='text-align: center; color: #6b7280; font-size: 0.95rem;'>passende Profile gefunden</p>"
    + `<p style='text-align: center; color: #475569; font-size: 0.92rem;'>Umkreis: ${radiusLabel}</p>`
    + `<p style='text-align: center; color: #1d4ed8; font-size: 0.95rem; font-weight: 700;'>Bester Match-Score: ${topScoreMeta.label}</p>`
    + (alternativeMatches > 0
      ? `<p style='text-align: center; color: #7c3aed; font-size: 0.95rem; font-weight: 700;'>davon ${alternativeMatches} ${alternativeMatches === 1 ? 'Berufsfeld-Match' : 'Berufsfeld-Matches'}</p>`
      : "")
    + (inclusionMatches > 0
      ? `<p style='text-align: center; color: #0f766e; font-size: 0.95rem; font-weight: 700;'>davon ${inclusionMatches} ${inclusionMatches === 1 ? 'Inklusions-Match' : 'Inklusions-Matches'}</p>`
      : "");
}

function openStudentFile(studentId, type) {
  const students = loadStudents();
  const student = students.find((s) => s.id === studentId);
  if (!student) return;
  const auth = getStoredFirmAuth();
  const offers = loadOffers();
  const activeFirm = findFirmOfferByAuth(auth, offers);
  const requests = loadFullProfileRequests();
  const hasGrantedAccess = !!(activeFirm && requests.some((request) => {
    const sameStudent = request.studentId === student.id || (student.profilCode && request.profilCode === student.profilCode);
    return sameStudent && request.firmId === activeFirm.id && isAcceptedFullProfileRequestStatus(request.status) && request.documentsGranted;
  }));
  if (!hasGrantedAccess) {
    // alert("Dieses Profil ist intern geprueft, aber ohne ausdrueckliche Zustimmung nicht vollstaendig freigegeben.");
    return;
  }
  const fileObj = type === "cv" ? student.lebenslauf : student.anschreiben;
  if (!fileObj || !fileObj.dataUrl) {
    // alert("Für dieses Profil wurde keine Datei hochgeladen.");
    return;
  }

  downloadFileData(fileObj);
}

function sendMessageToStudent(studentId) {
  const textarea = document.getElementById("msg_" + studentId);
  const text = textarea ? textarea.value.trim() : "";
  if (!text) {
    // alert("Bitte zuerst eine Nachricht eingeben.");
    return;
  }

  const offer = getLatestOfferFromInputsOrStorage();
  if (!offer) {
    // alert("Bitte zuerst ein Ausbildungsangebot speichern.");
    return;
  }

  const messages = loadMessages();
  const students = loadStudents();
  const student = students.find((s) => s.id === studentId);
  const profileCode = student && student.profilCode ? student.profilCode : "AZ-UNBEKANNT";
  const offerRoles = Array.isArray(offer.berufe) ? offer.berufe.join(", ") : (offer.ausbildung || "");
  messages.unshift({
    id: uniqueId("msg"),
    studentId: studentId,
    profileCode: profileCode,
    fromCompany: offer.firma,
    offerRole: offerRoles,
    offerCity: offer.ort,
    text: text,
    sentAt: new Date().toISOString()
  });
  saveMessages(messages);
  textarea.value = "";
  // alert("Nachricht wurde gesendet.");
}

function renderStudentMessages(studentId) {
  const container = document.getElementById("bewerberMessages");
  if (!container || !studentId) return;

  const messages = loadMessages().filter((m) => m.studentId === studentId);
  if (!messages.length) {
    container.innerHTML = "<p class='status'>Du hast noch keine Nachrichten von Firmen.</p>";
    return;
  }

  container.innerHTML = messages.map((msg) => {
    const when = new Date(msg.sentAt).toLocaleString("de-DE");
    return ""
      + "<article class='result-card'>"
      + "<h3>Nachricht von " + msg.fromCompany + "</h3>"
      + "<p><strong>Angebot:</strong> " + msg.offerRole + " in " + msg.offerCity + "</p>"
      + "<p>" + msg.text + "</p>"
      + "<p class='status'>Gesendet am " + when + "</p>"
      + "</article>";
  }).join("");
}

function collectStudentIdentityKeys(student, auth) {
  const keys = [];
  if (student && student.id) keys.push(student.id);
  if (student && student.userId && !keys.includes(student.userId)) keys.push(student.userId);
  if (student && student.profilCode && !keys.includes(student.profilCode)) keys.push(student.profilCode);
  if (auth && auth.id && !keys.includes(auth.id)) keys.push(auth.id);
  return keys;
}

function renderStudentEntryPreview(preferredAuth) {
  const previewName = document.getElementById("shortProfilePreviewName");
  const previewCode = document.getElementById("shortProfilePreviewCode");
  const previewRole = document.getElementById("shortProfilePreviewRole");
  const previewLocation = document.getElementById("shortProfilePreviewLocation");
  const previewSchool = document.getElementById("shortProfilePreviewSchool");
  const previewQualification = document.getElementById("shortProfilePreviewQualification");
  const previewGrades = document.getElementById("shortProfilePreviewGrades");
  const previewStrengths = document.getElementById("shortProfilePreviewStrengths");
  const previewLanguages = document.getElementById("shortProfilePreviewLanguages");
  const previewDocuments = document.getElementById("shortProfilePreviewDocuments");
  const previewStatus = document.getElementById("shortProfilePreviewStatus");
  if (!previewName || !previewCode || !previewRole || !previewLocation || !previewSchool || !previewQualification || !previewGrades || !previewStrengths || !previewLanguages || !previewDocuments || !previewStatus) {
    return;
  }

  const auth = preferredAuth || getStoredStudentAuth();
  const student = auth ? findStudentByAuth(auth) : null;
  const getValue = function(id) {
    const element = document.getElementById(id);
    return element && typeof element.value === "string" ? element.value.trim() : "";
  };
  const languageEntries = Array.from(document.querySelectorAll("#sprachenList li .sprache-label"))
    .map((element) => element.textContent.trim())
    .filter(Boolean);
  const languages = languageEntries.length
    ? languageEntries
    : (Array.isArray(student && student.sprachen) ? student.sprachen.filter(Boolean) : []);
  const documents = [
    ((document.getElementById("lebenslaufFile") || {}).files || []).length || (student && student.lebenslauf) ? "Lebenslauf" : "",
    ((document.getElementById("anschreibenFile") || {}).files || []).length || (student && student.anschreiben) ? "Anschreiben" : "",
    ((document.getElementById("zeugnisFile") || {}).files || []).length || (student && student.zeugnis) ? "Zeugnis" : "",
    ((document.getElementById("weiteresDokumentFile") || {}).files || []).length || (student && student.weiteresDokument) ? "Weiteres Dokument" : ""
  ].filter(Boolean);

  const name = getValue("name") || (student && student.name) || (auth && auth.name) || "Dein Name";
  const role = getValue("beruf") || (student && student.beruf) || "Wunschberuf";
  const city = getValue("stadt") || (student && student.stadt) || "Ort";
  const plz = getValue("plz") || (student && student.plz) || "";
  const school = getValue("schulabschluss") || (student && student.schulabschluss) || "Schulabschluss";
  const qualification = getValue("abgeschlosseneAusbildungStudium") || (student && student.abgeschlosseneAusbildungStudium) || "Keine abgeschlossene Ausbildung oder kein Studium angegeben";
  const mathGrade = getValue("noteMathe") || (student && student.noteMathe) || "";
  const germanGrade = getValue("noteDeutsch") || (student && student.noteDeutsch) || "";
  const englishGrade = getValue("noteEnglisch") || (student && student.noteEnglisch) || "";
  const electiveSubject = getValue("wahlfach") || (student && student.wahlfach) || "";
  const electiveGrade = getValue("noteWahlfach") || (student && student.noteWahlfach) || "";
  const strengths = getValue("besondereFaehigkeiten") || (student && student.besondereFaehigkeiten) || "Besondere Fähigkeiten und persönliche Stärken";
  const location = plz ? city + " (" + plz + ")" : city;
  const gradeParts = [
    mathGrade ? ("Mathe: " + formatGrade(mathGrade)) : "",
    germanGrade ? ("Deutsch: " + formatGrade(germanGrade)) : "",
    englishGrade ? ("Englisch: " + formatGrade(englishGrade)) : "",
    electiveGrade ? ((electiveSubject || "Wahlfach") + ": " + formatGrade(electiveGrade)) : ""
  ].filter(Boolean);

  previewCode.textContent = student && student.profilCode ? "Profilcode " + student.profilCode : "Kurzprofil-Vorschau";
  previewName.textContent = name;
  previewRole.textContent = role;
  previewLocation.textContent = location;
  previewSchool.textContent = school;
  previewQualification.textContent = qualification;
  previewGrades.textContent = gradeParts.length ? gradeParts.join(" • ") : "Noch keine Noten hinterlegt";
  previewStrengths.textContent = strengths;
  previewStatus.textContent = student
    ? getStudentMatchingVisibilityText(student)
    : "Unternehmen sehen zuerst nur dieses Kurzprofil. Vollständige Unterlagen bleiben bis zu deiner Freigabe geschützt.";
  previewLanguages.innerHTML = languages.length
    ? languages.map((language) => "<span class='bewerber-preview-chip'>" + escapeHtml(language) + "</span>").join("")
    : "<span class='bewerber-preview-chip bewerber-preview-chip--muted'>Noch keine Sprachen hinterlegt</span>";
  previewDocuments.innerHTML = documents.length
    ? documents.map((label) => "<span class='bewerber-preview-chip bewerber-preview-chip--strong'>" + escapeHtml(label) + "</span>").join("")
    : "<span class='bewerber-preview-chip bewerber-preview-chip--muted'>Noch keine Unterlagen hinterlegt</span>";
}

function bindStudentEntryPreview() {
  const previewPanel = document.getElementById("messagesPanel");
  if (!previewPanel || previewPanel.dataset.previewBound === "1") return;
  previewPanel.dataset.previewBound = "1";

  [
    "name", "beruf", "stadt", "plz", "schulabschluss", "abgeschlosseneAusbildungStudium", "besondereFaehigkeiten",
    "grundschuleVon", "grundschuleBis", "weiterfuehrendeSchulform", "weiterfuehrendeVon",
    "weiterfuehrendeBis", "noteMathe", "noteDeutsch", "noteEnglisch", "wahlfach", "noteWahlfach",
    "lebenslaufFile", "anschreibenFile", "zeugnisFile", "weiteresDokumentFile"
  ].forEach((id) => {
    const element = document.getElementById(id);
    if (!element) return;
    element.addEventListener("input", function() { renderStudentEntryPreview(); });
    element.addEventListener("change", function() { renderStudentEntryPreview(); });
  });

  const sprachenList = document.getElementById("sprachenList");
  const addSpracheBtn = document.getElementById("addSpracheBtn");
  if (sprachenList) {
    sprachenList.addEventListener("click", function() {
      setTimeout(function() { renderStudentEntryPreview(); }, 0);
    });
  }
  if (addSpracheBtn) {
    addSpracheBtn.addEventListener("click", function() {
      setTimeout(function() { renderStudentEntryPreview(); }, 0);
    });
  }
}

function renderStudentInternshipBaseInfo(authArg) {
  const container = document.getElementById("studentInternshipBaseInfo");
  if (!container) return;

  const snapshot = buildInternshipStudentBaseSnapshot(authArg, { preferInputs: true });
  const schoolLabel = snapshot.weiterfuehrendeSchulform || snapshot.schulabschluss || "Schulform oder Abschluss noch offen";
  const missing = [];
  if (!snapshot.name) missing.push("Name");
  if (!snapshot.stadt) missing.push("Ort");
  if (!snapshot.plz) missing.push("PLZ");

  container.innerHTML = "<strong>Automatisch übernommen:</strong> "
    + escapeHtml(snapshot.name || "Noch kein Name")
    + " • "
    + escapeHtml(snapshot.stadt || "Ort fehlt")
    + (snapshot.plz ? " (" + escapeHtml(snapshot.plz) + ")" : "")
    + " • "
    + escapeHtml(schoolLabel);

  if (missing.length) {
    container.innerHTML += "<br><span class='status'>Bitte ergänze in deinem Hauptprofil noch " + escapeHtml(missing.join(", ")) + ", damit das Praktikums-Matching vollständig arbeiten kann.</span>";
  }
}

