function initLandingLoginPage() {
  const form = document.getElementById("loginForm");
  if (!form) return;
  const emailInput = document.getElementById("email");
  const passwordInput = document.getElementById("password");
  const errorBox = document.getElementById("loginError");

  function showError(msg) {
    if (errorBox) {
      errorBox.textContent = msg || "Falsche Zugangsdaten oder E-Mail noch nicht bestätigt.";
      errorBox.classList.add("is-visible");
    }
  }
  function clearError() {
    if (errorBox) {
      errorBox.textContent = "";
      errorBox.classList.remove("is-visible");
    }
  }

  form.addEventListener("submit", async function(e) {
    e.preventDefault();
    clearError();

    const email = (emailInput ? emailInput.value : "").trim();
    const password = (passwordInput ? passwordInput.value : "").trim();
    if (!email || !password) {
      showError("Bitte E-Mail und Passwort eingeben.");
      return;
    }

    // --- Versuch 1: Bewerber-Login ---
    const studentUsers = loadRegisteredStudentUsers();
    const studentUser = studentUsers.find(function(u) { return normalizeText(u.email) === normalizeText(email); });
    if (studentUser) {
      if (!studentUser.emailConfirmed) {
        showError("Bitte bestätige zuerst deine E-Mail-Adresse.");
        return;
      }
      let check;
      try {
        check = await verifyStoredSecret(password, studentUser.passwordHash);
      } catch (err) {
        showError(err.message);
        return;
      }
      if (!check.valid) {
        showError("Passwort falsch. Bitte erneut versuchen.");
        return;
      }
      if (check.needsUpgrade) {
        studentUser.passwordHash = await createStoredSecret(password, { type: "password" });
        saveRegisteredStudentUsers(studentUsers);
      }
      const students = loadStudents();
      const student = students.find(function(s) { return s.userEmail === studentUser.email || s.email === studentUser.email; });
      const authId = (student && student.profilCode) ? student.profilCode : studentUser.id;
      const auth = {
        id: authId,
        name: studentUser.name,
        email: studentUser.email,
        emailConfirmed: !!studentUser.emailConfirmed,
        registeredAt: studentUser.registeredAt,
        loggedInAt: new Date().toISOString()
      };
      saveStoredStudentAuth(auth);
      if (student) {
        setActiveStudentId(student.id);
      }
      navigateWithTransition(buildRuntimeUrl("bewerber_profil.html"), "Dein Profil wird geöffnet...");
      return;
    }

    // --- Versuch 2: Firmen-Login ---
    const firmUsers = loadRegisteredFirmUsers();
    const firmUser = firmUsers.find(function(u) { return normalizeText(u.email) === normalizeText(email); });
    if (firmUser) {
      if (!firmUser.emailConfirmed) {
        showError("Bitte bestätige zuerst deine E-Mail-Adresse.");
        return;
      }
      let check;
      try {
        check = await verifyStoredSecret(password, firmUser.passwordHash);
      } catch (err) {
        showError(err.message);
        return;
      }
      if (!check.valid) {
        showError("Passwort falsch. Bitte erneut versuchen.");
        return;
      }
      if (check.needsUpgrade) {
        firmUser.passwordHash = await createStoredSecret(password, { type: "password" });
        saveRegisteredFirmUsers(firmUsers);
      }
      const auth = {
        id: firmUser.id,
        name: firmUser.name,
        email: firmUser.email,
        emailConfirmed: !!firmUser.emailConfirmed,
        registeredAt: firmUser.registeredAt,
        loggedInAt: new Date().toISOString()
      };
      saveStoredFirmAuth(auth);
      tryPostgresSync(firmUser.email, password, 'firm').catch(function() {});
      navigateWithTransition(buildRuntimeUrl("firma_profil.html"), "Firmen-Portal wird geöffnet...");
      return;
    }

    showError("Kein Konto mit dieser E-Mail-Adresse gefunden.");
  });
}

// ---------------------------------------------------------------------------
// Inaktivitäts-Auto-Logout
// ---------------------------------------------------------------------------
const IDLE_TIMEOUT_MS = 20 * 60 * 1000;   // 20 Minuten Inaktivität
const IDLE_WARN_BEFORE_MS = 60 * 1000;    // Warnung 60 Sek. vorher

(function initIdleLogout() {
  let idleTimer = 0;
  let warnTimer = 0;
  let warnToast = null;
  let active = false;

  function isAnySessionActive() {
    return !!(getStoredStudentAuth() || getStoredFirmAuth());
  }

  function doLogout() {
    clearStoredStudentAuth();
    clearStoredFirmAuth();
    if (warnToast && warnToast.parentNode) warnToast.parentNode.removeChild(warnToast);
    warnToast = null;
    navigateWithTransition(buildRuntimeUrl("anmeldung.html"), "Du wurdest wegen Inaktivität automatisch abgemeldet.");
  }

  function showWarnToast() {
    if (warnToast) return;
    warnToast = document.createElement("div");
    warnToast.setAttribute("role", "alert");
    warnToast.setAttribute("aria-live", "assertive");
    Object.assign(warnToast.style, {
      position: "fixed",
      bottom: "24px",
      left: "50%",
      transform: "translateX(-50%)",
      background: "#1e40af",
      color: "#fff",
      padding: "14px 24px",
      borderRadius: "10px",
      boxShadow: "0 4px 24px rgba(0,0,0,.25)",
      fontSize: "15px",
      zIndex: "99999",
      maxWidth: "90vw",
      textAlign: "center",
      lineHeight: "1.5"
    });
    warnToast.textContent = "Du wirst in 60 Sekunden automatisch abgemeldet. Bewege die Maus oder tippe, um angemeldet zu bleiben.";
    document.body.appendChild(warnToast);
  }

  function hideWarnToast() {
    if (warnToast && warnToast.parentNode) warnToast.parentNode.removeChild(warnToast);
    warnToast = null;
  }

  function resetTimers() {
    clearTimeout(idleTimer);
    clearTimeout(warnTimer);
    hideWarnToast();
    if (!isAnySessionActive()) return;
    warnTimer = setTimeout(showWarnToast, IDLE_TIMEOUT_MS - IDLE_WARN_BEFORE_MS);
    idleTimer = setTimeout(doLogout, IDLE_TIMEOUT_MS);
  }

  function onActivity() {
    if (!isAnySessionActive()) {
      if (active) {
        // Session wurde inzwischen beendet – Listener entfernen
        ["mousemove", "mousedown", "keydown", "touchstart", "scroll"].forEach(function(ev) {
          document.removeEventListener(ev, onActivity, true);
        });
        active = false;
      }
      return;
    }
    resetTimers();
  }

  function start() {
    if (active) return;
    active = true;
    ["mousemove", "mousedown", "keydown", "touchstart", "scroll"].forEach(function(ev) {
      document.addEventListener(ev, onActivity, { capture: true, passive: true });
    });
    resetTimers();
  }

  // Nur starten wenn eine Session aktiv ist
  if (isAnySessionActive()) {
    start();
  }

  // Auch nach Login-Navigationen prüfen (z. B. nach DOMContentLoaded)
  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", function() {
      if (isAnySessionActive()) start();
    }, { once: true });
  }
})();

function shouldShowPageShareButton() {
  if (!document.querySelector(".start-wrapper")) return false;
  if (document.querySelector(".profile-shell-wrapper")) return false;
  if (document.getElementById("adminPortal") || document.getElementById("adminLoginPanel")) return false;
  return !!document.querySelector(".index-topbar-actions");
}

function getPageSharePayload() {
  const metaDescription = document.querySelector('meta[name="description"]');
  const title = String(document.title || "AzubiMatcher").trim() || "AzubiMatcher";
  const text = metaDescription && metaDescription.content
    ? String(metaDescription.content).trim()
    : "Schau dir diese Seite auf AzubiMatcher an.";
  return {
    title: title,
    text: text,
    url: window.location.href
  };
}

async function copyPageShareUrl(url) {
  if (navigator.clipboard && typeof navigator.clipboard.writeText === "function" && window.isSecureContext) {
    await navigator.clipboard.writeText(url);
    return true;
  }

  const helper = document.createElement("textarea");
  helper.value = url;
  helper.setAttribute("readonly", "readonly");
  helper.style.position = "fixed";
  helper.style.opacity = "0";
  helper.style.pointerEvents = "none";
  document.body.appendChild(helper);
  helper.focus();
  helper.select();

  let copied = false;
  try {
    copied = document.execCommand("copy");
  } catch (error) {
    copied = false;
  }

  if (helper.parentNode) {
    helper.parentNode.removeChild(helper);
  }

  return copied;
}

function setPageShareButtonState(button, label, state) {
  if (!(button instanceof HTMLElement)) return;

  const labelNode = button.querySelector(".page-share-btn__label");
  if (labelNode) {
    labelNode.textContent = label;
  }
  button.dataset.shareState = state || "idle";

  window.clearTimeout(button.__shareResetTimer);
  if (state && state !== "idle") {
    button.__shareResetTimer = window.setTimeout(function() {
      if (!(button instanceof HTMLElement)) return;
      const resetLabelNode = button.querySelector(".page-share-btn__label");
      if (resetLabelNode) {
        resetLabelNode.textContent = "Diese Seite teilen";
      }
      button.dataset.shareState = "idle";
    }, 2400);
  }
}

async function handlePageShare(button) {
  const payload = getPageSharePayload();

  if (navigator.share && typeof navigator.share === "function") {
    try {
      await navigator.share(payload);
      setPageShareButtonState(button, "Danke fürs Teilen", "shared");
      return;
    } catch (error) {
      if (error && error.name === "AbortError") {
        return;
      }
    }
  }

  const copied = await copyPageShareUrl(payload.url);
  if (copied) {
    setPageShareButtonState(button, "Link kopiert", "copied");
    return;
  }

  window.prompt("Link zum Teilen:", payload.url);
}

function initPageShareButton() {
  if (!shouldShowPageShareButton()) return;

  const mount = document.querySelector(".index-topbar-actions");
  if (!mount || mount.querySelector("[data-share-page='true']")) return;

  const button = document.createElement("button");
  button.type = "button";
  button.className = "btn ghost page-share-btn";
  button.dataset.sharePage = "true";
  button.dataset.shareState = "idle";
  button.setAttribute("aria-label", "Diese Seite mit Freunden teilen");
  button.innerHTML = ""
    + "<span class='page-share-btn__icon' aria-hidden='true'>↗</span>"
    + "<span class='page-share-btn__label'>Diese Seite teilen</span>";
  button.addEventListener("click", function() {
    handlePageShare(button);
  });

  mount.insertBefore(button, mount.firstChild);
}

function initTopbarHoverPreview() {
  const clusters = Array.from(document.querySelectorAll(".index-nav-cluster"));
  if (!clusters.length) return;

  function comparableNavKey(rawHref) {
    const href = String(rawHref || "").trim();
    if (!href) return "";
    if (href.charAt(0) === "#") {
      return href.toLowerCase();
    }

    try {
      const parsed = new URL(href, window.location.href);
      return parsed.pathname.toLowerCase();
    } catch (error) {
      return href.toLowerCase();
    }
  }

  function dedupeSecondaryNavAgainstMain(cluster) {
    const metaNav = cluster.querySelector(".index-meta-nav");
    if (!metaNav) return;

    const mainKeys = new Set(
      Array.from(cluster.querySelectorAll(".index-nav a[href]")).map(function(link) {
        return comparableNavKey(link.getAttribute("href"));
      }).filter(Boolean)
    );

    Array.from(metaNav.querySelectorAll("a[href]")).forEach(function(link) {
      const key = comparableNavKey(link.getAttribute("href"));
      if (!key || !mainKeys.has(key)) return;
      if (link.parentNode) {
        link.parentNode.removeChild(link);
      }
    });
  }

  function syncMetaLinksIntoDirectory(cluster) {
    const panel = cluster.querySelector(".index-directory-panel");
    const metaNav = cluster.querySelector(".index-meta-nav");
    if (!panel || !metaNav) return;

    const metaLinks = Array.from(metaNav.querySelectorAll("a[href]"));
    let metaGroup = panel.querySelector(".index-directory-group--meta");

    if (!metaLinks.length) {
      if (metaGroup && metaGroup.parentNode) {
        metaGroup.parentNode.removeChild(metaGroup);
      }
      return;
    }

    if (!metaGroup) {
      metaGroup = document.createElement("div");
      metaGroup.className = "index-directory-group index-directory-group--meta";

      const title = document.createElement("span");
      title.className = "index-directory-title";
      title.textContent = "Schnellzugriff";
      metaGroup.appendChild(title);

      panel.appendChild(metaGroup);
    }

    Array.from(metaGroup.querySelectorAll("a[data-meta-clone='true']")).forEach(function(link) {
      if (link.parentNode) {
        link.parentNode.removeChild(link);
      }
    });

    metaLinks.forEach(function(sourceLink) {
      const cloned = sourceLink.cloneNode(true);
      cloned.setAttribute("data-meta-clone", "true");
      metaGroup.appendChild(cloned);
    });
  }

  clusters.forEach(function(cluster) {
    if (cluster.dataset.hoverPreviewBound === "true") return;

    dedupeSecondaryNavAgainstMain(cluster);

    syncMetaLinksIntoDirectory(cluster);

    const navLinks = Array.from(cluster.querySelectorAll(".index-nav a[href]"));
    const panelLinks = Array.from(cluster.querySelectorAll(".index-directory-panel a[href]"));
    if (!navLinks.length || !panelLinks.length) return;

    cluster.dataset.hoverPreviewBound = "true";

    function clearPreview() {
      panelLinks.forEach(function(link) {
        link.removeAttribute("data-nav-match");
      });

      Array.from(cluster.querySelectorAll(".index-directory-group[data-nav-match-group='true']")).forEach(function(group) {
        group.removeAttribute("data-nav-match-group");
      });
    }

    function setPreview(targetHref) {
      clearPreview();
      if (!targetHref) return;

      panelLinks.forEach(function(link) {
        if (link.getAttribute("href") !== targetHref) return;
        link.setAttribute("data-nav-match", "true");
        const group = link.closest(".index-directory-group");
        if (group) {
          group.setAttribute("data-nav-match-group", "true");
        }
      });
    }

    navLinks.forEach(function(link) {
      const href = link.getAttribute("href");
      link.addEventListener("mouseenter", function() {
        setPreview(href);
      });
      link.addEventListener("focus", function() {
        setPreview(href);
      });
    });

    cluster.addEventListener("mouseleave", clearPreview);
    cluster.addEventListener("focusout", function(event) {
      if (cluster.contains(event.relatedTarget)) return;
      clearPreview();
    });
  });
}

let pageInitializersBound = false;

function runPageInitializers() {
  if (pageInitializersBound) return;
  pageInitializersBound = true;

  initPageShareButton();
  initTopbarHoverPreview();

  if (document.getElementById("saveBewerber")) {
    initStudentPortal();
  }

  if (document.getElementById("studentProfileContent")) {
    initStudentProfilePage();
  }

  if (document.getElementById("studentInternshipWorkspace")) {
    initStudentInternshipPage();
  }

  if (document.getElementById("saveFirma")) {
    initFirmAuth();
  }

  if (document.getElementById("firmProfileContent")) {
    initFirmProfilePage();
  }

  if (document.getElementById("firmInternshipWorkspace")) {
    initFirmInternshipPage();
  }

  if (document.getElementById("mobileAppWorkspace")) {
    initMobileAppShell();
  }

  if (document.getElementById("studentMobileAppWorkspace")) {
    initStudentMobileAppPage();
  }

  if (document.getElementById("adminLoginPanel")) {
    initAdminPortal();
  }

  if (document.getElementById("matchingByProfession") && document.getElementById("adminPortal")) {
    initAdminMatchingOverview();
  }

  // Login-Handler wird durch den inline-Script in anmeldung.html abgedeckt
  // (benutzt buildRuntimeUrl für WordPress-kompatible Navigation)
}

if (document.readyState === "loading") {
  document.addEventListener("DOMContentLoaded", runPageInitializers, { once: true });
} else {
  runPageInitializers();
}

function initBerufsCarousel() {
  const viewport = document.querySelector(".carousel-viewport");
  const track = document.querySelector(".beruf-track");
  const prevBtn = document.querySelector(".carousel-prev");
  const nextBtn = document.querySelector(".carousel-next");
  const dotsContainer = document.querySelector(".carousel-dots");
  if (!track || !viewport || !dotsContainer) return;

  const cards = [...track.querySelectorAll(".beruf-card")];
  const GAP = 17.6; // 1.1rem at 16px base
  let perPage = window.innerWidth <= 640 ? 1 : 3;
  let totalPages = Math.ceil(cards.length / perPage);
  let currentPage = 0;
  let autoTimer = null;

  function professionSlug(value) {
    return normalizeProfessionText(value).replace(/\s+/g, "-");
  }

  function openProfessionPage(slug) {
    if (!slug) return;
    const params = new URLSearchParams(window.location.search);
    const next = new URLSearchParams();
    next.set("beruf", slug);
    const theme = (params.get("theme") || "").trim().toLowerCase();
    if (theme === "cool" || theme === "navy") next.set("theme", theme);
    navigateWithTransition("lehrberufe.html?" + next.toString(), "Berufsprofil wird geöffnet...");
  }

  cards.forEach(function(card) {
    const title = (card.querySelector("h3") || {}).textContent || "";
    const slug = professionSlug(title);
    if (!slug) return;

    card.dataset.berufSlug = slug;
    card.classList.add("beruf-card-link");
    card.setAttribute("role", "link");
    card.setAttribute("tabindex", "0");
    card.setAttribute("aria-label", title.trim() + " ansehen");

    card.addEventListener("click", function() {
      openProfessionPage(slug);
    });

    card.addEventListener("keydown", function(event) {
      if (event.key === "Enter" || event.key === " ") {
        event.preventDefault();
        openProfessionPage(slug);
      }
    });
  });

  function sizeCards() {
    const w = (viewport.offsetWidth - (perPage - 1) * GAP) / perPage;
    cards.forEach(function(c) {
      c.style.flexBasis = w + "px";
      c.style.maxWidth = w + "px";
    });
  }

  function buildDots() {
    dotsContainer.innerHTML = "";
    for (let i = 0; i < totalPages; i++) {
      const dot = document.createElement("button");
      dot.className = "carousel-dot" + (i === 0 ? " active" : "");
      dot.setAttribute("aria-label", "Seite " + (i + 1));
      dot.addEventListener("click", (function(idx) {
        return function() { goTo(idx); resetAuto(); };
      })(i));
      dotsContainer.appendChild(dot);
    }
  }

  function goTo(page) {
    currentPage = Math.max(0, Math.min(page, totalPages - 1));
    const offset = currentPage * (viewport.offsetWidth + GAP);
    track.style.transform = "translateX(-" + offset + "px)";
    [...dotsContainer.querySelectorAll(".carousel-dot")].forEach(function(d, i) {
      d.classList.toggle("active", i === currentPage);
    });
    prevBtn.disabled = currentPage === 0;
    nextBtn.disabled = currentPage >= totalPages - 1;
  }

  function resetAuto() {
    clearInterval(autoTimer);
    autoTimer = setInterval(function() {
      goTo(currentPage >= totalPages - 1 ? 0 : currentPage + 1);
    }, 4500);
  }

  prevBtn.addEventListener("click", function() { goTo(currentPage - 1); resetAuto(); });
  nextBtn.addEventListener("click", function() { goTo(currentPage + 1); resetAuto(); });

  viewport.addEventListener("mouseenter", function() { clearInterval(autoTimer); });
  viewport.addEventListener("mouseleave", resetAuto);

  // Touch swipe support
  let touchStartX = 0;
  viewport.addEventListener("touchstart", function(e) {
    touchStartX = e.changedTouches[0].clientX;
  }, { passive: true });
  viewport.addEventListener("touchend", function(e) {
    const diff = touchStartX - e.changedTouches[0].clientX;
    if (Math.abs(diff) > 40) {
      goTo(diff > 0 ? currentPage + 1 : currentPage - 1);
      resetAuto();
    }
  }, { passive: true });

  window.addEventListener("resize", function() {
    const newPer = window.innerWidth <= 640 ? 1 : 3;
    if (newPer !== perPage) {
      perPage = newPer;
      totalPages = Math.ceil(cards.length / perPage);
      buildDots();
    }
    sizeCards();
    goTo(Math.min(currentPage, totalPages - 1));
  });

  sizeCards();
  buildDots();
  goTo(0);
  resetAuto();
}

