function openStudentDocument(studentId, docType) {
  const students = loadStudents();
  const student = students.find((s) => s.id === studentId);
  if (!student) {
    alert("Profil nicht gefunden.");
    return;
  }

  let fileObj = null;
  if (docType === "lebenslauf") fileObj = student.lebenslauf;
  if (docType === "anschreiben") fileObj = student.anschreiben;
  if (docType === "zeugnis") fileObj = student.zeugnis;
  if (docType === "weiteresDokument") fileObj = student.weiteresDokument;
  if (docType === "profilbild") fileObj = student.profilBild;

  if (!fileObj || !fileObj.dataUrl) {
    alert("Dokument wurde nicht hochgeladen.");
    return;
  }

  const mimeType = resolveDocumentMimeType(fileObj);
  const viewableInBrowser = isBrowserViewableMimeType(mimeType);

  if (!viewableInBrowser) {
    downloadFileData(fileObj);
    alert("Dieser Dateityp kann nicht direkt im Browser angezeigt werden und wurde stattdessen heruntergeladen.");
    return;
  }

  const opened = window.open(fileObj.dataUrl, "_blank", "noopener,noreferrer");
  if (!opened) {
    // Popup blocked or browser prevented opening a large data URL.
    downloadFileData(fileObj);
    alert("Dokument konnte nicht in einem neuen Tab geöffnet werden und wurde stattdessen heruntergeladen.");
  }
}

function openFirmDocument(offerId, docType) {
  const offers = loadOffers();
  const offer = offers.find((o) => o.id === offerId);
  if (!offer) {
    alert("Firmenprofil nicht gefunden.");
    return;
  }

  const dataUrl = offer[docType];
  if (!dataUrl) {
    alert("Dokument wurde nicht hochgeladen.");
    return;
  }

  const mimeType = resolveDocumentMimeType(dataUrl);
  if (!isBrowserViewableMimeType(mimeType)) {
    downloadFileData({ dataUrl: dataUrl, name: docType + ".bin" });
    alert("Dieser Dateityp kann nicht direkt im Browser angezeigt werden und wurde stattdessen heruntergeladen.");
    return;
  }

  const opened = window.open(dataUrl, "_blank", "noopener,noreferrer");
  if (!opened) {
    downloadFileData({ dataUrl: dataUrl, name: docType + ".bin" });
    alert("Dokument konnte nicht in einem neuen Tab geöffnet werden und wurde stattdessen heruntergeladen.");
  }
}

function normalizeGradeToken(token) {
  const value = String(token || "").toLowerCase().trim();
  if (!value) return null;

  if (/^[1-6]$/.test(value)) return value;
  if (value === "i" || value === "l") return "1";

  if (value.includes("sehr gut")) return "1";
  if (value === "gut" || value.includes(" gut")) return "2";
  if (value.includes("befriedigend")) return "3";
  if (value.includes("ausreichend")) return "4";
  if (value.includes("mangelhaft")) return "5";
  if (value.includes("ungen\u00fcgend") || value.includes("ungen\u00fcgend")) return "6";

  return null;
}

function extractGradeFromText(rawText, subjectRegex, fallbackToken) {
  const text = String(rawText || "");
  const directRegex = new RegExp(subjectRegex + "[^\\n\\r]{0,28}?(1|2|3|4|5|6|sehr\\s+gut|gut|befriedigend|ausreichend|mangelhaft|ungen(?:u|\\u00fc)gend)", "i");
  const matchDirect = text.match(directRegex);
  if (matchDirect && matchDirect[1]) {
    return normalizeGradeToken(matchDirect[1]);
  }

  const reverseRegex = new RegExp("(1|2|3|4|5|6|sehr\\s+gut|gut|befriedigend|ausreichend|mangelhaft|ungen(?:u|\\u00fc)gend)[^\\n\\r]{0,16}?" + subjectRegex, "i");
  const matchReverse = text.match(reverseRegex);
  if (matchReverse && matchReverse[1]) {
    return normalizeGradeToken(matchReverse[1]);
  }

  return normalizeGradeToken(fallbackToken);
}

function buildComparisonRow(label, profileGrade, extractedGrade) {
  const hasExtracted = !!extractedGrade;
  const isMatch = hasExtracted && String(profileGrade || "") === String(extractedGrade || "");
  const badge = !hasExtracted
    ? "<span style='color:#92400e;background:#fef3c7;padding:0.15rem 0.45rem;border-radius:999px;'>nicht erkannt</span>"
    : isMatch
      ? "<span style='color:#166534;background:#dcfce7;padding:0.15rem 0.45rem;border-radius:999px;'>stimmt</span>"
      : "<span style='color:#991b1b;background:#fee2e2;padding:0.15rem 0.45rem;border-radius:999px;'>abweichend</span>";

  return ""
    + "<tr>"
    + "<td style='padding:0.35rem 0.5rem;border-bottom:1px solid #e5e7eb;'><strong>" + escapeHtml(label) + "</strong></td>"
    + "<td style='padding:0.35rem 0.5rem;border-bottom:1px solid #e5e7eb;'>" + escapeHtml(profileGrade || "-") + "</td>"
    + "<td style='padding:0.35rem 0.5rem;border-bottom:1px solid #e5e7eb;'>" + escapeHtml(extractedGrade || "-") + "</td>"
    + "<td style='padding:0.35rem 0.5rem;border-bottom:1px solid #e5e7eb;'>" + badge + "</td>"
    + "</tr>";
}

function getAutoPendingGradeCheckState() {
  if (!window.__azubiMatchAutoPendingGradeCheck) {
    window.__azubiMatchAutoPendingGradeCheck = {
      running: false,
      queuedIds: null
    };
  }
  return window.__azubiMatchAutoPendingGradeCheck;
}

function getAutoStudentVerificationState() {
  if (!window.__azubiMatchAutoStudentVerification) {
    window.__azubiMatchAutoStudentVerification = {
      running: false,
      queuedIds: null
    };
  }
  return window.__azubiMatchAutoStudentVerification;
}

function buildStudentAutoVerificationSignature(student) {
  const lebenslauf = student && student.lebenslauf ? student.lebenslauf : null;
  return [
    buildStudentGradeCheckSignature(student),
    student && student.name,
    lebenslauf && lebenslauf.name,
    lebenslauf && lebenslauf.size,
    lebenslauf && lebenslauf.type
  ].join("|");
}

function scheduleAutoStudentVerification(studentIds) {
  const state = getAutoStudentVerificationState();
  const ids = Array.isArray(studentIds) ? studentIds.filter(Boolean) : [];
  if (!ids.length) return;

  if (state.running) {
    state.queuedIds = ids;
    return;
  }

  window.setTimeout(() => {
    runAutoStudentVerification(ids);
  }, 180);
}

async function runAutoStudentVerification(studentIds) {
  const state = getAutoStudentVerificationState();
  if (state.running) {
    state.queuedIds = studentIds;
    return;
  }

  state.running = true;
  let pendingIds = Array.isArray(studentIds) ? studentIds.slice() : [];

  try {
    while (pendingIds.length) {
      let approvedAny = false;

      for (const studentId of pendingIds) {
        const students = loadStudents();
        const student = students.find((entry) => entry.id === studentId);
        if (!student || student.verified) continue;

        // Auto-Freigabe nur für vollständig gespeicherte Profile mit beiden Pflichtdokumenten.
        if (!student.registrierungAbgeschlossen) continue;
        if (!student.zeugnis || !student.zeugnis.dataUrl || !student.lebenslauf || !student.lebenslauf.dataUrl) continue;

        const signature = buildStudentAutoVerificationSignature(student);
        const autoState = student.autoAdminVerification || {};
        const alreadyBlocked = autoState.signature === signature && (autoState.status === "blocked" || autoState.status === "error");
        const alreadyApproved = autoState.signature === signature && autoState.status === "approved";
        if (alreadyBlocked || alreadyApproved) continue;

        try {
          const verified = await verifyStudentById(studentId);
          if (verified) {
            const afterStudents = loadStudents();
            const afterStudent = afterStudents.find((entry) => entry.id === studentId);
            if (afterStudent) {
              afterStudent.autoAdminVerification = {
                signature: signature,
                checkedAt: new Date().toISOString(),
                status: "approved",
                lastError: ""
              };
              saveStudents(afterStudents);
            }
            approvedAny = true;
          }
        } catch (err) {
          const retryStudents = loadStudents();
          const retryStudent = retryStudents.find((entry) => entry.id === studentId);
          if (retryStudent) {
            retryStudent.autoAdminVerification = {
              signature: signature,
              checkedAt: new Date().toISOString(),
              status: err && (err.code === "NAME_CHECK_FAILED" || err.code === "GRADE_MISMATCH" || err.code === "GRADE_CHECK_FAILED")
                ? "blocked"
                : "error",
              lastError: String((err && err.message) || "Unbekannter Fehler")
            };
            saveStudents(retryStudents);
          }
        }
      }

      if (approvedAny) {
        renderStudentsList("unverified");
        updateAdminStats();
      }

      if (state.queuedIds && state.queuedIds.length) {
        pendingIds = state.queuedIds.slice();
        state.queuedIds = null;
      } else {
        pendingIds = [];
      }
    }
  } finally {
    state.running = false;
  }
}

function buildStudentGradeCheckSignature(student) {
  const zeugnis = student && student.zeugnis ? student.zeugnis : null;
  return [
    student && student.id,
    student && student.updatedAt,
    zeugnis && zeugnis.name,
    zeugnis && zeugnis.size,
    zeugnis && zeugnis.type,
    student && student.noteMathe,
    student && student.noteDeutsch,
    student && student.noteEnglisch,
    student && student.wahlfach,
    student && student.noteWahlfach
  ].join("|");
}

function computeGradeComparisonForStudent(student, ocrText) {
  const extractedMathe = extractGradeFromText(ocrText, "(?:mathe|mathematik)");
  const extractedDeutsch = extractGradeFromText(ocrText, "deutsch");
  const extractedEnglisch = extractGradeFromText(ocrText, "englisch");
  let extractedWahlfach = null;

  if (student.wahlfach) {
    const escapedWahlfach = String(student.wahlfach).replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    extractedWahlfach = extractGradeFromText(ocrText, escapedWahlfach);
  }

  const subjects = [
    { label: "Mathe", profile: student.noteMathe, extracted: extractedMathe },
    { label: "Deutsch", profile: student.noteDeutsch, extracted: extractedDeutsch },
    { label: "Englisch", profile: student.noteEnglisch, extracted: extractedEnglisch }
  ];

  if (student.wahlfach) {
    subjects.push({ label: student.wahlfach, profile: student.noteWahlfach, extracted: extractedWahlfach });
  }

  const rows = subjects.map((entry) => buildComparisonRow(entry.label, entry.profile, entry.extracted));
  const mismatchSubjects = subjects
    .filter((entry) => entry.extracted && String(entry.profile || "") !== String(entry.extracted || ""))
    .map((entry) => entry.label);

  return {
    rows: rows,
    subjects: subjects,
    mismatchCount: mismatchSubjects.length,
    mismatchSubjects: mismatchSubjects
  };
}

async function analyzeStudentZeugnisComparison(student) {
  if (!student || !student.zeugnis || !student.zeugnis.dataUrl) {
    throw new Error("Kein Zeugnis zum Scannen vorhanden.");
  }

  let sourceDataUrl = student.zeugnis.dataUrl;
  const mimeType = resolveDocumentMimeType(student.zeugnis);

  if (mimeType === "application/pdf") {
    const pdfBytes = dataUrlToUint8Array(student.zeugnis.dataUrl);
    const pdfBlob = new Blob([pdfBytes], { type: "application/pdf" });
    const pngBlob = await convertPdfFirstPageToPng(pdfBlob, 2 * 1024 * 1024);
    sourceDataUrl = await readBlobAsDataUrl(pngBlob);
  } else if (!mimeType.startsWith("image/")) {
    throw new Error("OCR ist aktuell nur für Bilddateien oder PDF verfügbar.");
  }

  const ocrText = await extractTextWithLocalOcr(sourceDataUrl);
  const comparison = computeGradeComparisonForStudent(student, ocrText);

  return {
    ocrText: ocrText,
    rows: comparison.rows,
    mismatchCount: comparison.mismatchCount,
    mismatchSubjects: comparison.mismatchSubjects
  };
}

function renderGradeComparisonResultHtml(result, titlePrefix) {
  const summary = result.mismatchCount === 0
    ? "<p style='margin:0 0 0.6rem;color:#166534;'><strong>Ergebnis:</strong> Keine Abweichungen erkannt.</p>"
    : "<p style='margin:0 0 0.6rem;color:#991b1b;'><strong>Ergebnis:</strong> " + result.mismatchCount + " Abweichung(en) erkannt.</p>";

  const prefix = titlePrefix
    ? "<p style='margin:0 0 0.5rem;color:#1e3a8a;font-weight:600;'>" + escapeHtml(titlePrefix) + "</p>"
    : "";

  return ""
    + "<div style='border:1px solid #dbeafe;background:#eff6ff;border-radius:6px;padding:0.8rem;'>"
    + prefix
    + summary
    + "<div style='overflow:auto;'>"
    + "<table style='width:100%;border-collapse:collapse;font-size:0.88rem;color:#1f2937;'>"
    + "<thead><tr><th style='text-align:left;padding:0.35rem 0.5rem;border-bottom:1px solid #cbd5e1;'>Fach</th><th style='text-align:left;padding:0.35rem 0.5rem;border-bottom:1px solid #cbd5e1;'>Profil</th><th style='text-align:left;padding:0.35rem 0.5rem;border-bottom:1px solid #cbd5e1;'>Zeugnis (OCR)</th><th style='text-align:left;padding:0.35rem 0.5rem;border-bottom:1px solid #cbd5e1;'>Status</th></tr></thead>"
    + "<tbody>" + result.rows.join("") + "</tbody>"
    + "</table>"
    + "</div>"
    + "<p style='margin:0.6rem 0 0;color:#64748b;font-size:0.82rem;'>Hinweis: OCR kann je nach Bildqualität fehlerhaft sein. Ergebnis manuell prüfen.</p>"
    + "</div>";
}

function scheduleAutoPendingGradeChecks(studentIds) {
  const state = getAutoPendingGradeCheckState();
  const ids = Array.isArray(studentIds) ? studentIds.filter(Boolean) : [];
  if (!ids.length) return;

  if (state.running) {
    state.queuedIds = ids;
    return;
  }

  window.setTimeout(() => {
    runAutoPendingGradeChecks(ids);
  }, 120);
}

async function runAutoPendingGradeChecks(studentIds) {
  const state = getAutoPendingGradeCheckState();
  if (state.running) {
    state.queuedIds = studentIds;
    return;
  }

  state.running = true;
  let pendingIds = Array.isArray(studentIds) ? studentIds.slice() : [];

  try {
    while (pendingIds.length) {
      for (const studentId of pendingIds) {
        const resultEl = document.getElementById("scanResult_" + studentId);
        if (!resultEl) continue;

        const students = loadStudents();
        const student = students.find((entry) => entry.id === studentId);
        if (!student || student.verified || !student.zeugnis || !student.zeugnis.dataUrl) continue;

        const signature = buildStudentGradeCheckSignature(student);
        const alreadyChecked = student.autoGradeCheck && student.autoGradeCheck.signature === signature;
        if (alreadyChecked && Array.isArray(student.autoGradeCheck.rows)) {
          resultEl.innerHTML = renderGradeComparisonResultHtml({
            rows: student.autoGradeCheck.rows,
            mismatchCount: student.autoGradeCheck.mismatchCount || 0
          }, "Automatische Prüfung (ausstehend)");
          continue;
        }

        resultEl.innerHTML = "<p style='margin:0;color:#1e3a8a;'>Automatische Notenprüfung läuft...</p>";

        try {
          const analysis = await analyzeStudentZeugnisComparison(student);
          resultEl.innerHTML = renderGradeComparisonResultHtml(analysis, "Automatische Prüfung (ausstehend)");

          student.autoGradeCheck = {
            signature: signature,
            checkedAt: new Date().toISOString(),
            mismatchCount: analysis.mismatchCount,
            mismatchSubjects: analysis.mismatchSubjects,
            rows: analysis.rows,
            warningMailSentAt: student.autoGradeCheck ? student.autoGradeCheck.warningMailSentAt || "" : "",
            warningMailSignature: student.autoGradeCheck ? student.autoGradeCheck.warningMailSignature || "" : ""
          };

          if (analysis.mismatchCount > 0 && student.autoGradeCheck.warningMailSignature !== signature) {
            const target = resolveStudentNotificationTarget(student);
            if (target.email) {
              try {
                const subjectText = analysis.mismatchSubjects.length ? analysis.mismatchSubjects.join(", ") : "mindestens ein Fach";
                const checkedAt = new Date().toLocaleString("de-DE");
                await sendNotificationEmail({
                  email: target.email,
                  name: target.name || student.name || "Profil",
                  title: "Hinweis: Abweichung in Ihren Profildaten",
                  message: "Hallo " + (target.name || student.name || "") + ",\n\n"
                    + "bei der automatischen Dokumentenprüfung wurden Abweichungen zwischen Ihren Profilangaben und den eingereichten Unterlagen festgestellt.\n"
                    + "Betroffene Fächer: " + subjectText + "\n"
                    + "Prüfzeitpunkt: " + checkedAt + "\n\n"
                    + "Bitte überprüfen Sie Ihre Angaben im Profil sowie die hochgeladenen Dokumente und korrigieren Sie diese bei Bedarf.\n"
                    + "Sobald die Daten übereinstimmen, kann Ihre Verifizierung ohne Verzögerung fortgesetzt werden.\n\n"
                    + "Wenn Sie Fragen haben, melden Sie sich bitte beim AzubiMatch-Support.\n\n"
                    + "Freundliche Grüße\n"
                    + "Ihr AzubiMatch-Team"
                });
                student.autoGradeCheck.warningMailSentAt = new Date().toISOString();
                student.autoGradeCheck.warningMailSignature = signature;
              } catch (mailErr) {
                // Mail failure should not block verification workflow UI updates.
              }
            }
          }

          saveStudents(students);
        } catch (err) {
          resultEl.innerHTML = "<p style='margin:0;color:#991b1b;'>Automatische Prüfung fehlgeschlagen: " + escapeHtml(err.message || "Unbekannter Fehler") + "</p>";
        }
      }

      if (state.queuedIds && state.queuedIds.length) {
        pendingIds = state.queuedIds.slice();
        state.queuedIds = null;
      } else {
        pendingIds = [];
      }
    }
  } finally {
    state.running = false;
  }
}

function ensureTesseractLoaded() {
  if (window.Tesseract && typeof window.Tesseract.recognize === "function") {
    return Promise.resolve(window.Tesseract);
  }

  if (!window.__azubiMatchTesseractPromise) {
    window.__azubiMatchTesseractPromise = loadLegacyGlobalOnce(
      "vendor/tesseract/tesseract.min.js",
      "tesseract",
      "Tesseract",
      function(candidate) {
        return !!candidate && typeof candidate.recognize === "function";
      }
    ).then(function(tesseract) {
      if (tesseract && typeof tesseract.setLogging === "function") {
        tesseract.setLogging(false);
      }
      window.Tesseract = tesseract;
      return tesseract;
    }).catch(function(error) {
      delete window.__azubiMatchTesseractPromise;
      throw error;
    });
  }

  return window.__azubiMatchTesseractPromise;
}

function getLocalTesseractOptions() {
  return {
    workerPath: getRuntimeAssetUrl("vendor/tesseract/worker.min.js"),
    corePath: getRuntimeAssetUrl("vendor/tesseract/tesseract-core-lstm.wasm.js"),
    langPath: getRuntimeAssetUrl("vendor/tesseract/lang-data/")
  };
}

async function extractTextWithLocalOcr(sourceDataUrl) {
  const tesseract = await ensureTesseractLoaded();
  const ocrResult = await tesseract.recognize(sourceDataUrl, "deu+eng", getLocalTesseractOptions());
  return String((ocrResult && ocrResult.data && ocrResult.data.text) || "").trim();
}

async function scanAndCompareStudentZeugnis(studentId, triggerBtn) {
  const resultEl = document.getElementById("scanResult_" + studentId);
  if (resultEl) {
    resultEl.innerHTML = "<p style='margin:0;color:#1e3a8a;'>OCR läuft, bitte warten...</p>";
  }

  const students = loadStudents();
  const student = students.find((s) => s.id === studentId);
  if (!student || !student.zeugnis || !student.zeugnis.dataUrl) {
    if (resultEl) resultEl.innerHTML = "<p style='margin:0;color:#991b1b;'>Kein Zeugnis zum Scannen vorhanden.</p>";
    return;
  }

  if (triggerBtn) {
    triggerBtn.disabled = true;
    triggerBtn.textContent = "Scan läuft...";
  }

  try {
    await ensureTesseractLoaded();
    const analysis = await analyzeStudentZeugnisComparison(student);
    if (resultEl) {
      resultEl.innerHTML = renderGradeComparisonResultHtml(analysis, "Manuelle Prüfung");
    }
  } catch (err) {
    if (resultEl) {
      resultEl.innerHTML = "<p style='margin:0;color:#991b1b;'>Scan fehlgeschlagen: " + escapeHtml(err.message || "Unbekannter Fehler") + "</p>";
    }
  } finally {
    if (triggerBtn) {
      triggerBtn.disabled = false;
      triggerBtn.textContent = "Zeugnis scannen und Noten vergleichen";
    }
  }
}

async function scanAndValidateStudentDocuments(studentId, triggerBtn) {
  const resultEl = document.getElementById("nameCheckResult_" + studentId);
  if (resultEl) {
    resultEl.innerHTML = "<p style='margin:0;color:#1e3a8a;'>Dokumente werden auf Profilnamen geprüft...</p>";
  }

  const students = loadStudents();
  const student = students.find((s) => s.id === studentId);
  if (!student) {
    if (resultEl) resultEl.innerHTML = "<p style='margin:0;color:#991b1b;'>Profil nicht gefunden.</p>";
    return;
  }

  const hasAnyDoc = !!((student.zeugnis && student.zeugnis.dataUrl) || (student.lebenslauf && student.lebenslauf.dataUrl));
  if (!hasAnyDoc) {
    if (resultEl) resultEl.innerHTML = "<p style='margin:0;color:#991b1b;'>Kein Zeugnis oder Lebenslauf vorhanden.</p>";
    return;
  }

  if (triggerBtn) {
    triggerBtn.disabled = true;
    triggerBtn.textContent = "Name-Check läuft...";
  }

  try {
    const zeugnisExtraction = await extractDocumentTextForNameCheck(student.zeugnis);
    const lebenslaufExtraction = await extractDocumentTextForNameCheck(student.lebenslauf);

    if (zeugnisExtraction.supported) {
      zeugnisExtraction.nameCheck = evaluateProfileNameInText(student.name, zeugnisExtraction.text);
    }
    if (lebenslaufExtraction.supported) {
      lebenslaufExtraction.nameCheck = evaluateProfileNameInText(student.name, lebenslaufExtraction.text);
    }

    const checks = [zeugnisExtraction, lebenslaufExtraction].filter((entry) => entry.supported && entry.nameCheck);
    const mismatchCount = checks.filter((entry) => !entry.nameCheck.ok).length;
    const summary = !checks.length
      ? "<p style='margin:0 0 0.6rem;color:#92400e;'><strong>Ergebnis:</strong> Keine Dokumente konnten automatisiert auf Namen geprüft werden.</p>"
      : (mismatchCount === 0
        ? "<p style='margin:0 0 0.6rem;color:#166534;'><strong>Ergebnis:</strong> Profilname in allen prüfbaren Dokumenten gefunden.</p>"
        : "<p style='margin:0 0 0.6rem;color:#991b1b;'><strong>Ergebnis:</strong> " + mismatchCount + " Dokument(e) mit Namensabweichung.</p>");

    if (resultEl) {
      resultEl.innerHTML = ""
        + "<div style='border:1px solid #dbeafe;background:#eff6ff;border-radius:6px;padding:0.8rem;'>"
        + summary
        + "<table style='width:100%;border-collapse:collapse;font-size:0.88rem;color:#1f2937;'>"
        + "<thead><tr><th style='text-align:left;padding:0.35rem 0.5rem;border-bottom:1px solid #cbd5e1;'>Dokument</th><th style='text-align:left;padding:0.35rem 0.5rem;border-bottom:1px solid #cbd5e1;'>Name</th><th style='text-align:left;padding:0.35rem 0.5rem;border-bottom:1px solid #cbd5e1;'>Details</th></tr></thead>"
        + "<tbody>"
        + buildNameCheckRow("Zeugnis", zeugnisExtraction)
        + buildNameCheckRow("Lebenslauf", lebenslaufExtraction)
        + "</tbody>"
        + "</table>"
        + "<p style='margin:0.6rem 0 0;color:#64748b;font-size:0.82rem;'>Hinweis: OCR/Extraktion kann je nach Dateiformat und Qualität unvollständig sein. Ergebnis manuell prüfen.</p>"
        + "</div>";
    }
  } catch (err) {
    if (resultEl) {
      resultEl.innerHTML = "<p style='margin:0;color:#991b1b;'>Namensprüfung fehlgeschlagen: " + escapeHtml(err.message || "Unbekannter Fehler") + "</p>";
    }
  } finally {
    if (triggerBtn) {
      triggerBtn.disabled = false;
      triggerBtn.textContent = "Zeugnis & Lebenslauf auf Profilname prüfen";
    }
  }
}
// ===== Accessibility: Globaler Tastatur-Fokus-Hook =====
// Gilt für alle Seiten, die script.js laden.
(function () {
  function enableTabbing() {
    document.body.classList.add("user-is-tabbing");
  }
  function disableTabbing() {
    document.body.classList.remove("user-is-tabbing");
  }
  document.addEventListener("keydown", function (e) {
    if (e.key === "Tab") enableTabbing();
  });
  document.addEventListener("mousedown", disableTabbing);
  document.addEventListener("pointerdown", disableTabbing);
  document.addEventListener("touchstart", disableTabbing, { passive: true });
}());